INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('48a64915-45f8-4d66-8501-ef29206aa4d0', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '88c73897-04a5-4e07-a52d-51c99650ed3f', 'Savewo MagCell MC1003 10000mAh 磁吸無線行動電源', 'magcell-mc1003', '698ee0850724aa3beed87212', '🧲 MagCell MC1003 10000mAh 磁吸無線行動電源🔋⚡CCC認證，大容量磁吸，高級金屬工藝，抵玩登場✨採用 AI-Mg 5052 鋁鎂合金外殼，邊緣拋光設計✨，手感細膩滑順，同時堅固耐用🛡️，高效散熱，無線充電溫度更低，不燙手更安心✅，🧲無線磁吸加上雙口USB-A, USB-C輸出🔌，方便為各款裝置充電📱💻🎧！🔋 大容量 10000mAh，外出一整天電力滿滿⚡ 15W無線快充，高效散熱設計不發燙⚡ 20W PD 有線快充輸出⚖️ 僅重 185g，輕巧便攜📏 103.5 x 67.7 x 15.7mm🧲 N52 強磁吸附，穩固貼合不易滑落，完美貼合iPhone 15/16/17', '/products/savewo/magcell-mc1003.jpg', '[{"url": "/products/savewo/magcell-mc1003.jpg", "alt": "Savewo MagCell MC1003 10000mAh 磁吸無線行動電源", "sortOrder": 0}, {"url": "/products/savewo/magcell-mc1003-2.jpg", "alt": "Savewo MagCell MC1003 10000mAh 磁吸無線行動電源", "sortOrder": 1}, {"url": "/products/savewo/magcell-mc1003-3.jpg", "alt": "Savewo MagCell MC1003 10000mAh 磁吸無線行動電源", "sortOrder": 2}, {"url": "/products/savewo/magcell-mc1003-4.jpg", "alt": "Savewo MagCell MC1003 10000mAh 磁吸無線行動電源", "sortOrder": 3}, {"url": "/products/savewo/magcell-mc1003-5.jpg", "alt": "Savewo MagCell MC1003 10000mAh 磁吸無線行動電源", "sortOrder": 4}]', 238.0, NULL, 'active', 1) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('52607121-3589-461e-ab40-7e7330e3bacd', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '88c73897-04a5-4e07-a52d-51c99650ed3f', 'SAVEWO PowerCell Mini PC10K1 高性能迷你行動電源', 'powercell-pc10k1', '698ed9dac7fd2e3388bf715e', '【PowerCell mini終於輕細登場！性能同樣強勁！】🔋大電力基因．濃縮進化⚡️🔗 產品網站https://savewo.com/energy/powercell/pc10k1/好多客人都好鍾意我哋PowerCell，同時都有好多人問幾時會推出更輕巧便攜既版本，大家唔洗再等，依家終於有啦！！⚡️PowerCell mini 高性能迷你行動電源⚡️CCC認證，233g，掌心大小，真正 Pocket Size，內置 LCD 顯示屏，細細部但能量十足，支援PD 45W 高速放電，10000mAh（37Wh）大容量，出行必備！延續PowerCell核心科技：🔋  10000mAh（37Wh）⚡ ', '/products/savewo/powercell-pc10k1.jpg', '[{"url": "/products/savewo/powercell-pc10k1.jpg", "alt": "SAVEWO PowerCell Mini PC10K1 高性能迷你行動電源", "sortOrder": 0}, {"url": "/products/savewo/powercell-pc10k1-2.jpg", "alt": "SAVEWO PowerCell Mini PC10K1 高性能迷你行動電源", "sortOrder": 1}, {"url": "/products/savewo/powercell-pc10k1-3.jpg", "alt": "SAVEWO PowerCell Mini PC10K1 高性能迷你行動電源", "sortOrder": 2}, {"url": "/products/savewo/powercell-pc10k1-4.jpg", "alt": "SAVEWO PowerCell Mini PC10K1 高性能迷你行動電源", "sortOrder": 3}, {"url": "/products/savewo/powercell-pc10k1-5.jpg", "alt": "SAVEWO PowerCell Mini PC10K1 高性能迷你行動電源", "sortOrder": 4}, {"url": "/products/savewo/powercell-pc10k1-6.jpg", "alt": "SAVEWO PowerCell Mini PC10K1 高性能迷你行動電源", "sortOrder": 5}]', 268.0, NULL, 'active', 2) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('a7784be5-e328-4eea-8bfe-503d72965861', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '88c73897-04a5-4e07-a52d-51c99650ed3f', '*1.2米* SAVEWO PowerCable MIX 240W PD3.1 救世 4合1 極速充電線', 'powercable-mix', '69846c06d586a18207426f59', '🔋【出街最怕帶錯線‼️PowerCable MIX｜出門帶線，一條就夠😎】🔋🔋全部場景都充到！🔌 4 in 1 一線多用，支援最新 PD 3.1⚡ 最高 240W 極速充電！功率傳輸更快、更穩定💪1️⃣USB C → Lightning2️⃣USB C → USB C3️⃣USB A → Lightning4️⃣USB A → USB C🚀 瞬間充電｜Ultra Fast Charging⚡USB C 連接埠最高可達 240WLightning 最高可達 27W資料傳輸速度最高 480 Mbps🛡️ 安全再升級內建 E Marker 晶片智慧調節電流，保護裝置與個人安全💪 耐用設計 UP📏 線', '/products/savewo/powercable-mix.jpg', '[{"url": "/products/savewo/powercable-mix.jpg", "alt": "*1.2米* SAVEWO PowerCable MIX 240W PD3.1 救世 4合1 極速充電線", "sortOrder": 0}, {"url": "/products/savewo/powercable-mix-2.jpg", "alt": "*1.2米* SAVEWO PowerCable MIX 240W PD3.1 救世 4合1 極速充電線", "sortOrder": 1}, {"url": "/products/savewo/powercable-mix-3.jpg", "alt": "*1.2米* SAVEWO PowerCable MIX 240W PD3.1 救世 4合1 極速充電線", "sortOrder": 2}, {"url": "/products/savewo/powercable-mix-4.jpg", "alt": "*1.2米* SAVEWO PowerCable MIX 240W PD3.1 救世 4合1 極速充電線", "sortOrder": 3}, {"url": "/products/savewo/powercable-mix-5.jpg", "alt": "*1.2米* SAVEWO PowerCable MIX 240W PD3.1 救世 4合1 極速充電線", "sortOrder": 4}, {"url": "/products/savewo/powercable-mix-6.jpg", "alt": "*1.2米* SAVEWO PowerCable MIX 240W PD3.1 救世 4合1 極速充電線", "sortOrder": 5}]', 69.0, NULL, 'active', 3) ON CONFLICT DO NOTHING;
