INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('485f8bc9-b7b7-4420-8424-18eae8f02481', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '69787a97-49de-477e-9431-87d166480be0', 'SAVEWO 無線負離子直髮梳 Wireless Ionic Hair Straightener Brush', 'ionicbrush', '6976ea91d0495214ebb30e91', '✨ Savewo Ionic Brush 無線負離子直髮梳 ✨一梳之間，喚醒髮絲的自然優雅。MCH金屬陶瓷發熱片結合高濃度負離子，瞬間撫平毛躁與扁塌，賦予宛若沙龍般的絲滑直髮，綻放自信光采💫無線設計，告別電線糾纏，187g，不論是早上趕出門、下午補造型，還是旅行都可隨身攜帶為不同的妳而設的貼心細節：🪮 3D 梳齒矩陣設計，均勻導熱，減少拉扯與打結💎 高濃度負離子，每立方厘米高達 200 萬，撫平毛躁、提升光澤🔥 3 段溫控（160°C / 180°C / 200°C），精準對應各種髮質⚡ MCH金屬陶瓷發熱片 升溫快、安全性高又耐用🛡 20 分鐘自動斷電，安全貼心，避免忘記關機🔋 無線設計，U', '/products/savewo/ionicbrush.jpg', '[{"url": "/products/savewo/ionicbrush.jpg", "alt": "SAVEWO 無線負離子直髮梳 Wireless Ionic Hair Straightener Brush", "sortOrder": 0}, {"url": "/products/savewo/ionicbrush-2.jpg", "alt": "SAVEWO 無線負離子直髮梳 Wireless Ionic Hair Straightener Brush", "sortOrder": 1}, {"url": "/products/savewo/ionicbrush-3.jpg", "alt": "SAVEWO 無線負離子直髮梳 Wireless Ionic Hair Straightener Brush", "sortOrder": 2}, {"url": "/products/savewo/ionicbrush-4.jpg", "alt": "SAVEWO 無線負離子直髮梳 Wireless Ionic Hair Straightener Brush", "sortOrder": 3}, {"url": "/products/savewo/ionicbrush-5.jpg", "alt": "SAVEWO 無線負離子直髮梳 Wireless Ionic Hair Straightener Brush", "sortOrder": 4}, {"url": "/products/savewo/ionicbrush-6.jpg", "alt": "SAVEWO 無線負離子直髮梳 Wireless Ionic Hair Straightener Brush", "sortOrder": 5}]', 268.0, NULL, 'active', 7) ON CONFLICT DO NOTHING;
