INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('e0f5868b-c8c5-49d2-986a-ffcfe8c99ef0', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '0e7588df-a28c-4b75-80be-f1b9352e282e', 'SAVEWO Airflow ProStyle 專業數碼恆溫負離子護髮風筒 AF-HD01', 'airflow-prostyle-savewo-airflow', '6957701c6e1694d0cb91952e', '✨ SAVEWO Airflow ProStyle 專業數碼恆溫負離子風筒 AF‑HD01 登場✨您的專業造型師伴侶，護髮造型一步到位 💇‍♀️🔗 產品網站https://savewo.com/energy/prostyle/af-hd01/「咔嗒」一聲，磁吸風嘴即裝即用✅ 解鎖 4 種專業造型模式✅ 快速乾髮，同時呵護秀髮💨 1600W 特強功率⚡ 11萬轉超高速數碼電機🌪 74m/s 超高風速｜快速乾髮不傷髮💎 5億負離子 / cm³｜撫平毛躁，提升光澤🌡 NTC 三段恆溫系統｜每秒 150 次智能監測🔴三色 LED 清晰顯示風速與溫度🧲 磁吸風嘴設計🔥1檔溫度：28℃ / 2檔溫度：60', '/products/savewo/airflow-prostyle-savewo-airflow.jpg', '[{"url": "/products/savewo/airflow-prostyle-savewo-airflow.jpg", "alt": "SAVEWO Airflow ProStyle 專業數碼恆溫負離子護髮風筒 AF-HD01", "sortOrder": 0}, {"url": "/products/savewo/airflow-prostyle-savewo-airflow-2.jpg", "alt": "SAVEWO Airflow ProStyle 專業數碼恆溫負離子護髮風筒 AF-HD01", "sortOrder": 1}, {"url": "/products/savewo/airflow-prostyle-savewo-airflow-3.jpg", "alt": "SAVEWO Airflow ProStyle 專業數碼恆溫負離子護髮風筒 AF-HD01", "sortOrder": 2}, {"url": "/products/savewo/airflow-prostyle-savewo-airflow-4.jpg", "alt": "SAVEWO Airflow ProStyle 專業數碼恆溫負離子護髮風筒 AF-HD01", "sortOrder": 3}, {"url": "/products/savewo/airflow-prostyle-savewo-airflow-5.jpg", "alt": "SAVEWO Airflow ProStyle 專業數碼恆溫負離子護髮風筒 AF-HD01", "sortOrder": 4}, {"url": "/products/savewo/airflow-prostyle-savewo-airflow-6.jpg", "alt": "SAVEWO Airflow ProStyle 專業數碼恆溫負離子護髮風筒 AF-HD01", "sortOrder": 5}, {"url": "/products/savewo/airflow-prostyle-savewo-airflow-7.jpg", "alt": "SAVEWO Airflow ProStyle 專業數碼恆溫負離子護髮風筒 AF-HD01", "sortOrder": 6}]', 399.0, NULL, 'active', 10) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('d0a33aa5-6f2c-4d72-b301-76b69b7a6f09', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '7ed7ec4c-f825-40e7-99d9-486092d7834c', 'SAVEWO HEALTHCHAIR Travel 旅行型電池 (158Wh) (XC1專用)', 'healthchair-travel-battery-xc1', '69549e532a797e30a3daf3bb', 'X旅行型電池（24V 6.6Ah 158Wh）（額定容量158Wh 電池容量240Wh ）因應一般航空規定，每名乘客可攜帶兩枚不超過160Wh電池登機，即每名乘客可攜帶兩枚旅行型電池出行，令周遊列國再無限制。*建議事前與航空公司溝通確認*XC1專用"', '/products/savewo/healthchair-travel-battery-xc1.jpg', '[{"url": "/products/savewo/healthchair-travel-battery-xc1.jpg", "alt": "SAVEWO HEALTHCHAIR Travel 旅行型電池 (158Wh) (XC1專用)", "sortOrder": 0}]', 1280.0, NULL, 'active', 11) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('859206eb-98d3-4ae0-8058-dec0496632c9', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '827788ac-3d7c-40dc-88c5-5f6e6de09891', '*5支裝* SAVEWO 十一合一抗原快速檢測試劑 新型冠狀病毒 (COVID-19) / 鼻病毒 (RhV) / 人類偏肺病毒 (hMPV) / 肺炎鏈球菌 (SP) / 肺炎支原體 (MP) / 合胞病毒 (RSV) / 腺病毒 (ADV) / 副流感1/3型 (PIV 1/3) / 副流感2型 (PIV 2) / 甲型流感 (Flu A) / ⼄型流感 (Flu B)', 'rat-11in1-5', '69437a4e83227602e0dd9efd', 'SAVEWO全新推出的11合1抗原快速檢測劑，涵蓋超過 90% 流行性呼吸道疾病，涵蓋hMPV人類偏肺病毒、RhV鼻病毒、新型冠狀病毒（COVID-19）、甲型流感、乙型流感、肺炎鏈球菌、肺炎支原體、副流感病毒 1/3 型、副流感病毒 2 型、RSV呼吸道合胞病毒及腺病毒，對應絕大部分日常急性呼吸道感染個案。只需15分鐘⏰，即可提供高達99.9%準確度的檢測結果，且具有極佳的最低檢測限度（LoD），即便在病毒含量極低的早期亦能準確識別，遠勝同類產品💡即使病毒量極低，都可以檢測出病毒，令感染者喺症狀出現之前就被識別，及早隔離，減少併發症同傳染俾其他人嘅風險。考慮到唔同年齡層嘅使用者，測試劑採用 ', '/products/savewo/rat-11in1-5.jpg', '[{"url": "/products/savewo/rat-11in1-5.jpg", "alt": "*5支裝* SAVEWO 十一合一抗原快速檢測試劑 新型冠狀病毒 (COVID-19) / 鼻病毒 (RhV) / 人類偏肺病毒 (hMPV) / 肺炎鏈球菌 (SP) / 肺炎支原體 (MP) / 合胞病毒 (RSV) / 腺病毒 (ADV) / 副流感1/3型 (PIV 1/3) / 副流感2型 (PIV 2) / 甲型流感 (Flu A) / ⼄型流感 (Flu B)", "sortOrder": 0}, {"url": "/products/savewo/rat-11in1-5-2.jpg", "alt": "*5支裝* SAVEWO 十一合一抗原快速檢測試劑 新型冠狀病毒 (COVID-19) / 鼻病毒 (RhV) / 人類偏肺病毒 (hMPV) / 肺炎鏈球菌 (SP) / 肺炎支原體 (MP) / 合胞病毒 (RSV) / 腺病毒 (ADV) / 副流感1/3型 (PIV 1/3) / 副流感2型 (PIV 2) / 甲型流感 (Flu A) / ⼄型流感 (Flu B)", "sortOrder": 1}, {"url": "/products/savewo/rat-11in1-5-3.jpg", "alt": "*5支裝* SAVEWO 十一合一抗原快速檢測試劑 新型冠狀病毒 (COVID-19) / 鼻病毒 (RhV) / 人類偏肺病毒 (hMPV) / 肺炎鏈球菌 (SP) / 肺炎支原體 (MP) / 合胞病毒 (RSV) / 腺病毒 (ADV) / 副流感1/3型 (PIV 1/3) / 副流感2型 (PIV 2) / 甲型流感 (Flu A) / ⼄型流感 (Flu B)", "sortOrder": 2}, {"url": "/products/savewo/rat-11in1-5-4.jpg", "alt": "*5支裝* SAVEWO 十一合一抗原快速檢測試劑 新型冠狀病毒 (COVID-19) / 鼻病毒 (RhV) / 人類偏肺病毒 (hMPV) / 肺炎鏈球菌 (SP) / 肺炎支原體 (MP) / 合胞病毒 (RSV) / 腺病毒 (ADV) / 副流感1/3型 (PIV 1/3) / 副流感2型 (PIV 2) / 甲型流感 (Flu A) / ⼄型流感 (Flu B)", "sortOrder": 3}]', 173.0, NULL, 'active', 12) ON CONFLICT DO NOTHING;
