INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('c7de2ea3-7dd2-4ac3-a247-15e214cd14f7', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '827788ac-3d7c-40dc-88c5-5f6e6de09891', '*5支裝* SAVEWO六合一抗原快速檢測試劑 (新型冠狀病毒 Covid-19 / 呼吸道合胞病毒 RSV / 甲型流感 Flu A / ⼄型流感 Flu B / 腺病毒 ADV / 肺炎支原體 MP)', 'rat-6in1-5', '6943795c797c57512361048e', 'SAVEWO六合一抗原快速檢測試劑  (新型冠狀病毒 Covid-19 / 呼吸道合胞病毒 RSV / 甲型流感 Flu A / ⼄型流感 Flu B / 腺病毒 ADV / 肺炎支原體 MP)助你把握用藥及康復的黃金時間！甲型流感、乙型流感、新冠、呼吸道合胞病毒(RSV)、腺病毒、肺炎支原體同時伺機入侵，惟病徵往往相似，甚至可能同時感染！建議倘出現流感病徵，最好「先快測、後求診」，方便醫生盡快對症下藥，在病毒未大幅蔓延時及早治療！🔗 產品網站https://www.savewo.com/healthcare/zh-hk/products/6in1-antigen-test-kit/RNS92', '/products/savewo/rat-6in1-5.jpg', '[{"url": "/products/savewo/rat-6in1-5.jpg", "alt": "*5支裝* SAVEWO六合一抗原快速檢測試劑 (新型冠狀病毒 Covid-19 / 呼吸道合胞病毒 RSV / 甲型流感 Flu A / ⼄型流感 Flu B / 腺病毒 ADV / 肺炎支原體 MP)", "sortOrder": 0}, {"url": "/products/savewo/rat-6in1-5-2.jpg", "alt": "*5支裝* SAVEWO六合一抗原快速檢測試劑 (新型冠狀病毒 Covid-19 / 呼吸道合胞病毒 RSV / 甲型流感 Flu A / ⼄型流感 Flu B / 腺病毒 ADV / 肺炎支原體 MP)", "sortOrder": 1}, {"url": "/products/savewo/rat-6in1-5-3.jpg", "alt": "*5支裝* SAVEWO六合一抗原快速檢測試劑 (新型冠狀病毒 Covid-19 / 呼吸道合胞病毒 RSV / 甲型流感 Flu A / ⼄型流感 Flu B / 腺病毒 ADV / 肺炎支原體 MP)", "sortOrder": 2}, {"url": "/products/savewo/rat-6in1-5-4.jpg", "alt": "*5支裝* SAVEWO六合一抗原快速檢測試劑 (新型冠狀病毒 Covid-19 / 呼吸道合胞病毒 RSV / 甲型流感 Flu A / ⼄型流感 Flu B / 腺病毒 ADV / 肺炎支原體 MP)", "sortOrder": 3}, {"url": "/products/savewo/rat-6in1-5-5.jpg", "alt": "*5支裝* SAVEWO六合一抗原快速檢測試劑 (新型冠狀病毒 Covid-19 / 呼吸道合胞病毒 RSV / 甲型流感 Flu A / ⼄型流感 Flu B / 腺病毒 ADV / 肺炎支原體 MP)", "sortOrder": 4}]', 150.0, NULL, 'active', 15) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('ce7c3b23-3703-4ec0-bda7-c68c9bc9ffc7', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '0618299f-e65a-4b73-8743-33e9c30f4c65', '*R 標準碼* SAVEWO REGAL MASK 救世 2D 對摺型口罩 淺沙「UPF30 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)', 'regal-r-paledunes', '693924489e75a4dc9a382eb2', '【超「V」面！ 超舒適！ 救世新口罩注意！ Savewo Regal Mask 2D 對摺型口罩新上市！🥳😷✨】Savewo Regal Mask 係針對「V」面同舒適度而又不失保護力嘅口罩！😍 2D 對摺嘅流暢線條令你流露出最自然輕盈一面，救世目前唯一無鼻樑壓條設計嘅口罩，戴上去舒適貼服喺面上猶如無物😌，戴足一日都唔覺焗住焗住🌬️，仲防埋 UV 添☀️。簡單易用，輕便易攜🎒，無論去邊都可以隨身帶住，係你出街嘅好拍檔！💖Regal Mask 用咗 TYPECOOL+ 過濾技術，保留「高透氣」「強過濾」「防敏感」特質👏，除咗有效防禦飛沫、花粉、懸浮物質、細菌及病毒🦠，過濾效率有效 24 小時以上', '/products/savewo/regal-r-paledunes.jpg', '[{"url": "/products/savewo/regal-r-paledunes.jpg", "alt": "*R 標準碼* SAVEWO REGAL MASK 救世 2D 對摺型口罩 淺沙「UPF30 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)", "sortOrder": 0}, {"url": "/products/savewo/regal-r-paledunes-2.jpg", "alt": "*R 標準碼* SAVEWO REGAL MASK 救世 2D 對摺型口罩 淺沙「UPF30 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)", "sortOrder": 1}, {"url": "/products/savewo/regal-r-paledunes-3.jpg", "alt": "*R 標準碼* SAVEWO REGAL MASK 救世 2D 對摺型口罩 淺沙「UPF30 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)", "sortOrder": 2}]', 79.0, NULL, 'active', 16) ON CONFLICT DO NOTHING;
