INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('8aa9dbf5-6e03-44b2-90c3-aa56da9bd118', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '3a0021f1-4a3a-45d6-928f-711d9cebfb99', '*R 標準碼 旅行裝* SAVEWO ROYAL MASK 救世 2D 對摺型口罩 晨霧「KF94 + KN95 + ASTM LEVEL3 認證 」(5片獨立包裝/盒)', 'royal-r-morningmist-5', '6937e1867460c1001025a588', '集救世科研與時尚極致於一身，極修臉對摺型口罩 Royal Mask，能高度適合95%人士臉形，簡約而細緻V形設計讓你配戴極為方便亦易於收納。秉承救世專利過濾技術 TYPECOOL+，Royal Mask 保留「高透氣」「強過濾」「防敏感」特質，除有效防禦99.9%飛沫、花粉、懸浮物質、細菌及病毒，更配合獨有剪裁讓其緊貼面部完美防止漏氣，符合人體工學的立體設計，內部空間比一般口罩多出30％，呼吸更暢順，配戴更舒適無阻！Royal 級剪裁專利V形設計以極致的人體工學研發而成，質料防敏剪裁獨特，舒適地貼服在臉上猶如無物。配戴後更顯臉型利落自然，流暢線條讓你流露出最自然輕盈一面，無論便裝或晚裝，Roy', '/products/savewo/royal-r-morningmist-5.jpg', '[{"url": "/products/savewo/royal-r-morningmist-5.jpg", "alt": "*R 標準碼 旅行裝* SAVEWO ROYAL MASK 救世 2D 對摺型口罩 晨霧「KF94 + KN95 + ASTM LEVEL3 認證 」(5片獨立包裝/盒)", "sortOrder": 0}, {"url": "/products/savewo/royal-r-morningmist-5-2.jpg", "alt": "*R 標準碼 旅行裝* SAVEWO ROYAL MASK 救世 2D 對摺型口罩 晨霧「KF94 + KN95 + ASTM LEVEL3 認證 」(5片獨立包裝/盒)", "sortOrder": 1}, {"url": "/products/savewo/royal-r-morningmist-5-3.jpg", "alt": "*R 標準碼 旅行裝* SAVEWO ROYAL MASK 救世 2D 對摺型口罩 晨霧「KF94 + KN95 + ASTM LEVEL3 認證 」(5片獨立包裝/盒)", "sortOrder": 2}, {"url": "/products/savewo/royal-r-morningmist-5-4.jpg", "alt": "*R 標準碼 旅行裝* SAVEWO ROYAL MASK 救世 2D 對摺型口罩 晨霧「KF94 + KN95 + ASTM LEVEL3 認證 」(5片獨立包裝/盒)", "sortOrder": 3}, {"url": "/products/savewo/royal-r-morningmist-5-5.jpg", "alt": "*R 標準碼 旅行裝* SAVEWO ROYAL MASK 救世 2D 對摺型口罩 晨霧「KF94 + KN95 + ASTM LEVEL3 認證 」(5片獨立包裝/盒)", "sortOrder": 4}]', 25.0, NULL, 'active', 18) ON CONFLICT DO NOTHING;
