INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('51bed6f1-ffd1-4a22-abf6-a4e5bb6efeec', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '827788ac-3d7c-40dc-88c5-5f6e6de09891', '*20支裝* SAVEWO 十一合一抗原快速檢測試劑 新型冠狀病毒 (COVID-19) / 鼻病毒 (RhV) / 人類偏肺病毒 (hMPV) / 肺炎鏈球菌 (SP) / 肺炎支原體 (MP) / 合胞病毒 (RSV) / 腺病毒 (ADV) / 副流感1/3型 (PIV 1/3) / 副流感2型 (PIV 2) / 甲型流感 (Flu A) / ⼄型流感 (Flu B)', 'rat-11in1-20', '6937b199c031c1000a2f4249', 'SAVEWO全新推出的11合1抗原快速檢測劑，涵蓋超過 90% 流行性呼吸道疾病，涵蓋hMPV人類偏肺病毒、RhV鼻病毒、新型冠狀病毒（COVID-19）、甲型流感、乙型流感、肺炎鏈球菌、肺炎支原體、副流感病毒 1/3 型、副流感病毒 2 型、RSV呼吸道合胞病毒及腺病毒，對應絕大部分日常急性呼吸道感染個案。只需15分鐘⏰，即可提供高達99.9%準確度的檢測結果，且具有極佳的最低檢測限度（LoD），即便在病毒含量極低的早期亦能準確識別，遠勝同類產品💡即使病毒量極低，都可以檢測出病毒，令感染者喺症狀出現之前就被識別，及早隔離，減少併發症同傳染俾其他人嘅風險。考慮到唔同年齡層嘅使用者，測試劑採用 ', '/products/savewo/rat-11in1-20.jpg', '[{"url": "/products/savewo/rat-11in1-20.jpg", "alt": "*20支裝* SAVEWO 十一合一抗原快速檢測試劑 新型冠狀病毒 (COVID-19) / 鼻病毒 (RhV) / 人類偏肺病毒 (hMPV) / 肺炎鏈球菌 (SP) / 肺炎支原體 (MP) / 合胞病毒 (RSV) / 腺病毒 (ADV) / 副流感1/3型 (PIV 1/3) / 副流感2型 (PIV 2) / 甲型流感 (Flu A) / ⼄型流感 (Flu B)", "sortOrder": 0}, {"url": "/products/savewo/rat-11in1-20-2.jpg", "alt": "*20支裝* SAVEWO 十一合一抗原快速檢測試劑 新型冠狀病毒 (COVID-19) / 鼻病毒 (RhV) / 人類偏肺病毒 (hMPV) / 肺炎鏈球菌 (SP) / 肺炎支原體 (MP) / 合胞病毒 (RSV) / 腺病毒 (ADV) / 副流感1/3型 (PIV 1/3) / 副流感2型 (PIV 2) / 甲型流感 (Flu A) / ⼄型流感 (Flu B)", "sortOrder": 1}, {"url": "/products/savewo/rat-11in1-20-3.jpg", "alt": "*20支裝* SAVEWO 十一合一抗原快速檢測試劑 新型冠狀病毒 (COVID-19) / 鼻病毒 (RhV) / 人類偏肺病毒 (hMPV) / 肺炎鏈球菌 (SP) / 肺炎支原體 (MP) / 合胞病毒 (RSV) / 腺病毒 (ADV) / 副流感1/3型 (PIV 1/3) / 副流感2型 (PIV 2) / 甲型流感 (Flu A) / ⼄型流感 (Flu B)", "sortOrder": 2}, {"url": "/products/savewo/rat-11in1-20-4.jpg", "alt": "*20支裝* SAVEWO 十一合一抗原快速檢測試劑 新型冠狀病毒 (COVID-19) / 鼻病毒 (RhV) / 人類偏肺病毒 (hMPV) / 肺炎鏈球菌 (SP) / 肺炎支原體 (MP) / 合胞病毒 (RSV) / 腺病毒 (ADV) / 副流感1/3型 (PIV 1/3) / 副流感2型 (PIV 2) / 甲型流感 (Flu A) / ⼄型流感 (Flu B)", "sortOrder": 3}]', 680.0, NULL, 'active', 22) ON CONFLICT DO NOTHING;
