INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('ed746ad8-51bf-403c-b019-3472f619cd17', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '3f73ad1e-bfa4-4f24-bccc-95a66f75e37a', '*L 大碼 - 寬面型人士  旅行裝* SAVEWO 3DMASK ULTRA 救世超立體口罩 ULTRA TYPECOOL+「FFP2 + KF94 + ASTM LEVEL3 認證 」(5片獨立包裝/盒)', 'ultra-l-5', '6932a465c02b86000ca5944c', 'SAVEWO 3DMASK Ultra 救世超立體口罩是嶄新的即棄式防護呼吸器及醫用口罩，結合多種救世創新科技，通過各種嚴格的測試，擁有極高的過濾性能，特製的立體剪裁，彈性無痛寬耳帶，超低的呼吸阻力，即使長時間穿戴也十分舒適。無論功能及使用體驗均力臻完美。UltraSpunBond 超潑水面料，配合UltraSeal 超音波接焊點技術，令超薄透氣的3DMASK Ultra 達到前所未有的立體堅挺，更高耐用度，無懼惡劣環境，以及更強大的潑水及抗水性能，防止飛沫及液濺阻擋達160mmHg。TypeCool+過濾技術，超低呼吸阻力只有&lt; 2.4mmH2O，僅為傳統呼吸器的三分之一。得益於不受濕', '/products/savewo/ultra-l-5.jpg', '[{"url": "/products/savewo/ultra-l-5.jpg", "alt": "*L 大碼 - 寬面型人士  旅行裝* SAVEWO 3DMASK ULTRA 救世超立體口罩 ULTRA TYPECOOL+「FFP2 + KF94 + ASTM LEVEL3 認證 」(5片獨立包裝/盒)", "sortOrder": 0}, {"url": "/products/savewo/ultra-l-5-2.jpg", "alt": "*L 大碼 - 寬面型人士  旅行裝* SAVEWO 3DMASK ULTRA 救世超立體口罩 ULTRA TYPECOOL+「FFP2 + KF94 + ASTM LEVEL3 認證 」(5片獨立包裝/盒)", "sortOrder": 1}, {"url": "/products/savewo/ultra-l-5-3.jpg", "alt": "*L 大碼 - 寬面型人士  旅行裝* SAVEWO 3DMASK ULTRA 救世超立體口罩 ULTRA TYPECOOL+「FFP2 + KF94 + ASTM LEVEL3 認證 」(5片獨立包裝/盒)", "sortOrder": 2}, {"url": "/products/savewo/ultra-l-5-4.jpg", "alt": "*L 大碼 - 寬面型人士  旅行裝* SAVEWO 3DMASK ULTRA 救世超立體口罩 ULTRA TYPECOOL+「FFP2 + KF94 + ASTM LEVEL3 認證 」(5片獨立包裝/盒)", "sortOrder": 3}, {"url": "/products/savewo/ultra-l-5-5.jpg", "alt": "*L 大碼 - 寬面型人士  旅行裝* SAVEWO 3DMASK ULTRA 救世超立體口罩 ULTRA TYPECOOL+「FFP2 + KF94 + ASTM LEVEL3 認證 」(5片獨立包裝/盒)", "sortOrder": 4}, {"url": "/products/savewo/ultra-l-5-6.jpg", "alt": "*L 大碼 - 寬面型人士  旅行裝* SAVEWO 3DMASK ULTRA 救世超立體口罩 ULTRA TYPECOOL+「FFP2 + KF94 + ASTM LEVEL3 認證 」(5片獨立包裝/盒)", "sortOrder": 5}, {"url": "/products/savewo/ultra-l-5-7.jpg", "alt": "*L 大碼 - 寬面型人士  旅行裝* SAVEWO 3DMASK ULTRA 救世超立體口罩 ULTRA TYPECOOL+「FFP2 + KF94 + ASTM LEVEL3 認證 」(5片獨立包裝/盒)", "sortOrder": 6}, {"url": "/produc