INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('eed34560-ab46-4a5e-bcfd-d21734c21550', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '827788ac-3d7c-40dc-88c5-5f6e6de09891', '*20支裝* SAVEWO 五合一抗原快速檢測試劑 (新型冠狀病毒(Covid-19) / 甲型流感病毒(Influenza A) / 乙型流感病毒(Influenza B) / RSV呼吸道合胞病毒 / ADV腺病毒)', 'rat-5in1-20', '69257e268010b70016098905', 'SAVEWO全新推出的5合1抗原快速檢測劑，專為應對最常見的5️⃣大呼吸道病毒而設，涵蓋新型冠狀病毒（COVID-19）、甲型流感、乙型流感、RSV呼吸道合胞病毒及腺病毒，對應大部分日常急性呼吸道感染個案。只需15分鐘⏰，即可提供高達99.9%準確度的檢測結果，且具有極佳的最低檢測限度（LoD），即便在病毒含量極低的早期亦能準確識別，是診所、學校🏫、安老院舍👵🏻、企業單位及家庭常備的理想選擇。【五合一抗原快速檢測劑】📌 能同時檢測以下病毒：新型冠狀病毒（Covid-19） / 甲型流感病毒（Influenza A） / 乙型流感病毒（Influenza B） / RSV呼吸道合胞病毒 / AD', '/products/savewo/rat-5in1-20.jpg', '[{"url": "/products/savewo/rat-5in1-20.jpg", "alt": "*20支裝* SAVEWO 五合一抗原快速檢測試劑 (新型冠狀病毒(Covid-19) / 甲型流感病毒(Influenza A) / 乙型流感病毒(Influenza B) / RSV呼吸道合胞病毒 / ADV腺病毒)", "sortOrder": 0}, {"url": "/products/savewo/rat-5in1-20-2.jpg", "alt": "*20支裝* SAVEWO 五合一抗原快速檢測試劑 (新型冠狀病毒(Covid-19) / 甲型流感病毒(Influenza A) / 乙型流感病毒(Influenza B) / RSV呼吸道合胞病毒 / ADV腺病毒)", "sortOrder": 1}, {"url": "/products/savewo/rat-5in1-20-3.jpg", "alt": "*20支裝* SAVEWO 五合一抗原快速檢測試劑 (新型冠狀病毒(Covid-19) / 甲型流感病毒(Influenza A) / 乙型流感病毒(Influenza B) / RSV呼吸道合胞病毒 / ADV腺病毒)", "sortOrder": 2}, {"url": "/products/savewo/rat-5in1-20-4.jpg", "alt": "*20支裝* SAVEWO 五合一抗原快速檢測試劑 (新型冠狀病毒(Covid-19) / 甲型流感病毒(Influenza A) / 乙型流感病毒(Influenza B) / RSV呼吸道合胞病毒 / ADV腺病毒)", "sortOrder": 3}, {"url": "/products/savewo/rat-5in1-20-5.jpg", "alt": "*20支裝* SAVEWO 五合一抗原快速檢測試劑 (新型冠狀病毒(Covid-19) / 甲型流感病毒(Influenza A) / 乙型流感病毒(Influenza B) / RSV呼吸道合胞病毒 / ADV腺病毒)", "sortOrder": 4}]', 360.0, NULL, 'active', 36) ON CONFLICT DO NOTHING;
