INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('0db6e4bc-f3a5-44f9-824d-54e706e098bd', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '88c73897-04a5-4e07-a52d-51c99650ed3f', 'SAVEWO UniPlug UP100S PD3.0 [100W] 5 USB 全球旅行快充插頭', 'uniplug-up100s', '691164af1ab1ef000c162bee', '🔌新一代更細更好用既旅行充電神器！SAVEWO Uniplug UP100S 輕巧全能充電器登場 🔥經常出差周遊列國？你需要一個既輕便又強勁嘅充電夥伴！SAVEWO Uniplug UP100S 專為旅行者設計，體積細小但性能強悍，支援 PD 100W 高速充電，輕鬆應付手機、平板、筆記本電腦等多種設備。🔌 多接口設計，同時快充配備 3個USB-C + 2個USB-A 接口，比舊款UP100多一個 US/JP轉插，可以一次過為多部裝置充電，適合「電子裝備黨」！支援 PD3.0 快充，高耗電設備亦能極速回電:📱iPhone 17 Pro Max 最快充電速度：40W ; 30分鐘即可充至70%💻', '/products/savewo/uniplug-up100s.jpg', '[{"url": "/products/savewo/uniplug-up100s.jpg", "alt": "SAVEWO UniPlug UP100S PD3.0 [100W] 5 USB 全球旅行快充插頭", "sortOrder": 0}, {"url": "/products/savewo/uniplug-up100s-2.jpg", "alt": "SAVEWO UniPlug UP100S PD3.0 [100W] 5 USB 全球旅行快充插頭", "sortOrder": 1}, {"url": "/products/savewo/uniplug-up100s-3.jpg", "alt": "SAVEWO UniPlug UP100S PD3.0 [100W] 5 USB 全球旅行快充插頭", "sortOrder": 2}, {"url": "/products/savewo/uniplug-up100s-4.jpg", "alt": "SAVEWO UniPlug UP100S PD3.0 [100W] 5 USB 全球旅行快充插頭", "sortOrder": 3}, {"url": "/products/savewo/uniplug-up100s-5.jpg", "alt": "SAVEWO UniPlug UP100S PD3.0 [100W] 5 USB 全球旅行快充插頭", "sortOrder": 4}, {"url": "/products/savewo/uniplug-up100s-6.jpg", "alt": "SAVEWO UniPlug UP100S PD3.0 [100W] 5 USB 全球旅行快充插頭", "sortOrder": 5}]', 298.0, NULL, 'active', 40) ON CONFLICT DO NOTHING;
