INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('c96a20bd-f155-4f61-82c0-ab4c3337aa86', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '88c73897-04a5-4e07-a52d-51c99650ed3f', 'Savewo [MagMount PRO2] Qi2.2 磁吸無線充電支架', 'magmount-pro2', '6902e51d3ff03300188afc2d', '《最強無線快充登場》⚡️MagMount PRO2 Qi2.2 磁吸無線充電支架⚡️25W 極速高速無線快充 🚀｜TEC 超強製冷 ❄️｜iPhone &amp; Android 全面兼容 📱雙面 MagSafe 設計 ✨｜三大模式 🔄 極速、極靜、極冷｜手持、桌面、牆壁、車載全場景支援 🏠🚗🔄 三大模式1️⃣ 極速模式通過 Qi2.2 認證的 25W 高速充電 🔋，同時啟動 TEC 製冷系統與靜音風扇，實現高速充電並維持低溫運作。2️⃣ 極靜模式關閉風扇 🔇，輸出 7.5W 無線充電，適用於夜間、閱讀或辦公室等安靜環境。3️⃣ 極冷模式停用無線充電 🎮，啟動最強製冷功能 ❄️，長時間遊戲也能', '/products/savewo/magmount-pro2.jpg', '[{"url": "/products/savewo/magmount-pro2.jpg", "alt": "Savewo [MagMount PRO2] Qi2.2 磁吸無線充電支架", "sortOrder": 0}, {"url": "/products/savewo/magmount-pro2-2.jpg", "alt": "Savewo [MagMount PRO2] Qi2.2 磁吸無線充電支架", "sortOrder": 1}, {"url": "/products/savewo/magmount-pro2-3.jpg", "alt": "Savewo [MagMount PRO2] Qi2.2 磁吸無線充電支架", "sortOrder": 2}, {"url": "/products/savewo/magmount-pro2-4.jpg", "alt": "Savewo [MagMount PRO2] Qi2.2 磁吸無線充電支架", "sortOrder": 3}, {"url": "/products/savewo/magmount-pro2-5.jpg", "alt": "Savewo [MagMount PRO2] Qi2.2 磁吸無線充電支架", "sortOrder": 4}, {"url": "/products/savewo/magmount-pro2-6.jpg", "alt": "Savewo [MagMount PRO2] Qi2.2 磁吸無線充電支架", "sortOrder": 5}]', 338.0, NULL, 'active', 42) ON CONFLICT DO NOTHING;
