INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('4a40bfb4-d052-4fea-9cab-be82fb86d0b5', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '00462c1c-b0f1-475d-b69c-5e40ad30ded5', 'SAVEWO 3DMEOW Demon Black Pink 救世立體喵防護口罩 粉墨 (30片獨立包裝/盒)', '3dmeow-blackpink', '68e8c876f5d1de000e6283d3', '👻 萬聖節限定任務啟動：成為喵系獵人，驅逐黑夜DEMON😈！粉紅耳帶 × 黑霧面罩，甜美型格對撞既暗夜靈氣💗🖤完美詮釋「可愛喵獵人」既神秘風格。✨😺 TYPECOOL+ 高透氣過濾技術連惡魔氣息都阻擋不入！過濾微粒、細菌與病毒，逾24 小時保持輕盈呼吸～💨🩵 ESPP 防敏不織布親膚層柔軟貼面、零刺激，等你舒適作戰到天亮！🌙👂 輕盈舒適耳帶設計即使長時間巡獵都輕鬆 fit，不論大人定小朋友，都係完美獵人造型！🐾🕸️ 「粉墨」喵色登場・期間限定，10月中開始發貨！戴上「粉墨色」3DMEOW 立體喵口罩，化身喵系獵人 —— 驅散黑夜Demon，守護純淨呼吸！🖤🎃💗尺碼參考：KS 兒童細碼 (2-6', '/products/savewo/3dmeow-blackpink.jpg', '[{"url": "/products/savewo/3dmeow-blackpink.jpg", "alt": "SAVEWO 3DMEOW Demon Black Pink 救世立體喵防護口罩 粉墨 (30片獨立包裝/盒)", "sortOrder": 0}]', 119.0, NULL, 'active', 47) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('e2dee5c7-8149-4d44-8018-dc1f869655a8', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'd66b8015-ab1e-4515-9b64-fa994d4452a8', '*2.5cm × 6cm* SAVEWO 救世 TranSkin 全新人工皮防水透氣繃 (水膠體) (5片/盒)', 'traskin-bandages-5', '68c15c71a7cc73000a204370', '🌟 TranSkin全新人工皮防水透氣繃(水膠體)🌟革新傷口護理，助您全面修復肌膚！💧使用濕潤療法✨，可吸收癒合過程中的滲液，減少結痂機率，讓表皮更平整，降低疤痕形成的可能性。🔗 產品網站https://www.savewo.com/healthcare/zh-hk/products/transkin/hydrocolloid/ts-hb2560✨ 五大護理特點：1️⃣ 濕潤療法，加速癒合提供濕潤的環境，促進新生上皮細胞移動，讓傷口快速自癒。2️⃣ 降低結痂，美化傷口減少結痂機率，有效避免疤痕形成，讓肌膚回復平整光滑。3️⃣ 舒緩觸痛，提升舒適感柔軟的水膠體成分覆蓋傷口，減少疼痛與不適。4️⃣', '/products/savewo/traskin-bandages-5.jpg', '[{"url": "/products/savewo/traskin-bandages-5.jpg", "alt": "*2.5cm × 6cm* SAVEWO 救世 TranSkin 全新人工皮防水透氣繃 (水膠體) (5片/盒)", "sortOrder": 0}, {"url": "/products/savewo/traskin-bandages-5-2.jpg", "alt": "*2.5cm × 6cm* SAVEWO 救世 TranSkin 全新人工皮防水透氣繃 (水膠體) (5片/盒)", "sortOrder": 1}, {"url": "/products/savewo/traskin-bandages-5-3.jpg", "alt": "*2.5cm × 6cm* SAVEWO 救世 TranSkin 全新人工皮防水透氣繃 (水膠體) (5片/盒)", "sortOrder": 2}, {"url": "/products/savewo/traskin-bandages-5-4.jpg", "alt": "*2.5cm × 6cm* SAVEWO 救世 TranSkin 全新人工皮防水透氣繃 (水膠體) (5片/盒)", "sortOrder": 3}]', 29.0, NULL, 'active', 48) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('1be0e418-5f73-4170-8ef4-cde55ca7793f', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'ee5d2925-5774-4a23-92ce-01a1b071f520', '*Size 20* Wondaleaf 醫用黏貼敷料袋 (一個獨立包裝)', 'wondaleaf-ap20', '68a6da1ff0d400000adadcd4', '傷口護理新選擇，癒合更安心！✨你是否曾因傷口護理而困擾？無論是急性傷口還是長期慢性傷口，SAVEWO Wondaleaf膠粘敷料袋 都是一個高效、經濟又貼心的解決方案！臨床證明有效，Wondaleaf敷料助力各種傷口快速癒合，讓你輕鬆應對日常護理挑戰，安心恢復健康！每天更換內部紗布，3週內傷口完全癒合，展示了Wondaleaf在慢性傷口管理中的卓越表現！【產品特性】✔ 透明：傷口可視化，便於監測癒合進展✔ 靈活：適合身體不同部位，關節處也能穩固黏貼✔ 透氣防水：保持傷口乾爽且避免外部污染✔ 節省成本：高效護理，減少換敷料頻率✔ 符合ISO 13485認證：品質有保障【修補技術】敷料撕裂或部分脫', '/products/savewo/wondaleaf-ap20.jpg', '[{"url": "/products/savewo/wondaleaf-ap20.jpg", "alt": "*Size 20* Wondaleaf 醫用黏貼敷料袋 (一個獨立包裝)", "sortOrder": 0}, {"url": "/products/savewo/wondaleaf-ap20-2.jpg", "alt": "*Size 20* Wondaleaf 醫用黏貼敷料袋 (一個獨立包裝)", "sortOrder": 1}]', 36.0, NULL, 'active', 49) ON CONFLICT DO NOTHING;
