INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('49f2268b-693c-4fb2-a921-9d0b123ff838', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '3b4f89f7-ada4-4fe0-9f12-d3040323a344', 'RAINEC AIR PLUS 超輕特大遮面摺疊遮', 'rainec-airplus', '6880be215dca05000c260b8a', '🌂【Rainec Air Plus 超輕特大遮面摺疊雨傘，全新登場！】Rainec Air Plus 係晴雨天出行既最佳夥伴！採用超輕碳纖維複合傘骨，重量只有190g，長度27cm，但展開後遮面直徑達107cm，超級大把，就算孭住個大背囊都遮得到，輕便又實用！結合碳纖維與鋁鎂合金材質，具備強化防風功能，一把極其輕盈且耐用既摺疊雨傘，為你提供超大防護範圍，有效遮擋100%可見光，UPF高達2000，遮蔽99.95% UV！幫你遮陽！防曬！之餘，仲大幅減少陽光既熱力，帶你進入降温達16度既世界！無論係大雨﹑大太陽定大風都能輕鬆應對。Rainec Air Plus新增掛繩同繩扣設計，掛繩由高彈力尼龍', '/products/savewo/rainec-airplus.jpg', '[{"url": "/products/savewo/rainec-airplus.jpg", "alt": "RAINEC AIR PLUS 超輕特大遮面摺疊遮", "sortOrder": 0}, {"url": "/products/savewo/rainec-airplus-2.jpg", "alt": "RAINEC AIR PLUS 超輕特大遮面摺疊遮", "sortOrder": 1}, {"url": "/products/savewo/rainec-airplus-3.jpg", "alt": "RAINEC AIR PLUS 超輕特大遮面摺疊遮", "sortOrder": 2}, {"url": "/products/savewo/rainec-airplus-4.jpg", "alt": "RAINEC AIR PLUS 超輕特大遮面摺疊遮", "sortOrder": 3}, {"url": "/products/savewo/rainec-airplus-5.jpg", "alt": "RAINEC AIR PLUS 超輕特大遮面摺疊遮", "sortOrder": 4}, {"url": "/products/savewo/rainec-airplus-6.jpg", "alt": "RAINEC AIR PLUS 超輕特大遮面摺疊遮", "sortOrder": 5}]', 198.0, NULL, 'active', 61) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('22ed012b-63a9-41ba-b2c8-0e7b751fb871', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '3b4f89f7-ada4-4fe0-9f12-d3040323a344', 'RAINEC SLIM 超輕便摺疊遮', 'rainec-slim', '6880b9b69cc453fa105fdaa4', '🌂【Rainec Slim 超輕便摺疊遮登場，收納尺寸更細，遮蓋面積更大！】Rainec Slim收起上嚟可能比你想像既更輕更小！僅150g，23cm長，收起時直徑仲只有4cm。雖然細細把，打後的遮蔽直徑達99cm，無論男士定女士都適用！碳纖維 + 鋁鎂合金複合傘骨設有防反設計，打風落水當然無有怕，開合亦極其順暢，輕盈超堅硬，輕鬆駕馭。更有效遮擋可見光，又防UV！不單止遮陽防曬，更可大幅減少陽光熱力，實測可以降温達16度！ Rainec Air Slim新增掛繩同繩扣設計，掛繩由高彈力尼龍物料製成，堅韌耐用，繩扣只需輕輕一扣，就可以將雨遮掛係袋上，隨身攜帶，輕鬆自在。新版傘套的內裡布料升級為高', '/products/savewo/rainec-slim.jpg', '[{"url": "/products/savewo/rainec-slim.jpg", "alt": "RAINEC SLIM 超輕便摺疊遮", "sortOrder": 0}, {"url": "/products/savewo/rainec-slim-2.jpg", "alt": "RAINEC SLIM 超輕便摺疊遮", "sortOrder": 1}, {"url": "/products/savewo/rainec-slim-3.jpg", "alt": "RAINEC SLIM 超輕便摺疊遮", "sortOrder": 2}, {"url": "/products/savewo/rainec-slim-4.jpg", "alt": "RAINEC SLIM 超輕便摺疊遮", "sortOrder": 3}, {"url": "/products/savewo/rainec-slim-5.jpg", "alt": "RAINEC SLIM 超輕便摺疊遮", "sortOrder": 4}, {"url": "/products/savewo/rainec-slim-6.jpg", "alt": "RAINEC SLIM 超輕便摺疊遮", "sortOrder": 5}]', 168.0, NULL, 'active', 62) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('f56b2db3-f310-4d8e-b692-1fc4de2673ae', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '3b4f89f7-ada4-4fe0-9f12-d3040323a344', 'Rainec ULTRA 遮套', 'rainec-ultra-cover', '68809c3f45bb470014ab92b2', '全新 Rainec Ultra 遮套，新設計配備可調節長度肩帶，為你提供更方便、更實用的使用體驗。無論身型高矮、肩膊寬窄，都能輕鬆調整至最適合的位置，確保攜帶時舒適貼身，同時又展現時尚型格，方便收納和攜帶，解放雙手！', '/products/savewo/rainec-ultra-cover.jpg', '[{"url": "/products/savewo/rainec-ultra-cover.jpg", "alt": "Rainec ULTRA 遮套", "sortOrder": 0}, {"url": "/products/savewo/rainec-ultra-cover-2.jpg", "alt": "Rainec ULTRA 遮套", "sortOrder": 1}]', 50.0, NULL, 'active', 63) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('fc3e3b4e-3c38-4d54-862e-5f2cadcedafb', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '0e7588df-a28c-4b75-80be-f1b9352e282e', 'SAVEWO AirFlow Cool Fan 2 便攜式冰感風扇 2', 'coolfan2', '687e0ddb539433d726cf04f5', '🔥 Savewo AirFlow COOL FAN 2 新登場！熱到爆嘅夏天有救啦！🔥呢排香港嘅天氣除咗落雨就係又熱又焗，完全唔想離開有冷氣嘅地方。Savewo AirFlow COOL FAN 2專門應付夏天嘅悶熱！無論你喺屋企定出街，呢把風扇都可以即刻幫你降溫，涼到震！佢用咗超勁嘅超導冷卻板技術，1秒就令你體感溫度跌 -12°C，涼風直入皮膚，熱辣辣嘅日子都唔怕！🧊隨時隨地，爽到飛起！✨ 🌬️ 1秒極速凍感：撳個掣就涼，體感溫度即刻降 -12°C，熱氣全消！💡 LED 顯示：電量、模式一眼睇晒，操作超簡單！🌟 輕到冇朋友：採用鋰聚合物電池，只係重183克，拎出街零負擔，🔋 4000mAh ', '/products/savewo/coolfan2.jpg', '[{"url": "/products/savewo/coolfan2.jpg", "alt": "SAVEWO AirFlow Cool Fan 2 便攜式冰感風扇 2", "sortOrder": 0}, {"url": "/products/savewo/coolfan2-2.jpg", "alt": "SAVEWO AirFlow Cool Fan 2 便攜式冰感風扇 2", "sortOrder": 1}, {"url": "/products/savewo/coolfan2-3.jpg", "alt": "SAVEWO AirFlow Cool Fan 2 便攜式冰感風扇 2", "sortOrder": 2}, {"url": "/products/savewo/coolfan2-4.jpg", "alt": "SAVEWO AirFlow Cool Fan 2 便攜式冰感風扇 2", "sortOrder": 3}, {"url": "/products/savewo/coolfan2-5.jpg", "alt": "SAVEWO AirFlow Cool Fan 2 便攜式冰感風扇 2", "sortOrder": 4}, {"url": "/products/savewo/coolfan2-6.jpg", "alt": "SAVEWO AirFlow Cool Fan 2 便攜式冰感風扇 2", "sortOrder": 5}]', 238.0, NULL, 'active', 64) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('061ae4fb-7e04-4290-b278-cbc02362c045', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '3b4f89f7-ada4-4fe0-9f12-d3040323a344', 'Rainec Prime 超輕高性能碳纖維雨傘', 'rainec-prime', '6870e9711db833000cfe5076', '✨超輕高性能碳纖維雨傘Rainec Prime全新登場！全新專利手柄設計符合人體工學，進化你既長遮使用體驗✨萬眾期待，繼承Rainec Ultra！擁有U型手柄既碳纖維雨傘 Rainec Prime終於推出！🎉全碳纖維骨架設計，輕量而堅固，單手輕鬆操作，一鍵自動開遮，開合極其順暢，全遮只有365g，展開直徑達109cm，收合長度84cm，更有防風防反設計。全新專利手柄設計提供舒適握感，配合Rainec Tex技術，無懼日曬！風吹！雨打！，為你提供超Prime既保護同體驗，成為你最佳晴雨夥伴！小改變，大提升💡🤚 人體工學手柄：U型防滑啞光手柄符合手掌自然曲線，3個支點，強風中穩定不搖晃，兼具質感', '/products/savewo/rainec-prime.jpg', '[{"url": "/products/savewo/rainec-prime.jpg", "alt": "Rainec Prime 超輕高性能碳纖維雨傘", "sortOrder": 0}, {"url": "/products/savewo/rainec-prime-2.jpg", "alt": "Rainec Prime 超輕高性能碳纖維雨傘", "sortOrder": 1}, {"url": "/products/savewo/rainec-prime-3.jpg", "alt": "Rainec Prime 超輕高性能碳纖維雨傘", "sortOrder": 2}, {"url": "/products/savewo/rainec-prime-4.jpg", "alt": "Rainec Prime 超輕高性能碳纖維雨傘", "sortOrder": 3}, {"url": "/products/savewo/rainec-prime-5.jpg", "alt": "Rainec Prime 超輕高性能碳纖維雨傘", "sortOrder": 4}, {"url": "/products/savewo/rainec-prime-6.jpg", "alt": "Rainec Prime 超輕高性能碳纖維雨傘", "sortOrder": 5}, {"url": "/products/savewo/rainec-prime-7.jpg", "alt": "Rainec Prime 超輕高性能碳纖維雨傘", "sortOrder": 6}]', 199.0, NULL, 'active', 65) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('79559c71-b541-4506-adec-36d5e02958e7', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '88c73897-04a5-4e07-a52d-51c99650ed3f', 'SAVEWO UniPlug UP35 PD3.0 [35W] 5 USB 全球旅行快充插頭', 'uniplug-up35', '685e6ced6901d4d86de2b5ea', 'SAVEWO UniPlug UP35 PD3.0 [35W] 5 USB 全球旅行快充插頭1️⃣ 輕巧便攜設計重量只有153g，尺寸64.3 x 55.5 x 52.5 mm，仲細過粒扭計骰，放行李箱或背包都完全無負擔！性價比之選：救世價實惠$148，萬一遺失都唔會太心痛！👍2️⃣ 安全多埠充電，告別排隊配有 3個USB-C + 2個USB-A，1個US轉插，以及萬能轉插，最多同時支援7個設備！PD3.0快充：穩定高效，35W 快速充電足夠應付日常需求，iPhone快充更加唔在話下！📱⚡👍🏻安全丨備用10A保險絲、安全活門設計3️⃣ 氮化鎵(GaN)技術充電效率更高，減少熱損失，穩定又安全！', '/products/savewo/uniplug-up35.jpg', '[{"url": "/products/savewo/uniplug-up35.jpg", "alt": "SAVEWO UniPlug UP35 PD3.0 [35W] 5 USB 全球旅行快充插頭", "sortOrder": 0}, {"url": "/products/savewo/uniplug-up35-2.jpg", "alt": "SAVEWO UniPlug UP35 PD3.0 [35W] 5 USB 全球旅行快充插頭", "sortOrder": 1}, {"url": "/products/savewo/uniplug-up35-3.jpg", "alt": "SAVEWO UniPlug UP35 PD3.0 [35W] 5 USB 全球旅行快充插頭", "sortOrder": 2}, {"url": "/products/savewo/uniplug-up35-4.jpg", "alt": "SAVEWO UniPlug UP35 PD3.0 [35W] 5 USB 全球旅行快充插頭", "sortOrder": 3}]', 148.0, NULL, 'active', 66) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('bb737ee4-ef27-4dea-8014-38f63d60f92a', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '7ed7ec4c-f825-40e7-99d9-486092d7834c', 'SAVEWO HEALTHCHAIR 迷你無線遙控器及手柄組合 (ZC1專用後控制)', 'savewo-healthchair-wireless-remote-control', '684a7672483a86000fb4e5a1', '無線遙控器使用藍牙技術加密，不受任何延遲干擾，開機即可連接。遙控器手柄使用3D打印技術，輕便耐用，並適合照顧者長時間控制。電量續航：約10小時使用時間產品組合包括: 迷你無線遙控器、手柄*、USB-C充電線。*ZC1專用（*可選購左手或右手的手柄）', '/products/savewo/savewo-healthchair-wireless-remote-control.jpg', '[{"url": "/products/savewo/savewo-healthchair-wireless-remote-control.jpg", "alt": "SAVEWO HEALTHCHAIR 迷你無線遙控器及手柄組合 (ZC1專用後控制)", "sortOrder": 0}, {"url": "/products/savewo/savewo-healthchair-wireless-remote-control-2.jpg", "alt": "SAVEWO HEALTHCHAIR 迷你無線遙控器及手柄組合 (ZC1專用後控制)", "sortOrder": 1}]', 1680.0, NULL, 'active', 67) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('40ec7093-0a89-4942-af36-2cadc998a8f7', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '7ed7ec4c-f825-40e7-99d9-486092d7834c', 'SAVEWO HEALTHCHAIR 三段可調教式頭枕 (ZC1及ZA1專用)', 'savewo-healthchair-headrest', '684803729718eb0010ee99b6', 'Healthchair ZC1 &amp; ZA1 專用輪椅頭枕可分三段調節，包括頭，頸，上背段 。可調高度，伸縮及斜度。頭枕提供額外的支撐，增強使用者長時間坐在輪椅上的舒適感，減少疲勞。產品包含支架及安裝。重量：2.5KG"', '/products/savewo/savewo-healthchair-headrest.jpg', '[{"url": "/products/savewo/savewo-healthchair-headrest.jpg", "alt": "SAVEWO HEALTHCHAIR 三段可調教式頭枕 (ZC1及ZA1專用)", "sortOrder": 0}]', 599.0, NULL, 'active', 68) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('e8a8aafd-8c1e-4cca-b7dc-e18251e8f77e', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '0e7588df-a28c-4b75-80be-f1b9352e282e', 'SAVEWO AirFlow Clip Fan 多功能夾扇', 'clipfan', '683d6159f7643c000cb14403', 'SAVEWO AirFlow ClipFan 多功能夾扇✔️ 4種模式，無論咩場景都啱用 🌟✔️ 3段風速靜音設計操作超簡單，一鍵即開！💨✔️ 續航最長7小時，持續清涼無煩惱 🌬️✔️ 淨152g超輕，戴住都唔覺重 🎒🔗 產品網站https://savewo.com/energy/airflow/clipfan/多用途設計：1️⃣ 手持模式 💨細細部又輕巧，隨時拎住吹涼風，行街都唔怕焗住。2️⃣ 桌面模式 🖥️普通風扇仔放喺枱面容易跌，ClipFan手柄可以180度調角度，變底座靚靚咁放喺桌面，返工或者休息都啱晒！3️⃣ 掛頸模式 🎒附送掛繩，長短仲可以調，普通風扇仔要用手拎住，ClipFan', '/products/savewo/clipfan.jpg', '[{"url": "/products/savewo/clipfan.jpg", "alt": "SAVEWO AirFlow Clip Fan 多功能夾扇", "sortOrder": 0}, {"url": "/products/savewo/clipfan-2.jpg", "alt": "SAVEWO AirFlow Clip Fan 多功能夾扇", "sortOrder": 1}, {"url": "/products/savewo/clipfan-3.jpg", "alt": "SAVEWO AirFlow Clip Fan 多功能夾扇", "sortOrder": 2}]', 89.0, NULL, 'active', 69) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('329a394f-8666-48a7-a327-82ed4a0d81d9', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'd66b8015-ab1e-4515-9b64-fa994d4452a8', 'SAVEWO MasterCane 超輕碳纖維摺疊式拐杖', 'mastercane', '6836c25c71a573000fad9250', '🌟 SAVEWO 推動樂齡科技新發展！首創超輕碳纖維摺疊式拐杖「MasterCane 大師杖」 🌟🚶‍♀️隨著香港人口老化，預計到2031年，60歲以上的長者比例將超過30%。繼推出HealthChair 智能電動輪椅之後，眾多顧客詢問是否會有更多樂齡產品。因此，SAVEWO 再次創新，針對樂齡市場推出全新的碳纖維可折疊手杖「MasterCane大師杖」，並榮獲「HKSDA 2025」設計界的金獎。讓我們一起來了解其創新設計與先進科技材料的結合。🔗 產品網站https://www.savewo.com/healthcare/zh-hk/products/mastercane/mcf1產品特點：', '/products/savewo/mastercane.jpg', '[{"url": "/products/savewo/mastercane.jpg", "alt": "SAVEWO MasterCane 超輕碳纖維摺疊式拐杖", "sortOrder": 0}, {"url": "/products/savewo/mastercane-2.jpg", "alt": "SAVEWO MasterCane 超輕碳纖維摺疊式拐杖", "sortOrder": 1}, {"url": "/products/savewo/mastercane-3.jpg", "alt": "SAVEWO MasterCane 超輕碳纖維摺疊式拐杖", "sortOrder": 2}, {"url": "/products/savewo/mastercane-4.jpg", "alt": "SAVEWO MasterCane 超輕碳纖維摺疊式拐杖", "sortOrder": 3}, {"url": "/products/savewo/mastercane-5.jpg", "alt": "SAVEWO MasterCane 超輕碳纖維摺疊式拐杖", "sortOrder": 4}, {"url": "/products/savewo/mastercane-6.jpg", "alt": "SAVEWO MasterCane 超輕碳纖維摺疊式拐杖", "sortOrder": 5}]', 980.0, NULL, 'sold_out', 70) ON CONFLICT DO NOTHING;
