INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('f90ac19b-899b-4371-b8a4-6aada27f8e05', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '7ed7ec4c-f825-40e7-99d9-486092d7834c', '*半價超級優惠 5折！$4,990* SAVEWO HEALTHCHAIR Z ALUMINUM ZA1 全鋁合金電動輪椅', 'healthchair-zaluminumza1-1', '67ff76595893300010b25181', '半價超級優惠 5折！$4,990 原價 $11000 試車預約：95482544SAVEWO HEALTHCHAIR Z ALUMINUM - ZA1鋁合金製  安全舒適  輕巧易用 「性價比最高」全鋁合金電動輪椅🔗 產品網站https://healthchair.com/za1/特點：*輕量化 - 採用鋁合金車架，堅固耐用，絕不生銹，連電池總重僅為19kg，安全負重達100kg。*快速摺疊 - 簡單步驟即可摺疊，便於攜帶和存放。*持久續航力 - 採用高容量電池時，一次充電提供高達30km續航力，充沛的電力滿足日常出行。*無刷電機 - 180W*2的動力輸出，提供高達7度的上斜動力。*EABS', '/products/savewo/healthchair-zaluminumza1-1.jpg', '[{"url": "/products/savewo/healthchair-zaluminumza1-1.jpg", "alt": "*半價超級優惠 5折！$4,990* SAVEWO HEALTHCHAIR Z ALUMINUM ZA1 全鋁合金電動輪椅", "sortOrder": 0}, {"url": "/products/savewo/healthchair-zaluminumza1-1-2.jpg", "alt": "*半價超級優惠 5折！$4,990* SAVEWO HEALTHCHAIR Z ALUMINUM ZA1 全鋁合金電動輪椅", "sortOrder": 1}, {"url": "/products/savewo/healthchair-zaluminumza1-1-3.jpg", "alt": "*半價超級優惠 5折！$4,990* SAVEWO HEALTHCHAIR Z ALUMINUM ZA1 全鋁合金電動輪椅", "sortOrder": 2}, {"url": "/products/savewo/healthchair-zaluminumza1-1-4.jpg", "alt": "*半價超級優惠 5折！$4,990* SAVEWO HEALTHCHAIR Z ALUMINUM ZA1 全鋁合金電動輪椅", "sortOrder": 3}, {"url": "/products/savewo/healthchair-zaluminumza1-1-5.jpg", "alt": "*半價超級優惠 5折！$4,990* SAVEWO HEALTHCHAIR Z ALUMINUM ZA1 全鋁合金電動輪椅", "sortOrder": 4}, {"url": "/products/savewo/healthchair-zaluminumza1-1-6.jpg", "alt": "*半價超級優惠 5折！$4,990* SAVEWO HEALTHCHAIR Z ALUMINUM ZA1 全鋁合金電動輪椅", "sortOrder": 5}, {"url": "/products/savewo/healthchair-zaluminumza1-1-7.jpg", "alt": "*半價超級優惠 5折！$4,990* SAVEWO HEALTHCHAIR Z ALUMINUM ZA1 全鋁合金電動輪椅", "sortOrder": 6}, {"url": "/products/savewo/healthchair-zaluminumza1-1-8.jpg", "alt": "*半價超級優惠 5折！$4,990* SAVEWO HEALTHCHAIR Z ALUMINUM ZA1 全鋁合金電動輪椅", "sortOrder": 7}]', 1000.0, NULL, 'active', 74) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('01a79f98-1b69-49d7-928f-53cc43570368', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '88c73897-04a5-4e07-a52d-51c99650ed3f', 'SAVEWO x 別天神 幪面超人RX 浮世繪 MagCell MC509 5000mAh Wireless PowerBank', 'magcell-mc509-kamenrider', '67fe1fb118e9dde31d94156a', '【浮世繪風重塑傳奇英雄，SAVEWO x 別天神 幪面超人RX MagCell浮世繪系列壯麗登場！】當幪面超人的熱血精神，遇上日本浮世繪的藝術靈魂，一場跨越時代的英雄進化正式啟動！SAVEWO全新聯乘系列，以幪面超人RX世界觀為核心，重現RX、Black、Robo Rider 與 Bio Rider的傳奇風采，從日式浮世繪的武者、浪士、擬人動物與自然意象中汲取靈感，搭配幪面超人的經典造型，展現獨特視覺張力。融合勇氣、智慧與堅毅精神，重現昭和特攝作品中熱血不滅的英雄本色，凝縮在4款設計之中，把戰士的精神、力量與堅毅，以藝術語言再現。每一款都融合角色個性與浮世繪精神，成就獨一無二的藝術風格收藏。搭', '/products/savewo/magcell-mc509-kamenrider.jpg', '[{"url": "/products/savewo/magcell-mc509-kamenrider.jpg", "alt": "SAVEWO x 別天神 幪面超人RX 浮世繪 MagCell MC509 5000mAh Wireless PowerBank", "sortOrder": 0}, {"url": "/products/savewo/magcell-mc509-kamenrider-2.jpg", "alt": "SAVEWO x 別天神 幪面超人RX 浮世繪 MagCell MC509 5000mAh Wireless PowerBank", "sortOrder": 1}, {"url": "/products/savewo/magcell-mc509-kamenrider-3.jpg", "alt": "SAVEWO x 別天神 幪面超人RX 浮世繪 MagCell MC509 5000mAh Wireless PowerBank", "sortOrder": 2}, {"url": "/products/savewo/magcell-mc509-kamenrider-4.jpg", "alt": "SAVEWO x 別天神 幪面超人RX 浮世繪 MagCell MC509 5000mAh Wireless PowerBank", "sortOrder": 3}, {"url": "/products/savewo/magcell-mc509-kamenrider-5.jpg", "alt": "SAVEWO x 別天神 幪面超人RX 浮世繪 MagCell MC509 5000mAh Wireless PowerBank", "sortOrder": 4}]', 238.0, NULL, 'active', 75) ON CONFLICT DO NOTHING;
