INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('27dbb712-4e67-4220-a772-da37efa8eb0c', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '88c73897-04a5-4e07-a52d-51c99650ed3f', 'SAVEWO MagCell MC511QF 世界最細Qi2無線充電行動電源 （*內置Find My 定位功能）', 'magcell-mc511qf', '67d154c79196d0000ba62a6f', 'SAVEWO一直以來都持續創新，挑戰難度，為用家提供最好的產品。我們於美國CES2025公佈了全新開發的 MagCell Qi2 MC511Q2，以世界最小最薄*WPC Qi2官方認證（QI-23671），厚度🤏🏻僅有8mm，輕巧便攜🎒，強大性能，高貴材質✨，成功脫穎而出，受到各國訪客關注。同時開發的姊妹型號MC511QF，更取得Apple Mfi 認證，在完全不增加體積的情況下，内置FindMy定位功能，突破不可能！MC511系列兼具強大功能及時尚外觀，採用頂級雙面強化玻璃與高強度鋁合金邊框，打造出堅固而時尚的外觀，猶如一部全新的iPhone 手機📱。白銀鏡面版光滑亮麗，可作為隨行鏡子🪞，方', '/products/savewo/magcell-mc511qf.jpg', '[{"url": "/products/savewo/magcell-mc511qf.jpg", "alt": "SAVEWO MagCell MC511QF 世界最細Qi2無線充電行動電源 （*內置Find My 定位功能）", "sortOrder": 0}, {"url": "/products/savewo/magcell-mc511qf-2.jpg", "alt": "SAVEWO MagCell MC511QF 世界最細Qi2無線充電行動電源 （*內置Find My 定位功能）", "sortOrder": 1}, {"url": "/products/savewo/magcell-mc511qf-3.jpg", "alt": "SAVEWO MagCell MC511QF 世界最細Qi2無線充電行動電源 （*內置Find My 定位功能）", "sortOrder": 2}, {"url": "/products/savewo/magcell-mc511qf-4.jpg", "alt": "SAVEWO MagCell MC511QF 世界最細Qi2無線充電行動電源 （*內置Find My 定位功能）", "sortOrder": 3}, {"url": "/products/savewo/magcell-mc511qf-5.jpg", "alt": "SAVEWO MagCell MC511QF 世界最細Qi2無線充電行動電源 （*內置Find My 定位功能）", "sortOrder": 4}, {"url": "/products/savewo/magcell-mc511qf-6.jpg", "alt": "SAVEWO MagCell MC511QF 世界最細Qi2無線充電行動電源 （*內置Find My 定位功能）", "sortOrder": 5}, {"url": "/products/savewo/magcell-mc511qf-7.jpg", "alt": "SAVEWO MagCell MC511QF 世界最細Qi2無線充電行動電源 （*內置Find My 定位功能）", "sortOrder": 6}]', 338.0, NULL, 'active', 82) ON CONFLICT DO NOTHING;
