INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('e0ecdc5a-1c3f-4a4c-b36f-ce36ff71955c', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '88c73897-04a5-4e07-a52d-51c99650ed3f', 'SAVEWO MagCell Ultra MC1002Q2 多功能Qi2無線充電行動電源', 'magcell-mc1002q2', '67c01c2297c8ab000ed34c1c', 'SAVEWO MagCell Ultra Qi2 MC1002Q2具備真Qi2認證（QI-23604)的15W高速無線充電技術🔋，內置高耐用度 USB-C和Lightning內建電源線，提供最高達PD 22.5W的快速輸出。支援無線有線同步輸出及充放同步，把充電效率最大化，真正達到一機多用的效果。內置鋁合金支架，讓你邊充電邊使用手機，大大提升實用性。MC1002Q2的顯示器可以實時顯示電量及充電速度⏲，讓你隨時掌握充電狀態。採用優質10000mAh 3.85V 38.5Wh高電量電芯，配及優質電源管理系統，提供了優秀的能源轉換率，相比同類型產品能提供更多實際可用電量。MC1002Q2真正通過W', '/products/savewo/magcell-mc1002q2.jpg', '[{"url": "/products/savewo/magcell-mc1002q2.jpg", "alt": "SAVEWO MagCell Ultra MC1002Q2 多功能Qi2無線充電行動電源", "sortOrder": 0}, {"url": "/products/savewo/magcell-mc1002q2-2.jpg", "alt": "SAVEWO MagCell Ultra MC1002Q2 多功能Qi2無線充電行動電源", "sortOrder": 1}, {"url": "/products/savewo/magcell-mc1002q2-3.jpg", "alt": "SAVEWO MagCell Ultra MC1002Q2 多功能Qi2無線充電行動電源", "sortOrder": 2}, {"url": "/products/savewo/magcell-mc1002q2-4.jpg", "alt": "SAVEWO MagCell Ultra MC1002Q2 多功能Qi2無線充電行動電源", "sortOrder": 3}, {"url": "/products/savewo/magcell-mc1002q2-5.jpg", "alt": "SAVEWO MagCell Ultra MC1002Q2 多功能Qi2無線充電行動電源", "sortOrder": 4}]', 338.0, NULL, 'active', 84) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('70033c36-cd48-4e1c-acab-b75f249f78f0', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '00462c1c-b0f1-475d-b69c-5e40ad30ded5', '*KS 兒童細碼 旅行裝* SAVEWO 3DMEOW WHITE 救世立體喵兒童防護口罩 純白色 (5片獨立包裝/袋) (2-6歲適用)', '3dmeows2white5pcs', '67abfe8add1c88000b78873f', '*本產品將以旅行裝形式發貨，產品性能不變，請放心購買 !*SAVEWO 3DMEOW for Kids救世立體喵兒童防護口罩！萌爆升級！童心抗疫！綻放笑容！立體喵！超透氣！強過濾！採用救世最新TypeCool＋過濾技術，前所未有的透氣感受，配合 ESPP 不織布親膚物料及舒適型耳帶，質感柔軟舒適。把最好的都給予小朋友，讓他們戴著口罩也能綻放笑容！SAVEWO 3DMEOW for Kids 救世立體喵是即棄式兒童防護口罩，採用專利萌爆立體剪裁，有效增加呼吸空間，長時間穿戴也十分舒適，設有2款尺碼，適配2-6歲小童及7-13歲中童的臉型。升級版本採用最新TypeCool+ 過濾技術，超低呼吸阻力', '/products/savewo/3dmeows2white5pcs.jpg', '[{"url": "/products/savewo/3dmeows2white5pcs.jpg", "alt": "*KS 兒童細碼 旅行裝* SAVEWO 3DMEOW WHITE 救世立體喵兒童防護口罩 純白色 (5片獨立包裝/袋) (2-6歲適用)", "sortOrder": 0}, {"url": "/products/savewo/3dmeows2white5pcs-2.jpg", "alt": "*KS 兒童細碼 旅行裝* SAVEWO 3DMEOW WHITE 救世立體喵兒童防護口罩 純白色 (5片獨立包裝/袋) (2-6歲適用)", "sortOrder": 1}, {"url": "/products/savewo/3dmeows2white5pcs-3.jpg", "alt": "*KS 兒童細碼 旅行裝* SAVEWO 3DMEOW WHITE 救世立體喵兒童防護口罩 純白色 (5片獨立包裝/袋) (2-6歲適用)", "sortOrder": 2}, {"url": "/products/savewo/3dmeows2white5pcs-4.jpg", "alt": "*KS 兒童細碼 旅行裝* SAVEWO 3DMEOW WHITE 救世立體喵兒童防護口罩 純白色 (5片獨立包裝/袋) (2-6歲適用)", "sortOrder": 3}, {"url": "/products/savewo/3dmeows2white5pcs-5.jpg", "alt": "*KS 兒童細碼 旅行裝* SAVEWO 3DMEOW WHITE 救世立體喵兒童防護口罩 純白色 (5片獨立包裝/袋) (2-6歲適用)", "sortOrder": 4}]', 25.0, NULL, 'active', 85) ON CONFLICT DO NOTHING;
