INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('e3b5f3fb-444b-4b4a-a77e-315f7c04c2ec', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '88c73897-04a5-4e07-a52d-51c99650ed3f', 'SAVEWO Magcell MC509新年發福特別版', 'magcell-mc509-cny', '678a29efdb79b7000ddb10f1', '今個新春小狼與小豹化身成招財貓，帶著「發財大吉」與「福氣滿滿」的美好祝願來到你身邊🎉！SAVEWO特別推出Magcell MC509新年發福特別版，設計靈感來自於吉祥的招財貓，熱烈的紅金色調不僅迎合節日氣氛，更象徵著一年的好運與豐收。小狼與小豹換上了招財貓新裝，不僅增添了幾分俏皮可愛，更是財富和幸運的美好象徵。讓「發達亨通」與「福如東海」的祝福伴隨你度過每一天，是新春佳節送禮自用的絕佳選擇！Magcell MC509新年發福特別版是最細小的5000mAh磁吸無線充電行動電源，厚度只有8mm及僅重108g，帶著它四處拜年也絕不成為負擔。設有20W PD USB-C輸出，以及最高15W的無線快充功', '/products/savewo/magcell-mc509-cny.jpg', '[{"url": "/products/savewo/magcell-mc509-cny.jpg", "alt": "SAVEWO Magcell MC509新年發福特別版", "sortOrder": 0}, {"url": "/products/savewo/magcell-mc509-cny-2.jpg", "alt": "SAVEWO Magcell MC509新年發福特別版", "sortOrder": 1}, {"url": "/products/savewo/magcell-mc509-cny-3.jpg", "alt": "SAVEWO Magcell MC509新年發福特別版", "sortOrder": 2}]', 238.0, NULL, 'active', 88) ON CONFLICT DO NOTHING;
