INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('5e974408-cafc-466e-9eb7-19c7277fc7c5', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '00462c1c-b0f1-475d-b69c-5e40ad30ded5', '*ADT 成人版* SAVEWO 3DMEOW 救世立體喵成人版防護口罩 農曆新年別注版 (30片獨立包裝/盒) (90%以上成人適用)', 'savewo-3dmeow-adt-cny', '677f878836cda3000f69bf29', '3DMEOW 農曆新年別注版，萌爆可愛、人見人愛、身體健康、百毒不侵啦🤩！佢嘅「紅」運當頭口罩 + 黃「金」滿屋耳帶設計，真係襯晒過年喜喜慶慶氣氛，就算平時佩戴都夠晒精神爽利！小狼提提大家，3DMEOW 農曆新年別注版正做緊限時買2送1優惠，仲要齊備兒童細碼、兒童大碼、頑童版、成人版，幼童、少年、小顏人士及成人都啱用，真係好啱一家大細去拜年架👩‍👩‍👧‍👦！依家即刻入手，為新一年做好準備！特點:細菌過濾效率 BFE≥99.9%顆粒過濾效率 PFE≥99.9%病毒過濾效率 VFE≥99.9%創新  過濾技術，超強過濾極致透氣，能持久保持過濾效能，過濾效率有效24小時以上超低呼吸阻力 Breath', '/products/savewo/savewo-3dmeow-adt-cny.jpg', '[{"url": "/products/savewo/savewo-3dmeow-adt-cny.jpg", "alt": "*ADT 成人版* SAVEWO 3DMEOW 救世立體喵成人版防護口罩 農曆新年別注版 (30片獨立包裝/盒) (90%以上成人適用)", "sortOrder": 0}, {"url": "/products/savewo/savewo-3dmeow-adt-cny-2.jpg", "alt": "*ADT 成人版* SAVEWO 3DMEOW 救世立體喵成人版防護口罩 農曆新年別注版 (30片獨立包裝/盒) (90%以上成人適用)", "sortOrder": 1}, {"url": "/products/savewo/savewo-3dmeow-adt-cny-3.jpg", "alt": "*ADT 成人版* SAVEWO 3DMEOW 救世立體喵成人版防護口罩 農曆新年別注版 (30片獨立包裝/盒) (90%以上成人適用)", "sortOrder": 2}, {"url": "/products/savewo/savewo-3dmeow-adt-cny-4.jpg", "alt": "*ADT 成人版* SAVEWO 3DMEOW 救世立體喵成人版防護口罩 農曆新年別注版 (30片獨立包裝/盒) (90%以上成人適用)", "sortOrder": 3}]', 149.0, NULL, 'active', 91) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('c5d6906e-b24b-49a5-bd4a-32b4c84fce12', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'd66b8015-ab1e-4515-9b64-fa994d4452a8', 'Airwheel SQ3 兒童電動騎行行李箱', 'airwheel-sq3', '675a886482c0df000c8c8db1', '探索孩子的小小世界，讓旅行變得更加有趣！Airwheel SQ3 兒童多功能行李箱，專為3至6歲的小朋友設計。這款20英寸的行李箱重量僅4.7公斤，但承重能力高達40公斤，內部空間達到18升，足以容納孩子的所有冒險裝備。尺寸與重量：20英寸大小，重4.7公斤，最大承重40公斤。存儲容量：內部空間達18升，足夠裝下孩子的旅行必需品。適用年齡範圍：適合3至6歲的兒童。材質：主體採用堅固的聚碳酸酯材料，耐磨抗撞。輪子使用耐磨TPU材質，行駛平穩且靜音。功能設計：彩色燈光輪子，增加夜間的安全性和吸引力。內置音樂播放器，支持Micro SD卡，旅途中即可享受音樂。可拆卸拉桿和座椅設計，提供坐騎與拉行的雙', '/products/savewo/airwheel-sq3.jpg', '[{"url": "/products/savewo/airwheel-sq3.jpg", "alt": "Airwheel SQ3 兒童電動騎行行李箱", "sortOrder": 0}, {"url": "/products/savewo/airwheel-sq3-2.jpg", "alt": "Airwheel SQ3 兒童電動騎行行李箱", "sortOrder": 1}, {"url": "/products/savewo/airwheel-sq3-3.jpg", "alt": "Airwheel SQ3 兒童電動騎行行李箱", "sortOrder": 2}, {"url": "/products/savewo/airwheel-sq3-4.jpg", "alt": "Airwheel SQ3 兒童電動騎行行李箱", "sortOrder": 3}, {"url": "/products/savewo/airwheel-sq3-5.jpg", "alt": "Airwheel SQ3 兒童電動騎行行李箱", "sortOrder": 4}, {"url": "/products/savewo/airwheel-sq3-6.jpg", "alt": "Airwheel SQ3 兒童電動騎行行李箱", "sortOrder": 5}]', 1580.0, NULL, 'active', 92) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('d818885a-1df9-4274-8f91-b0f6d12edfa7', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'd66b8015-ab1e-4515-9b64-fa994d4452a8', 'Airwheel SE3SL 20吋可登機智能騎行電動行李箱', 'airwheel-se3sl', '675a42b2d30d3b000c802c10', 'AirWheel SE3SL 新一代電動行李喼，三大革新，全面進化，旅行最佳拍擋！體積革新體積精簡至登機行李喼的極限大小，從此無畏「行刑架」。重量革新重量由9.4kg大幅減輕至6.8kg，更加輕巧便儶，完全符合手提行李登機標準。續航革新全新電池容量由73.6kWh 大幅增加至92.5kWh，行程提高25%。配備專屬APP，實時監控行李箱狀態，包括電量和鎖定系統，還可進行遠程控制，使每次旅行都充滿科技感。內置USB充電端口，隨時為您的移動設備充電，無需擔心電力不足。堅固的外殼和智能制動系統，確保您的行李和個人物品既安全又完好無損。提供多種時尚顏色，包括粉色、銀色、灰色和黑色，讓您的旅行風格與眾不', '/products/savewo/airwheel-se3sl.jpg', '[{"url": "/products/savewo/airwheel-se3sl.jpg", "alt": "Airwheel SE3SL 20吋可登機智能騎行電動行李箱", "sortOrder": 0}, {"url": "/products/savewo/airwheel-se3sl-2.jpg", "alt": "Airwheel SE3SL 20吋可登機智能騎行電動行李箱", "sortOrder": 1}, {"url": "/products/savewo/airwheel-se3sl-3.jpg", "alt": "Airwheel SE3SL 20吋可登機智能騎行電動行李箱", "sortOrder": 2}, {"url": "/products/savewo/airwheel-se3sl-4.jpg", "alt": "Airwheel SE3SL 20吋可登機智能騎行電動行李箱", "sortOrder": 3}, {"url": "/products/savewo/airwheel-se3sl-5.jpg", "alt": "Airwheel SE3SL 20吋可登機智能騎行電動行李箱", "sortOrder": 4}, {"url": "/products/savewo/airwheel-se3sl-6.jpg", "alt": "Airwheel SE3SL 20吋可登機智能騎行電動行李箱", "sortOrder": 5}, {"url": "/products/savewo/airwheel-se3sl-7.jpg", "alt": "Airwheel SE3SL 20吋可登機智能騎行電動行李箱", "sortOrder": 6}, {"url": "/products/savewo/airwheel-se3sl-8.jpg", "alt": "Airwheel SE3SL 20吋可登機智能騎行電動行李箱", "sortOrder": 7}]', 4380.0, NULL, 'active', 93) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('72bd9568-cf37-4166-8a38-5acb1b324018', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '00462c1c-b0f1-475d-b69c-5e40ad30ded5', '*ADT 成人版* SAVEWO 3DMEOW 救世立體喵成人版防護口罩 聖誕別注版「聖誕小狼」(30片獨立包裝/盒) (90% 以上成人適用)', '3dmeowxmadt', '6747d3748d57da000ce904c6', '小狼聖誕鉅製！3DMEOW 節日換裝，Jungle Meow 聖誕喵降臨，同小朋友一齊過聖誕啦！3DMEOW 聖誕別注版全年最開心嘅聖誕節即將來臨，戴上3DMEOW聖誕別注版嚟歡度佳節啦！佢以聖誕紅主題配色，配上青綠色耳帶，戴上後立即化身聖誕喵，等小朋友以萌爆造型，同小狼一齊過聖誕啦！提提大家，3DMEOW 聖誕別注版係節日限定推出貨品，真係手快有、手慢冇架🎄🎄！特點:細菌過濾效率 BFE≥99.9%顆粒過濾效率 PFE≥99.9%病毒過濾效率 VFE≥99.9%創新  過濾技術，超強過濾極致透氣，能持久保持過濾效能，過濾效率有效24小時以上超低呼吸阻力 Breathing Resistanc', '/products/savewo/3dmeowxmadt.jpg', '[{"url": "/products/savewo/3dmeowxmadt.jpg", "alt": "*ADT 成人版* SAVEWO 3DMEOW 救世立體喵成人版防護口罩 聖誕別注版「聖誕小狼」(30片獨立包裝/盒) (90% 以上成人適用)", "sortOrder": 0}, {"url": "/products/savewo/3dmeowxmadt-2.jpg", "alt": "*ADT 成人版* SAVEWO 3DMEOW 救世立體喵成人版防護口罩 聖誕別注版「聖誕小狼」(30片獨立包裝/盒) (90% 以上成人適用)", "sortOrder": 1}, {"url": "/products/savewo/3dmeowxmadt-3.jpg", "alt": "*ADT 成人版* SAVEWO 3DMEOW 救世立體喵成人版防護口罩 聖誕別注版「聖誕小狼」(30片獨立包裝/盒) (90% 以上成人適用)", "sortOrder": 2}, {"url": "/products/savewo/3dmeowxmadt-4.jpg", "alt": "*ADT 成人版* SAVEWO 3DMEOW 救世立體喵成人版防護口罩 聖誕別注版「聖誕小狼」(30片獨立包裝/盒) (90% 以上成人適用)", "sortOrder": 3}]', 149.0, NULL, 'active', 94) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('2a9a34e0-9629-4e7f-96a0-48f98384750d', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '88c73897-04a5-4e07-a52d-51c99650ed3f', 'SAVEWO Aromist充電式霧化香薰機（送天然精油10mL乙支 - 請同時購買）', 'savewo-aromist-essential-oil-diffuser', '67444bad19409c000f0cc940', 'SAVEWO Aromist 無水霧化香薰機，採用美觀實用的設計，讓您在高效擴香的同時，享受純正的香氣體驗。這款香薰機不僅免去傳統加水的麻煩，還能長效運行，且超靜音設計，讓您的每一次使用更加愉悅與舒適。設有午夜黑及晨光白，無論是居家放鬆、辦公室專注，還是作為送禮佳品，Aromist 都是提升生活質感的不二之選。🔗 產品網站https://savewo.com/energy/aromist/at-od01/產品特點：創新時尚時尚造型，精緻金屬霧化噴頭，無線設計，美觀耐用且易清潔。無水霧化無需加水，方便快捷，同時避免黴菌及細菌滋生。高效擴香高效擴香技術，覆蓋範圍更廣，保持香味純正不稀釋。持久電量能', '/products/savewo/savewo-aromist-essential-oil-diffuser.jpg', '[{"url": "/products/savewo/savewo-aromist-essential-oil-diffuser.jpg", "alt": "SAVEWO Aromist充電式霧化香薰機（送天然精油10mL乙支 - 請同時購買）", "sortOrder": 0}, {"url": "/products/savewo/savewo-aromist-essential-oil-diffuser-2.jpg", "alt": "SAVEWO Aromist充電式霧化香薰機（送天然精油10mL乙支 - 請同時購買）", "sortOrder": 1}, {"url": "/products/savewo/savewo-aromist-essential-oil-diffuser-3.jpg", "alt": "SAVEWO Aromist充電式霧化香薰機（送天然精油10mL乙支 - 請同時購買）", "sortOrder": 2}]', 498.0, NULL, 'active', 95) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('10913c0a-de9b-4d85-a4b4-092f3b5bcf88', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '69787a97-49de-477e-9431-87d166480be0', 'SAVEWO 救世 eHeat 暖手寶移動電源 HW501', 'eheat-hw501', '67444861e5c8a200104e0dfb', '在這個冬季，SAVEWO eHeat 暖手寶 HW501 是能帶來溫暖的必備小夥伴。提供三段式恆溫設計，可持續發熱達14小時，配備正反雙面加熱技術和鋁鎂合金外殼，確保迅速且舒適的加熱。內置5000mAh電池可兼作移動電源，重量僅133g，方便攜帶，使每個寒冷的日子都變得溫暖而美好。隨時調節：擁有三段式恆溫設計，可選擇35˚C、40˚C或50˚C，讓你根據個人喜好和外界環境，調整最舒適的溫度。持續溫暖：提供最大14小時的持續發熱*，時刻保持你的雙手溫暖舒適。均勻發熱：採用正反雙面加熱技術，確保快速均勻發熱，讓你的手掌和指尖迅速感受到溫度的擁抱。時尚耐用：鋁鎂合金外殼配合親膚塗層，不僅使外觀更加時', '/products/savewo/eheat-hw501.jpg', '[{"url": "/products/savewo/eheat-hw501.jpg", "alt": "SAVEWO 救世 eHeat 暖手寶移動電源 HW501", "sortOrder": 0}, {"url": "/products/savewo/eheat-hw501-2.jpg", "alt": "SAVEWO 救世 eHeat 暖手寶移動電源 HW501", "sortOrder": 1}, {"url": "/products/savewo/eheat-hw501-3.jpg", "alt": "SAVEWO 救世 eHeat 暖手寶移動電源 HW501", "sortOrder": 2}, {"url": "/products/savewo/eheat-hw501-4.jpg", "alt": "SAVEWO 救世 eHeat 暖手寶移動電源 HW501", "sortOrder": 3}, {"url": "/products/savewo/eheat-hw501-5.jpg", "alt": "SAVEWO 救世 eHeat 暖手寶移動電源 HW501", "sortOrder": 4}]', 138.0, NULL, 'active', 96) ON CONFLICT DO NOTHING;
