INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('e3b23def-b1af-4cfe-83a4-9c51f4711fec', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '7ed7ec4c-f825-40e7-99d9-486092d7834c', 'SAVEWO HEALTHCHAIR 碳纖維專用手機架 - Magsafe磁吸版 (ZC1及XC1專用)', 'savewo-healthchair-magsafe-phonestand', '673dada2f5e1ee000ca76f12', '輕巧耐用，可按用家需要靈活轉向，以及調整俯仰角度。使用磁吸設計，安裝和拆卸都非常方便。能輕鬆地將相容的iPhone或其他裝置固定在HealthChair上，能夠隨時查看通知、導航或進行通話，方面用家出行。*ZC1及XC1專用', '/products/savewo/savewo-healthchair-magsafe-phonestand.jpg', '[{"url": "/products/savewo/savewo-healthchair-magsafe-phonestand.jpg", "alt": "SAVEWO HEALTHCHAIR 碳纖維專用手機架 - Magsafe磁吸版 (ZC1及XC1專用)", "sortOrder": 0}]', 480.0, NULL, 'active', 98) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('09c848a0-7116-424d-81ab-63d2efe2fb61', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '88c73897-04a5-4e07-a52d-51c99650ed3f', 'SAVEWO X EVANGELION MagCell MC509 5000mAh Wireless PowerBank 彩繪玻璃系列', 'magcell-mc509-eva7to12', '673ae071cd5815000ca6370c', 'SAVEWO X EVANGELION MagCell  升級登場！更強大的性能，更美觀耐用的印刷技術，集觀賞及實用的完美演繹！今次加推六款全新彩繪玻璃風格設計，外殼印有EVANGELION經典角色以及機甲，色彩鮮明，質感精細。並採用救世研發的第二代金屬UV固化數碼印刷技術，確保圖案清晰，並令印刷更持久耐用。同時完美融合救世自家開發的MagCell MC509，最細小的5000mAh磁吸無線充電行動電源，具備強大的功能！厚度只有8mm及僅重108g，設有20W PD USB-C輸出，以及最高15W的無線快充功能。 採用純鈷高密度電芯，以USB-C有線充電足夠為任何iPhone完全充電。更可作為', '/products/savewo/magcell-mc509-eva7to12.jpg', '[{"url": "/products/savewo/magcell-mc509-eva7to12.jpg", "alt": "SAVEWO X EVANGELION MagCell MC509 5000mAh Wireless PowerBank 彩繪玻璃系列", "sortOrder": 0}, {"url": "/products/savewo/magcell-mc509-eva7to12-2.jpg", "alt": "SAVEWO X EVANGELION MagCell MC509 5000mAh Wireless PowerBank 彩繪玻璃系列", "sortOrder": 1}, {"url": "/products/savewo/magcell-mc509-eva7to12-3.jpg", "alt": "SAVEWO X EVANGELION MagCell MC509 5000mAh Wireless PowerBank 彩繪玻璃系列", "sortOrder": 2}, {"url": "/products/savewo/magcell-mc509-eva7to12-4.jpg", "alt": "SAVEWO X EVANGELION MagCell MC509 5000mAh Wireless PowerBank 彩繪玻璃系列", "sortOrder": 3}, {"url": "/products/savewo/magcell-mc509-eva7to12-5.jpg", "alt": "SAVEWO X EVANGELION MagCell MC509 5000mAh Wireless PowerBank 彩繪玻璃系列", "sortOrder": 4}, {"url": "/products/savewo/magcell-mc509-eva7to12-6.jpg", "alt": "SAVEWO X EVANGELION MagCell MC509 5000mAh Wireless PowerBank 彩繪玻璃系列", "sortOrder": 5}, {"url": "/products/savewo/magcell-mc509-eva7to12-7.jpg", "alt": "SAVEWO X EVANGELION MagCell MC509 5000mAh Wireless PowerBank 彩繪玻璃系列", "sortOrder": 6}]', 318.0, NULL, 'active', 99) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('201b4393-920c-4489-a095-aec9db2cbe25', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '00462c1c-b0f1-475d-b69c-5e40ad30ded5', '*ADT 成人版* SAVEWO 3DMEOW 救世立體喵成人版防護口罩「吸血鬼小狼」(30片獨立包裝/盒) (90% 以上成人適用)', 'meow-adt-vampire', '6703aa8eac9bb56d93639fa6', '【萬眾期待！吸血鬼小狼決定再回來人間作惡！🖤】自從上年吸血鬼小狼同大家渡過咗一個好鬼好玩嘅Halloween🎃👻之後，就銷聲匿跡……傳聞佢去咗德古拉伯爵古堡遊歷🏰，學習做一隻更好的吸血鬼🧛‍♂️，古堡巍然矗立喺200尺嘅高崖之上，小狼天生有輕功底子，完全難佢唔到9秒9就上去，但係㩒門鐘後先知吸血鬼德古拉伯爵原來不在家🙈雖然小狼深深被古堡嘅神秘氣氛所吸引，但係都知道人間有好多朋友仔掛住佢🥺，小狼大人好開心，決定再回來人間！💌為大家帶來型爆嘅黑色立體喵口罩，準備好再進入黑色世界吧！🖤😈救世立體喵口罩 「吸血小狼版」KDT-頑童版萬眾期待，率先登場，立即預訂！SAVEWO 3DMEOW VAMPIR', '/products/savewo/meow-adt-vampire.jpg', '[{"url": "/products/savewo/meow-adt-vampire.jpg", "alt": "*ADT 成人版* SAVEWO 3DMEOW 救世立體喵成人版防護口罩「吸血鬼小狼」(30片獨立包裝/盒) (90% 以上成人適用)", "sortOrder": 0}, {"url": "/products/savewo/meow-adt-vampire-2.jpg", "alt": "*ADT 成人版* SAVEWO 3DMEOW 救世立體喵成人版防護口罩「吸血鬼小狼」(30片獨立包裝/盒) (90% 以上成人適用)", "sortOrder": 1}, {"url": "/products/savewo/meow-adt-vampire-3.jpg", "alt": "*ADT 成人版* SAVEWO 3DMEOW 救世立體喵成人版防護口罩「吸血鬼小狼」(30片獨立包裝/盒) (90% 以上成人適用)", "sortOrder": 2}, {"url": "/products/savewo/meow-adt-vampire-4.jpg", "alt": "*ADT 成人版* SAVEWO 3DMEOW 救世立體喵成人版防護口罩「吸血鬼小狼」(30片獨立包裝/盒) (90% 以上成人適用)", "sortOrder": 3}]', 149.0, NULL, 'active', 100) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('40a72353-9941-4fb5-bd50-c28a467c983d', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'd66b8015-ab1e-4515-9b64-fa994d4452a8', '救世完美導尿管', 'savewo-condom-catheter', '66f2743d699926000ddf4fcd', '救世推出全部男人都會讚好嘅產品！救世完美導尿管登場！解決插JJ嘅恐懼、痛苦、麻煩！救世大力發展新質生產力，聯乘馬來西亞醫療創科公司Twin Catalyst共同研發，開發出全球首創完美導尿管，用創新醫療科技，幫助病人、醫護、照顧者告別痛苦。新產品已經申請緊專利！成日話︰「屙尿咁簡單」，但呢件日日都要做嘅事，對好多長期卧床或者尿失禁嘅男人其實係一件好痛苦嘅事，因為依家嘅尿液引流技術，就係喺尿道口插入長度逾40厘米嘅入侵性導尿管，經細小嘅尿道直到膀胱(大家不妨想像40cm有幾長)！插入過程既恐懼又痛苦，仲有機會引致發炎；最慘唔係痛一次，而係每一至兩個星期由醫護人員更換一次。所以插尿喉雖然係一件非常', '/products/savewo/savewo-condom-catheter.jpg', '[{"url": "/products/savewo/savewo-condom-catheter.jpg", "alt": "救世完美導尿管", "sortOrder": 0}, {"url": "/products/savewo/savewo-condom-catheter-2.jpg", "alt": "救世完美導尿管", "sortOrder": 1}, {"url": "/products/savewo/savewo-condom-catheter-3.jpg", "alt": "救世完美導尿管", "sortOrder": 2}, {"url": "/products/savewo/savewo-condom-catheter-4.jpg", "alt": "救世完美導尿管", "sortOrder": 3}]', 32.0, NULL, 'active', 101) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('60e0a210-becb-4550-99b7-0a3adb512230', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'd66b8015-ab1e-4515-9b64-fa994d4452a8', 'SAVEWO 救世 TGP-X1C 智能空氣消毒淨化機（陳列品）', 'tgp-x1c-demo', '66f11b6718606f000d390fd0', 'Savewo-TGP-X1C  智能空氣消毒淨化機A.I. Sanitizing Air Purifier HEPA H13 + Gas &amp; ODOR Filter 濾網組合定價$480/套（跟機已有一套）包裝：可洗滌初濾網 * 1 (建議700小時清洗或更換）活性碳空氣淨化濾網* 1 (建議2000小時更換)HEPA H13高效濾網* 1 (建議2000小時更換)視乎使用的環境情況，濾網的最佳使用時間或有所改變。空氣質素理想的環境下使用可以增加最佳使用時間；相反，在空氣質素惡劣的環境下使用會減少最佳使用時間。*濾網壽命視乎實際環境的污染情況而有所增減。初效濾網是可清洗的，勤加清洗可保', '/products/savewo/tgp-x1c-demo.jpg', '[{"url": "/products/savewo/tgp-x1c-demo.jpg", "alt": "SAVEWO 救世 TGP-X1C 智能空氣消毒淨化機（陳列品）", "sortOrder": 0}, {"url": "/products/savewo/tgp-x1c-demo-2.jpg", "alt": "SAVEWO 救世 TGP-X1C 智能空氣消毒淨化機（陳列品）", "sortOrder": 1}, {"url": "/products/savewo/tgp-x1c-demo-3.jpg", "alt": "SAVEWO 救世 TGP-X1C 智能空氣消毒淨化機（陳列品）", "sortOrder": 2}, {"url": "/products/savewo/tgp-x1c-demo-4.jpg", "alt": "SAVEWO 救世 TGP-X1C 智能空氣消毒淨化機（陳列品）", "sortOrder": 3}, {"url": "/products/savewo/tgp-x1c-demo-5.jpg", "alt": "SAVEWO 救世 TGP-X1C 智能空氣消毒淨化機（陳列品）", "sortOrder": 4}, {"url": "/products/savewo/tgp-x1c-demo-6.jpg", "alt": "SAVEWO 救世 TGP-X1C 智能空氣消毒淨化機（陳列品）", "sortOrder": 5}, {"url": "/products/savewo/tgp-x1c-demo-7.jpg", "alt": "SAVEWO 救世 TGP-X1C 智能空氣消毒淨化機（陳列品）", "sortOrder": 6}, {"url": "/products/savewo/tgp-x1c-demo-8.jpg", "alt": "SAVEWO 救世 TGP-X1C 智能空氣消毒淨化機（陳列品）", "sortOrder": 7}, {"url": "/products/savewo/tgp-x1c-demo-9.jpg", "alt": "SAVEWO 救世 TGP-X1C 智能空氣消毒淨化機（陳列品）", "sortOrder": 8}, {"url": "/products/savewo/tgp-x1c-demo-10.jpg", "alt": "SAVEWO 救世 TGP-X1C 智能空氣消毒淨化機（陳列品）", "sortOrder": 9}, {"url": "/products/savewo/tgp-x1c-demo-11.jpg", "alt": "SAVEWO 救世 TGP-X1C 智能空氣消毒淨化機（陳列品）", "sortOrder": 10}, {"url": "/products/savewo/tgp-x1c-demo-12.jpg", "alt": "SAVEWO 救世 TGP-X1C 智能空氣消毒淨化機（陳列品）", "sortOrder": 11}]', 1280.0, NULL, 'active', 102) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('88a612b3-95f9-491c-bc52-a277e853cb27', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '88c73897-04a5-4e07-a52d-51c99650ed3f', 'SAVEWO CarPlug Nano 智能車載充電器', 'carplug-nano', '66e3ef6997ed53001fa6a32a', 'SAVEWO CarPlug Nano是全球最小PD 45W車載充電器。不僅外形精巧，而且功能強大，在追求極致車內美學和功能性的今天不可或缺。CarPlug Nano的體積小於9.4cm³，重量輕至 20g，小型設計使它在插入車載插座時幾乎不留任何突出部分，完美融合於您的車內環境，完全不影響車輛內部造型。CarPlug Nano 配備了兩個 USB-C 輸出端口，可支援兩台設備同時充電，單輸出時最大充電速度高達 45W 的 PD 3.0 快速充電。無論是為智能手機、平板還是筆記型電腦，CarPlug Nano 都能迅速回復設備電力，保證您的設備在最短時間內回到滿電狀態。此外，CarPlug N', '/products/savewo/carplug-nano.jpg', '[{"url": "/products/savewo/carplug-nano.jpg", "alt": "SAVEWO CarPlug Nano 智能車載充電器", "sortOrder": 0}, {"url": "/products/savewo/carplug-nano-2.jpg", "alt": "SAVEWO CarPlug Nano 智能車載充電器", "sortOrder": 1}, {"url": "/products/savewo/carplug-nano-3.jpg", "alt": "SAVEWO CarPlug Nano 智能車載充電器", "sortOrder": 2}, {"url": "/products/savewo/carplug-nano-4.jpg", "alt": "SAVEWO CarPlug Nano 智能車載充電器", "sortOrder": 3}, {"url": "/products/savewo/carplug-nano-5.jpg", "alt": "SAVEWO CarPlug Nano 智能車載充電器", "sortOrder": 4}]', 168.0, NULL, 'active', 103) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('06116edc-a7b6-4869-8b86-101adc325c5c', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'd66b8015-ab1e-4515-9b64-fa994d4452a8', 'Savewo ProCloth 超極細纖維擦拭布', 'procloth', '66e3c016d76929001c58de5d', '針對手機、鏡頭、相機、手錶及首飾等，貴重及精密儀器設計的專業擦拭布，集合除污、防刮、拋光功能於一身，能迅速安全地令物品亮麗如新。採用超柔軟的極細纖維製造，表面採用特殊的細絨結構，能輕鬆去除物品表污垢、油脂及指紋等殘留物，且不傷及表面。清潔後的屏幕及鏡片，能感受全新時的高清晰度。清潔後的手錶及首飾，重新綻放亮麗的光澤。產品特徵：○ 輕鬆去除油污：特殊的纖維結構，具有良好的吸收力，有效清除油膜和污垢。○ 對皮膚溫和：即使不使用清潔劑，也能有出色的擦拭效果，不會對環境造成污染。○ 清潔後無殘留：擦拭後非常乾淨，幾乎沒有水滴或纖維殘留。○ 不易划傷：採用軟質纖維結構，不易划傷被清潔物品。○ 反復清洗不', '/products/savewo/procloth.jpg', '[{"url": "/products/savewo/procloth.jpg", "alt": "Savewo ProCloth 超極細纖維擦拭布", "sortOrder": 0}, {"url": "/products/savewo/procloth-2.jpg", "alt": "Savewo ProCloth 超極細纖維擦拭布", "sortOrder": 1}, {"url": "/products/savewo/procloth-3.jpg", "alt": "Savewo ProCloth 超極細纖維擦拭布", "sortOrder": 2}]', 29.0, NULL, 'active', 104) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('680efd1f-f9dd-4b7f-885e-e15a4de67488', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '88c73897-04a5-4e07-a52d-51c99650ed3f', 'Savewo MagMount PRO MM-W15Q2 Qi2磁吸充電支架', 'magmount-pro', '66e3a00b699e200022d22cc1', '大受好評的MagMount 的磁吸充電專業版本登場！外型時尚的設計，輕鬆融入任何環境，作為強力磁吸手機支架，同時快速為手機充電，即使在繁忙的交通中也可以一吸馬上充電，全程無需分心，既安全又方便！ 還能安裝顯示器旁邊，一邊充電一邊操作，幾方便又實用！MagMount PRO 獲得 Qi2 認證，編號 QI-22200，無論是 iPhone 或是 Android，都可以享受到高達 15W 的快速且安全的無線充電！🔗 產品網站https://savewo.com/energy/magmount/mm-w15q2/【產品重點】已獲Qi2認証，無論iPhone/Android 均能提供真正15W 高速無', '/products/savewo/magmount-pro.jpg', '[{"url": "/products/savewo/magmount-pro.jpg", "alt": "Savewo MagMount PRO MM-W15Q2 Qi2磁吸充電支架", "sortOrder": 0}, {"url": "/products/savewo/magmount-pro-2.jpg", "alt": "Savewo MagMount PRO MM-W15Q2 Qi2磁吸充電支架", "sortOrder": 1}, {"url": "/products/savewo/magmount-pro-3.jpg", "alt": "Savewo MagMount PRO MM-W15Q2 Qi2磁吸充電支架", "sortOrder": 2}, {"url": "/products/savewo/magmount-pro-4.jpg", "alt": "Savewo MagMount PRO MM-W15Q2 Qi2磁吸充電支架", "sortOrder": 3}, {"url": "/products/savewo/magmount-pro-5.jpg", "alt": "Savewo MagMount PRO MM-W15Q2 Qi2磁吸充電支架", "sortOrder": 4}, {"url": "/products/savewo/magmount-pro-6.jpg", "alt": "Savewo MagMount PRO MM-W15Q2 Qi2磁吸充電支架", "sortOrder": 5}, {"url": "/products/savewo/magmount-pro-7.jpg", "alt": "Savewo MagMount PRO MM-W15Q2 Qi2磁吸充電支架", "sortOrder": 6}]', 268.0, NULL, 'active', 105) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('0f55dd39-cda8-494d-8dfc-e5b14b3228f3', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '3a0021f1-4a3a-45d6-928f-711d9cebfb99', '*R 標準碼* SAVEWO ROYAL MASK 救世 2D 對摺型口罩 深綠「KF94 + KN95 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)', 'royal-r-darkgreen', '66d8111f30a555000d584820', '集救世科研與時尚極致於一身，極修臉對摺型口罩 Royal Mask，能高度適合95%人士臉形，簡約而細緻V形設計讓你配戴極為方便亦易於收納。秉承救世專利過濾技術 TYPECOOL+，Royal Mask 保留「高透氣」「強過濾」「防敏感」特質，除有效防禦99.9%飛沫、花粉、懸浮物質、細菌及病毒，更配合獨有剪裁讓其緊貼面部完美防止漏氣，符合人體工學的立體設計，內部空間比一般口罩多出30％，呼吸更暢順，配戴更舒適無阻！Royal 級剪裁專利V形設計以極致的人體工學研發而成，質料防敏剪裁獨特，舒適地貼服在臉上猶如無物。配戴後更顯臉型利落自然，流暢線條讓你流露出最自然輕盈一面，無論便裝或晚裝，Roy', '/products/savewo/royal-r-darkgreen.jpg', '[{"url": "/products/savewo/royal-r-darkgreen.jpg", "alt": "*R 標準碼* SAVEWO ROYAL MASK 救世 2D 對摺型口罩 深綠「KF94 + KN95 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)", "sortOrder": 0}, {"url": "/products/savewo/royal-r-darkgreen-2.jpg", "alt": "*R 標準碼* SAVEWO ROYAL MASK 救世 2D 對摺型口罩 深綠「KF94 + KN95 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)", "sortOrder": 1}, {"url": "/products/savewo/royal-r-darkgreen-3.jpg", "alt": "*R 標準碼* SAVEWO ROYAL MASK 救世 2D 對摺型口罩 深綠「KF94 + KN95 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)", "sortOrder": 2}, {"url": "/products/savewo/royal-r-darkgreen-4.jpg", "alt": "*R 標準碼* SAVEWO ROYAL MASK 救世 2D 對摺型口罩 深綠「KF94 + KN95 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)", "sortOrder": 3}, {"url": "/products/savewo/royal-r-darkgreen-5.jpg", "alt": "*R 標準碼* SAVEWO ROYAL MASK 救世 2D 對摺型口罩 深綠「KF94 + KN95 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)", "sortOrder": 4}]', 149.0, NULL, 'active', 106) ON CONFLICT DO NOTHING;
