INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('a2540b63-b2d6-46a6-8e16-178ea4629186', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '0e7588df-a28c-4b75-80be-f1b9352e282e', 'SAVEWO AirFlow Jet Fan 超高速多功能便攜噴射風扇', 'savewo-airflow-jetfan', '66d13b2e6da72f000d6e9a81', '🌀 最強掌心噴射風扇！SAVEWO AirFlow Jet Fan超高速多功能便攜噴射風扇壓軸登場！細小輕巧配備50W高功率！爆發真10萬轉！🌀SAVEWO AirFlow Jet Fan 細小輕巧，卻可以暴發超強風力！性能稱皇！設有三種模式，由強力噴射、風扇至高效抽風，迎合你喺唔同場合嘅需要，一機多用，邊個話風扇只係得送風咁簡單？🔥 噴射模式Jet Fan採用100,000rpm高速渦輪電機，金屬扇葉一體化設計，實現高達50m/s有效風速噴射模式非常適合露營的時候快速點燃營火，或者為BBQ燒烤透爐。還可以快速吹起派對氣球，或者清理屋企嘅灰塵，或者吹乾物件表面殘留水分，令清潔工作更加有效率。🌬', '/products/savewo/savewo-airflow-jetfan.jpg', '[{"url": "/products/savewo/savewo-airflow-jetfan.jpg", "alt": "SAVEWO AirFlow Jet Fan 超高速多功能便攜噴射風扇", "sortOrder": 0}, {"url": "/products/savewo/savewo-airflow-jetfan-2.jpg", "alt": "SAVEWO AirFlow Jet Fan 超高速多功能便攜噴射風扇", "sortOrder": 1}, {"url": "/products/savewo/savewo-airflow-jetfan-3.jpg", "alt": "SAVEWO AirFlow Jet Fan 超高速多功能便攜噴射風扇", "sortOrder": 2}, {"url": "/products/savewo/savewo-airflow-jetfan-4.jpg", "alt": "SAVEWO AirFlow Jet Fan 超高速多功能便攜噴射風扇", "sortOrder": 3}, {"url": "/products/savewo/savewo-airflow-jetfan-5.jpg", "alt": "SAVEWO AirFlow Jet Fan 超高速多功能便攜噴射風扇", "sortOrder": 4}, {"url": "/products/savewo/savewo-airflow-jetfan-6.jpg", "alt": "SAVEWO AirFlow Jet Fan 超高速多功能便攜噴射風扇", "sortOrder": 5}]', 269.0, NULL, 'active', 111) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('7fddf98e-92d1-457c-9ea0-0273ac9e3864', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'd66b8015-ab1e-4515-9b64-fa994d4452a8', 'SAVEWO MagMount MM-01 汽車伸縮旋轉可摺叠支架', 'magmount-mm-01', '66d02f22b42be20010c6f3aa', '🌐 每個角度，只為您的完美視野SAVEWO MagMount MM-01，一款專為現代生活設計的多用途磁吸支架，不僅堅固可靠，更提供無與倫比的調整自由度。無論是車內、辦公桌或家中任何平面，MM-01都能完美融入您的空間，提供最佳的觀看體驗。🔩 創新磁吸技術，安全穩固採用MagSafe磁吸技術，讓您的手機瞬間固定，即使是顛簸的駕駛路途也不擔心。配合堅固的合金制支架和3M VHB強力雙面膠，安全無憂。🔄 360度旋轉，自由調節MM-01的波頭設計與多關節可調支架，實現360度旋轉及多角度調整，輕鬆達到您所需的每一個視角，無論是導航、觀看影片或進行視訊通話。📱 一支架，兼容所有手機隨附的SAVEWO', '/products/savewo/magmount-mm-01.jpg', '[{"url": "/products/savewo/magmount-mm-01.jpg", "alt": "SAVEWO MagMount MM-01 汽車伸縮旋轉可摺叠支架", "sortOrder": 0}, {"url": "/products/savewo/magmount-mm-01-2.jpg", "alt": "SAVEWO MagMount MM-01 汽車伸縮旋轉可摺叠支架", "sortOrder": 1}, {"url": "/products/savewo/magmount-mm-01-3.jpg", "alt": "SAVEWO MagMount MM-01 汽車伸縮旋轉可摺叠支架", "sortOrder": 2}, {"url": "/products/savewo/magmount-mm-01-4.jpg", "alt": "SAVEWO MagMount MM-01 汽車伸縮旋轉可摺叠支架", "sortOrder": 3}]', 69.0, NULL, 'active', 112) ON CONFLICT DO NOTHING;
