INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('ded57a16-a560-4e31-a5ba-137282996a91', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '00462c1c-b0f1-475d-b69c-5e40ad30ded5', '*ADT 成人版* SAVEWO 3DMEOW Pardus 救世立體喵成人版防護口罩 小豹版 (30片獨立包裝/盒) (90% 以上成人適用)', 'savewo-3dmeow-adt-pardus', '6698d55c39930c57f0f1415c', '概覽:SAVEWO 3DMEOW for Kids救世立體喵兒童防護口罩！萌爆升級！童心抗疫！綻放笑容！立體喵！超透氣！強過濾！採用救世最新TypeCool＋過濾技術，前所未有的透氣感受，配合 ESPP 不織布親膚物料及舒適型耳帶，質感柔軟舒適。把最好的都給予小朋友，讓他們戴著口罩也能綻放笑容！SAVEWO 3DMEOW for Kids 救世立體喵是即棄式兒童防護口罩，採用專利萌爆立體剪裁，有效增加呼吸空間，長時間穿戴也十分舒適，能適配2-6歲小童臉型，升級版本採用最新TypeCool+ 過濾技術，超低呼吸阻力 Breathing Resistance&lt; 2.8mmH2O，特別適合小朋', '/products/savewo/savewo-3dmeow-adt-pardus.jpg', '[{"url": "/products/savewo/savewo-3dmeow-adt-pardus.jpg", "alt": "*ADT 成人版* SAVEWO 3DMEOW Pardus 救世立體喵成人版防護口罩 小豹版 (30片獨立包裝/盒) (90% 以上成人適用)", "sortOrder": 0}, {"url": "/products/savewo/savewo-3dmeow-adt-pardus-2.jpg", "alt": "*ADT 成人版* SAVEWO 3DMEOW Pardus 救世立體喵成人版防護口罩 小豹版 (30片獨立包裝/盒) (90% 以上成人適用)", "sortOrder": 1}, {"url": "/products/savewo/savewo-3dmeow-adt-pardus-3.jpg", "alt": "*ADT 成人版* SAVEWO 3DMEOW Pardus 救世立體喵成人版防護口罩 小豹版 (30片獨立包裝/盒) (90% 以上成人適用)", "sortOrder": 2}, {"url": "/products/savewo/savewo-3dmeow-adt-pardus-4.jpg", "alt": "*ADT 成人版* SAVEWO 3DMEOW Pardus 救世立體喵成人版防護口罩 小豹版 (30片獨立包裝/盒) (90% 以上成人適用)", "sortOrder": 3}]', 119.0, NULL, 'active', 117) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('65962cef-f58c-438a-8373-64a1849ea8ee', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '88c73897-04a5-4e07-a52d-51c99650ed3f', '*2米* SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線', 'powercable-magnetic-2m', '668fbe60892d78001001ad44', 'SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線市場上最高充電速度的磁吸自卷收納電線，支援最新PD3.1，功率傳輸高達 240W，比一般USB-C 線快 8 倍，並且相容於多種快速充電協定，可為手機、平板電腦、部分筆記型電腦如MacBook Pro等進行充電。同時亦具有USB2.0 480Mbps數據傳輸功能。自動磁力吸附自卷，快速輕鬆整理充電線，告別雜亂感覺，重拾整齊的桌面和車廂。能夠輕鬆磁吸在磁性金屬表面，或者配合SAVEWO MagRing 磁吸在任何物件或牆壁上。採用高強度PC + ABS 材料製造的機甲風插頭，以及超柔軟的磁吸', '/products/savewo/powercable-magnetic-2m.jpg', '[{"url": "/products/savewo/powercable-magnetic-2m.jpg", "alt": "*2米* SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線", "sortOrder": 0}, {"url": "/products/savewo/powercable-magnetic-2m-2.jpg", "alt": "*2米* SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線", "sortOrder": 1}, {"url": "/products/savewo/powercable-magnetic-2m-3.jpg", "alt": "*2米* SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線", "sortOrder": 2}, {"url": "/products/savewo/powercable-magnetic-2m-4.jpg", "alt": "*2米* SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線", "sortOrder": 3}, {"url": "/products/savewo/powercable-magnetic-2m-5.jpg", "alt": "*2米* SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線", "sortOrder": 4}, {"url": "/products/savewo/powercable-magnetic-2m-6.jpg", "alt": "*2米* SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線", "sortOrder": 5}, {"url": "/products/savewo/powercable-magnetic-2m-7.jpg", "alt": "*2米* SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線", "sortOrder": 6}, {"url": "/products/savewo/powercable-magnetic-2m-8.jpg", "alt": "*2米* SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線", "sortOrder": 7}, {"url": "/products/savewo/powercable-magnetic-2m-9.jpg", "alt": "*2米* SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線", "sortOrder": 8}]', 99.0, NULL, 'active', 118) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('32c2f8a3-5407-4319-aa17-25963e914d2c', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '0e7588df-a28c-4b75-80be-f1b9352e282e', 'SAVEWO AirFlow Cool Fan 便攜式冰感風扇', 'airflow-coolfan', '668faf31f6d1ca0016f8825a', 'SAVEWO AirFlow Cool Fan 便攜式冰感風扇最強電量🔋！強勁風力🍃！𣊬間冰爽🧊！作為一款便攜式冰感風扇，SAVEWO AirFlow Cool Fan集合咗強大製冷效果❄、長續航力以及安全可靠等特點，係夏日消暑嘅理想選擇。無論喺屋企、辦公室定係外出，都可以為你帶嚟舒適凉爽嘅體驗。🔗 產品網站https://savewo.com/energy/airflow/coolfan/【產品重點】🌬極速冰感製冷，瞬間降溫12°c採用半導體製冷技術，可以喺極短時間內降低出風口溫度高達12°c。🌬5000mAh同級最大電量，長達20小時續航力搭載5000mAh超大容量電池，是同級產品中最大電', '/products/savewo/airflow-coolfan.jpg', '[{"url": "/products/savewo/airflow-coolfan.jpg", "alt": "SAVEWO AirFlow Cool Fan 便攜式冰感風扇", "sortOrder": 0}, {"url": "/products/savewo/airflow-coolfan-2.jpg", "alt": "SAVEWO AirFlow Cool Fan 便攜式冰感風扇", "sortOrder": 1}, {"url": "/products/savewo/airflow-coolfan-3.jpg", "alt": "SAVEWO AirFlow Cool Fan 便攜式冰感風扇", "sortOrder": 2}, {"url": "/products/savewo/airflow-coolfan-4.jpg", "alt": "SAVEWO AirFlow Cool Fan 便攜式冰感風扇", "sortOrder": 3}, {"url": "/products/savewo/airflow-coolfan-5.jpg", "alt": "SAVEWO AirFlow Cool Fan 便攜式冰感風扇", "sortOrder": 4}, {"url": "/products/savewo/airflow-coolfan-6.jpg", "alt": "SAVEWO AirFlow Cool Fan 便攜式冰感風扇", "sortOrder": 5}]', 198.0, NULL, 'active', 119) ON CONFLICT DO NOTHING;
