INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('efd48a94-b9c3-43c9-9dfb-cf30aa478fb7', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '88c73897-04a5-4e07-a52d-51c99650ed3f', 'SAVEWO FlipDock Qi2 三合一磁吸摺疊旋轉無線充電座 FD-W31Q2', 'filpdock', '6686063551e92e96fa15da00', 'SAVEWO FlipDock Qi2 三合一磁吸摺疊旋轉無線充電座 FD-W31Q2不僅提供極致的充電便利性，更是多裝置使用者的首選。它的三合一設計可同時為三個裝置充電，無需逐一排隊等待，無論您需要同時給智能手機、平板、手表或是耳機充電，這款充電座都能滿足您的需求。這讓它成為家庭多裝置用戶、科技愛好者以及商務人士的理想選擇。已獲Qi2認証，無論iPhone/Android 均能提供真正15W 高速無線充電。https://wirelesspowerconsortium.atlassian.net/servicedesk/customer/portal/12/article/377651207', '/products/savewo/filpdock.jpg', '[{"url": "/products/savewo/filpdock.jpg", "alt": "SAVEWO FlipDock Qi2 三合一磁吸摺疊旋轉無線充電座 FD-W31Q2", "sortOrder": 0}, {"url": "/products/savewo/filpdock-2.jpg", "alt": "SAVEWO FlipDock Qi2 三合一磁吸摺疊旋轉無線充電座 FD-W31Q2", "sortOrder": 1}, {"url": "/products/savewo/filpdock-3.jpg", "alt": "SAVEWO FlipDock Qi2 三合一磁吸摺疊旋轉無線充電座 FD-W31Q2", "sortOrder": 2}, {"url": "/products/savewo/filpdock-4.jpg", "alt": "SAVEWO FlipDock Qi2 三合一磁吸摺疊旋轉無線充電座 FD-W31Q2", "sortOrder": 3}, {"url": "/products/savewo/filpdock-5.jpg", "alt": "SAVEWO FlipDock Qi2 三合一磁吸摺疊旋轉無線充電座 FD-W31Q2", "sortOrder": 4}, {"url": "/products/savewo/filpdock-6.jpg", "alt": "SAVEWO FlipDock Qi2 三合一磁吸摺疊旋轉無線充電座 FD-W31Q2", "sortOrder": 5}, {"url": "/products/savewo/filpdock-7.jpg", "alt": "SAVEWO FlipDock Qi2 三合一磁吸摺疊旋轉無線充電座 FD-W31Q2", "sortOrder": 6}]', 238.0, NULL, 'active', 122) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('4276d84f-9b81-4de7-aa19-27030b411262', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '88c73897-04a5-4e07-a52d-51c99650ed3f', '*1米* SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線', 'powercable-magnetic-1m', '667be590a4aff9001f32e073', 'SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線市場上最高充電速度的磁吸自卷收納電線，支援最新PD3.1，功率傳輸高達 240W，比一般USB-C 線快 8 倍，並且相容於多種快速充電協定，可為手機、平板電腦、部分筆記型電腦如MacBook Pro等進行充電。同時亦具有USB2.0 480Mbps數據傳輸功能。自動磁力吸附自卷，快速輕鬆整理充電線，告別雜亂感覺，重拾整齊的桌面和車廂。能夠輕鬆磁吸在磁性金屬表面，或者配合SAVEWO MagRing 磁吸在任何物件或牆壁上。採用高強度PC + ABS 材料製造的機甲風插頭，以及超柔軟的磁吸', '/products/savewo/powercable-magnetic-1m.jpg', '[{"url": "/products/savewo/powercable-magnetic-1m.jpg", "alt": "*1米* SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線", "sortOrder": 0}, {"url": "/products/savewo/powercable-magnetic-1m-2.jpg", "alt": "*1米* SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線", "sortOrder": 1}, {"url": "/products/savewo/powercable-magnetic-1m-3.jpg", "alt": "*1米* SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線", "sortOrder": 2}, {"url": "/products/savewo/powercable-magnetic-1m-4.jpg", "alt": "*1米* SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線", "sortOrder": 3}, {"url": "/products/savewo/powercable-magnetic-1m-5.jpg", "alt": "*1米* SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線", "sortOrder": 4}, {"url": "/products/savewo/powercable-magnetic-1m-6.jpg", "alt": "*1米* SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線", "sortOrder": 5}, {"url": "/products/savewo/powercable-magnetic-1m-7.jpg", "alt": "*1米* SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線", "sortOrder": 6}, {"url": "/products/savewo/powercable-magnetic-1m-8.jpg", "alt": "*1米* SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線", "sortOrder": 7}, {"url": "/products/savewo/powercable-magnetic-1m-9.jpg", "alt": "*1米* SAVEWO PowerCable USB-C Magnetic 磁吸自卷240W PD3.1 極速充電線", "sortOrder": 8}]', 69.0, NULL, 'active', 123) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('94368e78-d72d-4152-9f34-1ce31c08e2ec', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '00462c1c-b0f1-475d-b69c-5e40ad30ded5', '*KS 兒童細碼* SAVEWO 3DMEOW Wisteria 救世立體喵兒童防護口罩 紫藤 (30片獨立包裝/盒) (2-6歲適用)', 'savewo-3dmeow-ks-wisteria', '6674ff8d79479500165abec6', 'SAVEWO 3DMEOW for Kids救世立體喵兒童防護口罩！萌爆升級！童心抗疫！綻放笑容！立體喵！超透氣！強過濾！採用救世最新TypeCool＋過濾技術，前所未有的透氣感受，配合 ESPP 不織布親膚物料及舒適型耳帶，質感柔軟舒適。把最好的都給予小朋友，讓他們戴著口罩也能綻放笑容！SAVEWO 3DMEOW for Kids 救世立體喵是即棄式兒童防護口罩，採用專利萌爆立體剪裁，有效增加呼吸空間，長時間穿戴也十分舒適，設有2款尺碼，適配2-6歲小童及7-13歲中童的臉型。升級版本採用最新TypeCool+ 過濾技術，超低呼吸阻力 Breathing Resistance&lt; 2.8', '/products/savewo/savewo-3dmeow-ks-wisteria.jpg', '[{"url": "/products/savewo/savewo-3dmeow-ks-wisteria.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW Wisteria 救世立體喵兒童防護口罩 紫藤 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 0}, {"url": "/products/savewo/savewo-3dmeow-ks-wisteria-2.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW Wisteria 救世立體喵兒童防護口罩 紫藤 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 1}, {"url": "/products/savewo/savewo-3dmeow-ks-wisteria-3.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW Wisteria 救世立體喵兒童防護口罩 紫藤 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 2}, {"url": "/products/savewo/savewo-3dmeow-ks-wisteria-4.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW Wisteria 救世立體喵兒童防護口罩 紫藤 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 3}]', 149.0, NULL, 'active', 124) ON CONFLICT DO NOTHING;
