INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('57aa2ab9-a076-4642-9125-794547d71fc9', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '88c73897-04a5-4e07-a52d-51c99650ed3f', 'SAVEWO MagCell MC509 超薄磁吸式無線行動電源', 'magcell-mc509', '66544c29e1831b001c940680', 'SAVEWO MagCell MC509係目前全球最細小最輕薄嘅5000mAh磁吸式行動電源🧲⚡，體積只有54cm³，重量僅為108g，超薄設計，厚度只有8mm，擁有極致輕巧便攜嘅特性，磁吸一貼就自動無綫充電，手感極佳！講個秘密㊙️比大家知，救世為咗確保MagCell MC509嘅質量，其實電池內部仲特登留低咗0.2mm空間，俾電芯有足夠嘅空間做熱脹冷縮，進一步延長電池嘅壽命。為咗達到極致咁超薄，同時保持世界最細小，仲要確保耐用性同提供最佳嘅品質，真係一啲都唔容易。救世選用咗能源密度更高嘅鈷電極鋰聚合物電芯🔋，相比同體積嘅鋰電池可以儲存更多能量，咁先至可以做到最好嘅MagCell！🔗 產品網站', '/products/savewo/magcell-mc509.jpg', '[{"url": "/products/savewo/magcell-mc509.jpg", "alt": "SAVEWO MagCell MC509 超薄磁吸式無線行動電源", "sortOrder": 0}, {"url": "/products/savewo/magcell-mc509-2.jpg", "alt": "SAVEWO MagCell MC509 超薄磁吸式無線行動電源", "sortOrder": 1}, {"url": "/products/savewo/magcell-mc509-3.jpg", "alt": "SAVEWO MagCell MC509 超薄磁吸式無線行動電源", "sortOrder": 2}, {"url": "/products/savewo/magcell-mc509-4.jpg", "alt": "SAVEWO MagCell MC509 超薄磁吸式無線行動電源", "sortOrder": 3}, {"url": "/products/savewo/magcell-mc509-5.jpg", "alt": "SAVEWO MagCell MC509 超薄磁吸式無線行動電源", "sortOrder": 4}, {"url": "/products/savewo/magcell-mc509-6.jpg", "alt": "SAVEWO MagCell MC509 超薄磁吸式無線行動電源", "sortOrder": 5}, {"url": "/products/savewo/magcell-mc509-7.jpg", "alt": "SAVEWO MagCell MC509 超薄磁吸式無線行動電源", "sortOrder": 6}, {"url": "/products/savewo/magcell-mc509-8.jpg", "alt": "SAVEWO MagCell MC509 超薄磁吸式無線行動電源", "sortOrder": 7}]', 198.0, NULL, 'active', 132) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('39da3fc0-ee5c-4290-9ab0-ba8883590840', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'd66b8015-ab1e-4515-9b64-fa994d4452a8', 'SAVEWO Oxygen 便攜式手提氧氣機', 'savewo-oxygen-so1000', '664aed3a94326d0011e1eff0', 'SAVEWO Oxygen 便攜式手提氧氣機隨身攜帶，自由呼吸 — SAVEWO Oxygen 便攜式手提氧氣機專為活躍生活設計：不論是戶外冒險、長途旅行還是日常出行，SAVEWO Oxygen讓您在任何時候、任何地點都能享受純凈氧氣。體積輕巧（僅1.98kg），輕鬆適應各種活動需求，實現真正的移動自由。高效供氧技術：每分鐘最高可供5公升等效流量的空氣，確保您在需要時獲得充足氧氣。配備五種流量設定，滿足不同情景下的需求，無論是休閒步行還是高強度訓練。長效電池與快速充電：內置的99Wh高容量電池，最長運作時間達5小時，讓您遠離電源的束縛。支持USB-C PD3.0 100W快速充電，短時間內即可', '/products/savewo/savewo-oxygen-so1000.jpg', '[{"url": "/products/savewo/savewo-oxygen-so1000.jpg", "alt": "SAVEWO Oxygen 便攜式手提氧氣機", "sortOrder": 0}, {"url": "/products/savewo/savewo-oxygen-so1000-2.jpg", "alt": "SAVEWO Oxygen 便攜式手提氧氣機", "sortOrder": 1}, {"url": "/products/savewo/savewo-oxygen-so1000-3.jpg", "alt": "SAVEWO Oxygen 便攜式手提氧氣機", "sortOrder": 2}, {"url": "/products/savewo/savewo-oxygen-so1000-4.jpg", "alt": "SAVEWO Oxygen 便攜式手提氧氣機", "sortOrder": 3}, {"url": "/products/savewo/savewo-oxygen-so1000-5.jpg", "alt": "SAVEWO Oxygen 便攜式手提氧氣機", "sortOrder": 4}, {"url": "/products/savewo/savewo-oxygen-so1000-6.jpg", "alt": "SAVEWO Oxygen 便攜式手提氧氣機", "sortOrder": 5}]', 13800.0, NULL, 'active', 133) ON CONFLICT DO NOTHING;
