INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('8650f350-edb0-46db-9da2-ca46e4a60cd6', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '0e7588df-a28c-4b75-80be-f1b9352e282e', 'SAVEWO AirFlow Neckfan 品味套裝（每盒5包，30片/套，每款味道各10片）', 'savewo-airflow-aromatherapy-tablets-set', '662f541b68783800141f7f4c', '無拘無束 溫柔送爽SAVEWO AirFlow 掛頸風扇重量只有180g，長期佩戴亦不感倦意；最長可4.5小時送出立體環形柔風，配合三段風速調節、小蒼蘭、佛手柑、山茶花三種不同香薰片，不論天氣，都可為您送爽添香。第二段︰*風量不同 一樣溫柔三段風速調節，清爽微風可送走鬱悶，加強風力後則可帶來瞬間清涼，切合不同季節、環境需要。立體環形柔風，避免因為強風拂面而造成頭痛、頭暈等不適。第三段︰*香薰擴香 感受自然可添加三款不同花果香味的香薰片，以散發香氣、提振精神，使您漫步城市、仍可呼吸自然。第四段︰*自由自在 親膚舒適 解放雙手，工作、運動、烹飪時不再大汗淋漓。以親膚材質所製，減少黏膩感。鬆緊可調，', '/products/savewo/savewo-airflow-aromatherapy-tablets-set.jpg', '[{"url": "/products/savewo/savewo-airflow-aromatherapy-tablets-set.jpg", "alt": "SAVEWO AirFlow Neckfan 品味套裝（每盒5包，30片/套，每款味道各10片）", "sortOrder": 0}, {"url": "/products/savewo/savewo-airflow-aromatherapy-tablets-set-2.jpg", "alt": "SAVEWO AirFlow Neckfan 品味套裝（每盒5包，30片/套，每款味道各10片）", "sortOrder": 1}, {"url": "/products/savewo/savewo-airflow-aromatherapy-tablets-set-3.jpg", "alt": "SAVEWO AirFlow Neckfan 品味套裝（每盒5包，30片/套，每款味道各10片）", "sortOrder": 2}, {"url": "/products/savewo/savewo-airflow-aromatherapy-tablets-set-4.jpg", "alt": "SAVEWO AirFlow Neckfan 品味套裝（每盒5包，30片/套，每款味道各10片）", "sortOrder": 3}, {"url": "/products/savewo/savewo-airflow-aromatherapy-tablets-set-5.jpg", "alt": "SAVEWO AirFlow Neckfan 品味套裝（每盒5包，30片/套，每款味道各10片）", "sortOrder": 4}, {"url": "/products/savewo/savewo-airflow-aromatherapy-tablets-set-6.jpg", "alt": "SAVEWO AirFlow Neckfan 品味套裝（每盒5包，30片/套，每款味道各10片）", "sortOrder": 5}, {"url": "/products/savewo/savewo-airflow-aromatherapy-tablets-set-7.jpg", "alt": "SAVEWO AirFlow Neckfan 品味套裝（每盒5包，30片/套，每款味道各10片）", "sortOrder": 6}, {"url": "/products/savewo/savewo-airflow-aromatherapy-tablets-set-8.jpg", "alt": "SAVEWO AirFlow Neckfan 品味套裝（每盒5包，30片/套，每款味道各10片）", "sortOrder": 7}]', 179.0, NULL, 'active', 138) ON CONFLICT DO