INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('2383b2ab-71eb-4ddb-9c3c-570065050ae5', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '7ed7ec4c-f825-40e7-99d9-486092d7834c', '半價超級優惠 5折！*優惠價$12800，原價$25800* SAVEWO HEALTHCHAIR X CARBON - XC1 超輕量碳纖維電動輪椅', 'healthchair-zcarbonxc1', '6616342f304cec001414db01', '半價超級優惠 5折！$12,800 原價 $25,800 試車預約：95482544HealthChair X CARBON XC1碳纖對摺 極致輕量 便利出行「總重量僅為14kg」原價$25800 預訂優惠價$12800 🔗 產品網站https://healthchair.com/xc1/特點：*極致輕量 - 全車採用碳纖維車架，總重量僅為14kg，不足傳統電動輪椅一半的重量，安全負重達100kg，同級最輕。*3秒摺疊 - 簡單步驟，3秒摺疊，摺疊後體積細小，並可站立及推行，便於攜帶和存放。*持久續航力 - 採用高容量電池時，一次充電提供高達20km續航力，充沛的電力滿足日常出行。*大輸出無', '/products/savewo/healthchair-zcarbonxc1.jpg', '[{"url": "/products/savewo/healthchair-zcarbonxc1.jpg", "alt": "半價超級優惠 5折！*優惠價$12800，原價$25800* SAVEWO HEALTHCHAIR X CARBON - XC1 超輕量碳纖維電動輪椅", "sortOrder": 0}, {"url": "/products/savewo/healthchair-zcarbonxc1-2.jpg", "alt": "半價超級優惠 5折！*優惠價$12800，原價$25800* SAVEWO HEALTHCHAIR X CARBON - XC1 超輕量碳纖維電動輪椅", "sortOrder": 1}, {"url": "/products/savewo/healthchair-zcarbonxc1-3.jpg", "alt": "半價超級優惠 5折！*優惠價$12800，原價$25800* SAVEWO HEALTHCHAIR X CARBON - XC1 超輕量碳纖維電動輪椅", "sortOrder": 2}, {"url": "/products/savewo/healthchair-zcarbonxc1-4.jpg", "alt": "半價超級優惠 5折！*優惠價$12800，原價$25800* SAVEWO HEALTHCHAIR X CARBON - XC1 超輕量碳纖維電動輪椅", "sortOrder": 3}, {"url": "/products/savewo/healthchair-zcarbonxc1-5.jpg", "alt": "半價超級優惠 5折！*優惠價$12800，原價$25800* SAVEWO HEALTHCHAIR X CARBON - XC1 超輕量碳纖維電動輪椅", "sortOrder": 4}, {"url": "/products/savewo/healthchair-zcarbonxc1-6.jpg", "alt": "半價超級優惠 5折！*優惠價$12800，原價$25800* SAVEWO HEALTHCHAIR X CARBON - XC1 超輕量碳纖維電動輪椅", "sortOrder": 5}, {"url": "/products/savewo/healthchair-zcarbonxc1-7.jpg", "alt": "半價超級優惠 5折！*優惠價$12800，原價$25800* SAVEWO HEALTHCHAIR X CARBON - XC1 超輕量碳纖維電動輪椅", "sortOrder": 6}, {"url": "/products/savewo/healthchair-zcarbonxc1-8.jpg", "alt": "半價超級優惠 5折！*優惠價$12800，原價$25800* SAVEWO HEALTHCHAIR X CARBON - XC1 超