INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('55447470-b95a-4af5-b4e8-fa583ed14721', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '00462c1c-b0f1-475d-b69c-5e40ad30ded5', '*KS 兒童細碼* SAVEWO 3DMEOW Jewel Topaz 救世立體喵兒童防護口罩 寶石系列 托帕石 (30片獨立包裝/盒) (2-6歲適用)', 'savewo-3dmeow-ks-jltz', '66139f71a8b7fd0017957428', 'SAVEWO 3DMEOW for Kids救世立體喵兒童防護口罩！萌爆升級！童心抗疫！綻放笑容！立體喵！超透氣！強過濾！採用救世最新TypeCool＋過濾技術，前所未有的透氣感受，配合 ESPP 不織布親膚物料及舒適型耳帶，質感柔軟舒適。把最好的都給予小朋友，讓他們戴著口罩也能綻放笑容！SAVEWO 3DMEOW for Kids 救世立體喵是即棄式兒童防護口罩，採用專利萌爆立體剪裁，有效增加呼吸空間，長時間穿戴也十分舒適，設有2款尺碼，適配2-6歲小童及7-13歲中童的臉型。升級版本採用最新TypeCool+ 過濾技術，超低呼吸阻力 Breathing Resistance&lt; 2.8', '/products/savewo/savewo-3dmeow-ks-jltz.jpg', '[{"url": "/products/savewo/savewo-3dmeow-ks-jltz.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW Jewel Topaz 救世立體喵兒童防護口罩 寶石系列 托帕石 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 0}, {"url": "/products/savewo/savewo-3dmeow-ks-jltz-2.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW Jewel Topaz 救世立體喵兒童防護口罩 寶石系列 托帕石 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 1}, {"url": "/products/savewo/savewo-3dmeow-ks-jltz-3.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW Jewel Topaz 救世立體喵兒童防護口罩 寶石系列 托帕石 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 2}, {"url": "/products/savewo/savewo-3dmeow-ks-jltz-4.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW Jewel Topaz 救世立體喵兒童防護口罩 寶石系列 托帕石 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 3}, {"url": "/products/savewo/savewo-3dmeow-ks-jltz-5.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW Jewel Topaz 救世立體喵兒童防護口罩 寶石系列 托帕石 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 4}, {"url": "/products/savewo/savewo-3dmeow-ks-jltz-6.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW Jewel Topaz 救世立體喵兒童防護口罩 寶石系列 托帕石 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 5}, {"url": "/products/savewo/savewo-3dmeow-ks-jltz-7.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW Jewel Topaz 救世立體喵兒童防護口罩 寶石系列 托帕石 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 6}, {"url": "/products/savewo/savewo-3dmeow-ks-jltz-8.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW Jewel Topaz 救世立體喵兒童防護口罩 寶石系列 托帕石 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 7}]', 149.0, NULL, 'active', 142) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('10ce8280-a6e2-4bef-9caa-15f430287321', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '3a0021f1-4a3a-45d6-928f-711d9cebfb99', '*R 標準碼* SAVEWO ROYAL MASK 梳打系列 救世 2D 對摺型口罩 蝶豆花「KF94 + KN95 + ASTM LEVEL3 認證 」(2色耳帶各15件，30片/盒，獨立包裝)', 'royal-r-butterflypea', '6605282d019468001a31bee4', '集救世科研與時尚極致於一身，極修臉對摺型口罩 Royal Mask，能高度適合95%人士臉形，簡約而細緻V形設計讓你配戴極為方便亦易於收納。秉承救世專利過濾技術 TYPECOOL+，Royal Mask 保留「高透氣」「強過濾」「防敏感」特質，除有效防禦99.9%飛沫、花粉、懸浮物質、細菌及病毒，更配合獨有剪裁讓其緊貼面部完美防止漏氣，符合人體工學的立體設計，內部空間比一般口罩多出30％，呼吸更暢順，配戴更舒適無阻！Royal 級剪裁專利V形設計以極致的人體工學研發而成，質料防敏剪裁獨特，舒適地貼服在臉上猶如無物。配戴後更顯臉型利落自然，流暢線條讓你流露出最自然輕盈一面，無論便裝或晚裝，Roy', '/products/savewo/royal-r-butterflypea.jpg', '[{"url": "/products/savewo/royal-r-butterflypea.jpg", "alt": "*R 標準碼* SAVEWO ROYAL MASK 梳打系列 救世 2D 對摺型口罩 蝶豆花「KF94 + KN95 + ASTM LEVEL3 認證 」(2色耳帶各15件，30片/盒，獨立包裝)", "sortOrder": 0}, {"url": "/products/savewo/royal-r-butterflypea-2.jpg", "alt": "*R 標準碼* SAVEWO ROYAL MASK 梳打系列 救世 2D 對摺型口罩 蝶豆花「KF94 + KN95 + ASTM LEVEL3 認證 」(2色耳帶各15件，30片/盒，獨立包裝)", "sortOrder": 1}, {"url": "/products/savewo/royal-r-butterflypea-3.jpg", "alt": "*R 標準碼* SAVEWO ROYAL MASK 梳打系列 救世 2D 對摺型口罩 蝶豆花「KF94 + KN95 + ASTM LEVEL3 認證 」(2色耳帶各15件，30片/盒，獨立包裝)", "sortOrder": 2}, {"url": "/products/savewo/royal-r-butterflypea-4.jpg", "alt": "*R 標準碼* SAVEWO ROYAL MASK 梳打系列 救世 2D 對摺型口罩 蝶豆花「KF94 + KN95 + ASTM LEVEL3 認證 」(2色耳帶各15件，30片/盒，獨立包裝)", "sortOrder": 3}, {"url": "/products/savewo/royal-r-butterflypea-5.jpg", "alt": "*R 標準碼* SAVEWO ROYAL MASK 梳打系列 救世 2D 對摺型口罩 蝶豆花「KF94 + KN95 + ASTM LEVEL3 認證 」(2色耳帶各15件，30片/盒，獨立包裝)", "sortOrder": 4}, {"url": "/products/savewo/royal-r-butterflypea-6.jpg", "alt": "*R 標準碼* SAVEWO ROYAL MASK 梳打系列 救世 2D 對摺型口罩 蝶豆花「KF94 + KN95 + ASTM LEVEL3 認證 」(2色耳帶各15件，30片/盒，獨立包裝)", "sortOrder": 5}]', 149.0, NULL, 'active', 143) ON CONFLICT DO NOTHING;
