INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('341b0b90-f74d-4482-a45f-ae36c55d81eb', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '7187e8af-25ad-4cbf-aa41-a6b51e1adcd7', '*一片裝* SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE', 'smile-1', '65dc57f7300b474e8edca071', '全球首個無障礙FFP2認證呼吸器全新研發的SAVEWO VisionFilm 超高清防霧視窗專利技術，在口罩中間嘴部位置形成廣角透明視窗，能多角度展示用家的嘴部。VisionFilm 膠片以超音波技術焊接於口罩的中央，防水防漏氣，確保氣密安全。VisionFilm具有高清防霧氣功能，無論用家說話甚至做運動，也𣎴會出現任何霧化。SAVEWO 3DMASK Smile 的口罩設計採用3DMASK Extreme Pro的V-Shape 專利設計改良而成，加上FleXnet 專利支撐物料，提供超立體堅挺的剪裁，更貼合人的面型。上方設有方便摺疊的專利設計，能夠讓用戶輕鬆調校口罩視窗的傾仰角度，即使不同', '/products/savewo/smile-1.jpg', '[{"url": "/products/savewo/smile-1.jpg", "alt": "*一片裝* SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE", "sortOrder": 0}, {"url": "/products/savewo/smile-1-2.jpg", "alt": "*一片裝* SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE", "sortOrder": 1}, {"url": "/products/savewo/smile-1-3.jpg", "alt": "*一片裝* SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE", "sortOrder": 2}, {"url": "/products/savewo/smile-1-4.jpg", "alt": "*一片裝* SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE", "sortOrder": 3}, {"url": "/products/savewo/smile-1-5.jpg", "alt": "*一片裝* SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE", "sortOrder": 4}, {"url": "/products/savewo/smile-1-6.jpg", "alt": "*一片裝* SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE", "sortOrder": 5}, {"url": "/products/savewo/smile-1-7.jpg", "alt": "*一片裝* SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE", "sortOrder": 6}, {"url": "/products/savewo/smile-1-8.jpg", "alt": "*一片裝* SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE", "sortOrder": 7}, {"url": "/products/savewo/smile-1-9.jpg", "alt": "*一片裝* SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE", "sortOrder": 8}]', 6.0, NULL, 'active', 147) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('83f1c6c8-ecec-40d7-a9eb-367e2b319669', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '00462c1c-b0f1-475d-b69c-5e40ad30ded5', '*KDT 小顏人士* SAVEWO 3DMEOW CADET BLUE 救世立體喵頑童防護口罩 深藍色 (30片獨立包裝/盒) (大童, 小顏人士適用)', 'kidultsdarkblue', '65c479dad5635c001a793fe7', '概覽童真不是小朋友的專利，救世精心開發出 SAVEWO 3DMEOW For Kidults 立體喵頑童版防護口罩！現正推出深綠色常規版本 !救世立體喵頑童版防護口罩採用中童及小顏成人設計，同時也適合各位童心未泯嘅大細路！除了白喵、粉紅喵、粉藍喵之外，仲有隻跑得慢半拍既黑貓趕黎登場！3DMEOW更通過韓國MFDS 認證為KF94等級，尺碼增至4款，無論大人同小朋友都能夠安心配戴，變成超可愛貓喵萌爆示人！爸爸媽媽賺錢買喵戴～3DMEOW For Kidults配合3DMEOW For Kids，同囝囝囡囡一齊萌爆全場！童心抗疫！綻放笑容！🔗 產品網站https://www.savewo.com/', '/products/savewo/kidultsdarkblue.jpg', '[{"url": "/products/savewo/kidultsdarkblue.jpg", "alt": "*KDT 小顏人士* SAVEWO 3DMEOW CADET BLUE 救世立體喵頑童防護口罩 深藍色 (30片獨立包裝/盒) (大童, 小顏人士適用)", "sortOrder": 0}, {"url": "/products/savewo/kidultsdarkblue-2.jpg", "alt": "*KDT 小顏人士* SAVEWO 3DMEOW CADET BLUE 救世立體喵頑童防護口罩 深藍色 (30片獨立包裝/盒) (大童, 小顏人士適用)", "sortOrder": 1}, {"url": "/products/savewo/kidultsdarkblue-3.jpg", "alt": "*KDT 小顏人士* SAVEWO 3DMEOW CADET BLUE 救世立體喵頑童防護口罩 深藍色 (30片獨立包裝/盒) (大童, 小顏人士適用)", "sortOrder": 2}]', 149.0, NULL, 'sold_out', 148) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('1a9712c0-af04-4495-ad20-985a83ab16b3', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '00462c1c-b0f1-475d-b69c-5e40ad30ded5', '*KL 兒童大碼* SAVEWO 3DMEOW CADET BLUE 救世立體喵兒童防護口罩 深藍色 (30片獨立包裝/盒) (7-13歲適用)', '3dmeowl2darkblue', '65c47899558846000e7f9bf1', '概覽:SAVEWO 3DMEOW for Kids救世立體喵兒童防護口罩！萌爆升級！童心抗疫！綻放笑容！SAVEWO 3DMEOW for Kids 救世立體喵兒童防護口罩，採用專利萌爆立體剪裁，有效增加呼吸空間，長時間穿戴也十分舒適。採用 TYPECOOL+ 救世最新過濾技術，前所未有的透氣感受配合 ESPP 不織布親膚物料及舒適型耳帶，質感柔軟舒適。把最好的都給予小朋友，讓他們戴著口罩也能綻放笑容！空氣阻力Breathing Resistance&lt; 2.8的超高透氣度，特別適合小朋友使用。防止液淺阻擋達160mmHg，更有效過濾99.9%細菌、微塵及病毒。每片均採用獨立個體包裝，方便', '/products/savewo/3dmeowl2darkblue.jpg', '[{"url": "/products/savewo/3dmeowl2darkblue.jpg", "alt": "*KL 兒童大碼* SAVEWO 3DMEOW CADET BLUE 救世立體喵兒童防護口罩 深藍色 (30片獨立包裝/盒) (7-13歲適用)", "sortOrder": 0}, {"url": "/products/savewo/3dmeowl2darkblue-2.jpg", "alt": "*KL 兒童大碼* SAVEWO 3DMEOW CADET BLUE 救世立體喵兒童防護口罩 深藍色 (30片獨立包裝/盒) (7-13歲適用)", "sortOrder": 1}, {"url": "/products/savewo/3dmeowl2darkblue-3.jpg", "alt": "*KL 兒童大碼* SAVEWO 3DMEOW CADET BLUE 救世立體喵兒童防護口罩 深藍色 (30片獨立包裝/盒) (7-13歲適用)", "sortOrder": 2}]', 149.0, NULL, 'active', 149) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('920693bb-5467-49af-81a1-5ba4153f2b89', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '00462c1c-b0f1-475d-b69c-5e40ad30ded5', '*KS 兒童細碼* SAVEWO 3DMEOW CADET BLUE 救世立體喵兒童防護口罩 深藍色(30片獨立包裝/盒) (2-6歲適用)', '3dmeows2darkblue', '65c476d2d2eeb30011f27593', 'SAVEWO 3DMEOW for Kids救世立體喵兒童防護口罩！萌爆升級！童心抗疫！綻放笑容！立體喵！超透氣！強過濾！採用救世最新TypeCool＋過濾技術，前所未有的透氣感受，配合 ESPP 不織布親膚物料及舒適型耳帶，質感柔軟舒適。把最好的都給予小朋友，讓他們戴著口罩也能綻放笑容！SAVEWO 3DMEOW for Kids 救世立體喵是即棄式兒童防護口罩，採用專利萌爆立體剪裁，有效增加呼吸空間，長時間穿戴也十分舒適，設有2款尺碼，適配2-6歲小童及7-13歲中童的臉型。升級版本採用最新TypeCool+ 過濾技術，超低呼吸阻力 Breathing Resistance&lt; 2.8', '/products/savewo/3dmeows2darkblue.jpg', '[{"url": "/products/savewo/3dmeows2darkblue.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW CADET BLUE 救世立體喵兒童防護口罩 深藍色(30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 0}, {"url": "/products/savewo/3dmeows2darkblue-2.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW CADET BLUE 救世立體喵兒童防護口罩 深藍色(30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 1}, {"url": "/products/savewo/3dmeows2darkblue-3.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW CADET BLUE 救世立體喵兒童防護口罩 深藍色(30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 2}]', 149.0, NULL, 'active', 150) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('7395dda4-ecdc-406f-a819-20af7fb476a1', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'ee5d2925-5774-4a23-92ce-01a1b071f520', '*2米卷裝* SAVEWO 救世 TranSkin 防水透明薄膜 (闊10cm)', 'wondaleaf-flatdressing-2m', '65c19879583c54001a5068dc', 'SAVEWO 救世 TranSkin 防水透明薄膜，薄到只得0.02mm，防水耐用、透氣舒適！超薄親膚的材質，貼上後就不覺得存在。無論是洗手或是沐浴，長時間防水功能能有效預防傷口因沾水而發炎，加速傷口癒合，提供極佳防護！🔗 產品網站https://www.savewo.com/healthcare/zh-hk/products/transkin/dressing/ts-rd10香港製造0.02mm超薄設計使傷口完美隱形，面上傷痕不再顯眼日常洗手、洗澡不會影響傷口可根據傷口大小剪裁，不易捲邊鬆脫，即使用於腳踝、手指等關節位置也不容易鬆脫清潔後的割傷、擦傷、燙傷等，可配合藥膏加速傷口癒合應用場景廣', '/products/savewo/wondaleaf-flatdressing-2m.jpg', '[{"url": "/products/savewo/wondaleaf-flatdressing-2m.jpg", "alt": "*2米卷裝* SAVEWO 救世 TranSkin 防水透明薄膜 (闊10cm)", "sortOrder": 0}, {"url": "/products/savewo/wondaleaf-flatdressing-2m-2.jpg", "alt": "*2米卷裝* SAVEWO 救世 TranSkin 防水透明薄膜 (闊10cm)", "sortOrder": 1}, {"url": "/products/savewo/wondaleaf-flatdressing-2m-3.jpg", "alt": "*2米卷裝* SAVEWO 救世 TranSkin 防水透明薄膜 (闊10cm)", "sortOrder": 2}]', 180.0, NULL, 'active', 151) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('13163806-3319-4902-b1bf-1efa9a8222d8', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '00462c1c-b0f1-475d-b69c-5e40ad30ded5', '*ADT 成人版* SAVEWO 3DMEOW CADET BLUE 救世立體喵成人版防護口罩 深藍色 (30片獨立包裝/盒) (90% 以上成人適用)', 'meowadtcb', '65c05f5442fd3c0014cecc7a', '概覽【3D MEOW成人版正式登場，一家大細一齊萌爆升級！】立體喵口罩一直深受小朋友歡迎，高透氣、強過濾、最呵護肌膚抗過敏嘅強大效能令滲透率超出想象，行出街唔難發現總有一個戴住立體喵嘅小朋友在左近！收到唔少Daddy Mammy詢問幾時出成人碼，夾硬戴住Kidults都袋住先。由於剪裁需要重新設計及研發，要大家久等萬分歉意，今日小編好開心宣布：「3D MEOW成人版終於登場！」顏色分別有黑色、白色、灰色、綠色一共四色任君選擇。從此尺寸由兒童細碼Kids S、兒童大碼Kids L、頑童Kidults至成人Adults都一應俱全，仲全系列已通過韓國MFDS認證，正式成為真正KF94立體喵，以後無論', '/products/savewo/meowadtcb.jpg', '[{"url": "/products/savewo/meowadtcb.jpg", "alt": "*ADT 成人版* SAVEWO 3DMEOW CADET BLUE 救世立體喵成人版防護口罩 深藍色 (30片獨立包裝/盒) (90% 以上成人適用)", "sortOrder": 0}, {"url": "/products/savewo/meowadtcb-2.jpg", "alt": "*ADT 成人版* SAVEWO 3DMEOW CADET BLUE 救世立體喵成人版防護口罩 深藍色 (30片獨立包裝/盒) (90% 以上成人適用)", "sortOrder": 1}, {"url": "/products/savewo/meowadtcb-3.jpg", "alt": "*ADT 成人版* SAVEWO 3DMEOW CADET BLUE 救世立體喵成人版防護口罩 深藍色 (30片獨立包裝/盒) (90% 以上成人適用)", "sortOrder": 2}]', 149.0, NULL, 'active', 152) ON CONFLICT DO NOTHING;
