INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('67869520-f1d4-41a5-ab37-5e81b7e9ca46', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'd66b8015-ab1e-4515-9b64-fa994d4452a8', 'Savewo MagRing磁性環', 'magring', '65aa3f64c3701feed2946b57', '救世又有新花臣，新推出Savewo MagRing磁性環🧲⭕。一個超薄圈仔，可以有幾多玩法？最正路嘅玩法，就係貼喺手機/手機殼後邊，只需簡單一貼、無需其他步驟咁，就令手機秒變MagSafe 兼容*，從此無線充電、再無限制⚡！第二個玩法，就係令佢搖身一變成磁力支架，利用佢嘅磁性力量，穩固放置手機係特定位置，揸車嘅朋友仔可以用佢放喺車廂入邊🚗，睇地圖時夠晒方便🗺，仲要唔驚佢會跌！小狼諗到嘅第三種玩法，就係配合客製化/別注版MagCell。既然佢哋咁靚仔，唔放出嚟咪嘥？MagCell本身會利用磁性吸附係鐵製品上面，放喺雪櫃等金屬表面並無問題，但如果想掛起其他材質表面都冇有怕，因為MagRing背面採', '/products/savewo/magring.jpg', '[{"url": "/products/savewo/magring.jpg", "alt": "Savewo MagRing磁性環", "sortOrder": 0}, {"url": "/products/savewo/magring-2.jpg", "alt": "Savewo MagRing磁性環", "sortOrder": 1}, {"url": "/products/savewo/magring-3.jpg", "alt": "Savewo MagRing磁性環", "sortOrder": 2}, {"url": "/products/savewo/magring-4.jpg", "alt": "Savewo MagRing磁性環", "sortOrder": 3}, {"url": "/products/savewo/magring-5.jpg", "alt": "Savewo MagRing磁性環", "sortOrder": 4}]', 19.0, NULL, 'active', 160) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('70d32708-1c9f-4913-9374-bb0f67c2ff29', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '88c73897-04a5-4e07-a52d-51c99650ed3f', 'SAVEWO UniPlug UP140 PD3.1 [140W]  4 USB 全球旅行快充插頭', 'uniplug-up140', '65a10e938a25a900146470b0', '世上首款PD3.1 140W全球旅行快充插頭--Savewo UniPlug 140W🌍！這個劃時代的旅行插頭體積細小輕巧(體積只有92.7 x 55 x 53.7mm，重量不足270g)，但將會為日後旅行帶來大大轉變，令您可以體驗一場零負擔的「說走就走的旅行」🛄，而不是苦於攜帶沉重的變壓器(火牛🔥🐮)。🔗 產品網站https://savewo.com/energy/uniplug/up140/【Savewo UniPlug 140W 有何特點？】💪🏻強勁丨支援PD3.1 140W，可用於MacBook Pro 16”全速充電🪶輕巧丨體積只有92.7 x 55 x 53.7mm，重量僅為270', '/products/savewo/uniplug-up140.jpg', '[{"url": "/products/savewo/uniplug-up140.jpg", "alt": "SAVEWO UniPlug UP140 PD3.1 [140W]  4 USB 全球旅行快充插頭", "sortOrder": 0}, {"url": "/products/savewo/uniplug-up140-2.jpg", "alt": "SAVEWO UniPlug UP140 PD3.1 [140W]  4 USB 全球旅行快充插頭", "sortOrder": 1}, {"url": "/products/savewo/uniplug-up140-3.jpg", "alt": "SAVEWO UniPlug UP140 PD3.1 [140W]  4 USB 全球旅行快充插頭", "sortOrder": 2}, {"url": "/products/savewo/uniplug-up140-4.jpg", "alt": "SAVEWO UniPlug UP140 PD3.1 [140W]  4 USB 全球旅行快充插頭", "sortOrder": 3}]', 499.0, NULL, 'active', 161) ON CONFLICT DO NOTHING;
