INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('8a309e79-3de2-4d48-bfc8-2332b6997485', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '00462c1c-b0f1-475d-b69c-5e40ad30ded5', '*KDT 小顏人士* SAVEWO 3DMEOW 救世立體喵成人版防護口罩 聖誕別注版「聖誕小狼」(30片獨立包裝/盒) (大童, 小顏人士適用)', '3dmeowxmkdt', '6576c1ae6c58b5fa92f76388', '小狼聖誕鉅製！3DMEOW 節日換裝，Jungle Meow 聖誕喵降臨，同小朋友一齊過聖誕啦！3DMEOW 聖誕別注版全年最開心嘅聖誕節即將來臨，戴上3DMEOW聖誕別注版嚟歡度佳節啦！佢以聖誕紅主題配色，配上青綠色耳帶，戴上後立即化身聖誕喵，等小朋友以萌爆造型，同小狼一齊過聖誕啦！提提大家，3DMEOW 聖誕別注版係節日限定推出貨品，真係手快有、手慢冇架🎄🎄！3DMEOW 聖誕別注版(30片獨立包裝/盒)3DMEOW KIDULTS 小顏人士 (中童、大童及小顏人士)摺疊：100 x 128mm張開：150 x 128mm特點:細菌過濾效率 BFE≥99.9%顆粒過濾效率 PFE≥99.9', '/products/savewo/3dmeowxmkdt.jpg', '[{"url": "/products/savewo/3dmeowxmkdt.jpg", "alt": "*KDT 小顏人士* SAVEWO 3DMEOW 救世立體喵成人版防護口罩 聖誕別注版「聖誕小狼」(30片獨立包裝/盒) (大童, 小顏人士適用)", "sortOrder": 0}, {"url": "/products/savewo/3dmeowxmkdt-2.jpg", "alt": "*KDT 小顏人士* SAVEWO 3DMEOW 救世立體喵成人版防護口罩 聖誕別注版「聖誕小狼」(30片獨立包裝/盒) (大童, 小顏人士適用)", "sortOrder": 1}, {"url": "/products/savewo/3dmeowxmkdt-3.jpg", "alt": "*KDT 小顏人士* SAVEWO 3DMEOW 救世立體喵成人版防護口罩 聖誕別注版「聖誕小狼」(30片獨立包裝/盒) (大童, 小顏人士適用)", "sortOrder": 2}]', 149.0, NULL, 'active', 166) ON CONFLICT DO NOTHING;
