INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('913a7fe6-1f66-4c90-bb86-d33910fb57bc', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '3f73ad1e-bfa4-4f24-bccc-95a66f75e37a', 'SAVEWO 3DMASK ULTRA CARBON 救世超立體口罩 (三款尺寸可選) (30片獨立包裝/盒)', 'ultracarbon', '6560551652309c9e90484777', '四層防護、特設活性碳過濾零異味層的3D Mask Ultra Carbon開始發售！因應有需要人士的需求，救世一直未有停低研發腳步。新推出3D Mask Ultra Carbon，在原有3D Mask Ultra基礎之上，再特設活性碳過濾零異味層，可高效過濾揮發性有機化合物、二氧化物、甲苯、甲醛、氨等有害物質，同時可過濾口氣及異味，時刻令你感覺清新。此外，亦因為其四層構造，剪裁上更加立體，自然戴得更加舒適！【四層構造】．UltraSpunBond 超潑水面料配合UltraSeal 超音波接焊點技術，令超薄透氣的3DMASK Ultra 達到前所未有的立體堅挺，更高耐用度，無懼惡劣環境，以及更強', '/products/savewo/ultracarbon.jpg', '[{"url": "/products/savewo/ultracarbon.jpg", "alt": "SAVEWO 3DMASK ULTRA CARBON 救世超立體口罩 (三款尺寸可選) (30片獨立包裝/盒)", "sortOrder": 0}, {"url": "/products/savewo/ultracarbon-2.jpg", "alt": "SAVEWO 3DMASK ULTRA CARBON 救世超立體口罩 (三款尺寸可選) (30片獨立包裝/盒)", "sortOrder": 1}, {"url": "/products/savewo/ultracarbon-3.jpg", "alt": "SAVEWO 3DMASK ULTRA CARBON 救世超立體口罩 (三款尺寸可選) (30片獨立包裝/盒)", "sortOrder": 2}]', 189.0, NULL, 'active', 173) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('6ccd5523-339a-462e-b09a-7b74e363f984', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '00462c1c-b0f1-475d-b69c-5e40ad30ded5', '*KS 兒童細碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 秋冬限定配色 (30片獨立包裝/盒) (2-6歲適用)', '3dmeowkscbdg', '655c7806f74957001189b193', 'SAVEWO 3DMEOW for Kids救世立體喵兒童防護口罩！萌爆升級！童心抗疫！綻放笑容！立體喵！超透氣！強過濾！採用救世最新TypeCool＋過濾技術，前所未有的透氣感受，配合 ESPP 不織布親膚物料及舒適型耳帶，質感柔軟舒適。把最好的都給予小朋友，讓他們戴著口罩也能綻放笑容！SAVEWO 3DMEOW for Kids 救世立體喵是即棄式兒童防護口罩，採用專利萌爆立體剪裁，有效增加呼吸空間，長時間穿戴也十分舒適，設有2款尺碼，適配2-6歲小童及7-13歲中童的臉型。升級版本採用最新TypeCool+ 過濾技術，超低呼吸阻力 Breathing Resistance&lt; 2.8', '/products/savewo/3dmeowkscbdg.jpg', '[{"url": "/products/savewo/3dmeowkscbdg.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 秋冬限定配色 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 0}, {"url": "/products/savewo/3dmeowkscbdg-2.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 秋冬限定配色 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 1}, {"url": "/products/savewo/3dmeowkscbdg-3.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 秋冬限定配色 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 2}, {"url": "/products/savewo/3dmeowkscbdg-4.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 秋冬限定配色 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 3}, {"url": "/products/savewo/3dmeowkscbdg-5.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 秋冬限定配色 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 4}, {"url": "/products/savewo/3dmeowkscbdg-6.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 秋冬限定配色 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 5}]', 149.0, NULL, 'active', 174) ON CONFLICT DO NOTHING;
