INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('65ab085b-9d01-43ca-bf11-1235cca8d78a', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '69787a97-49de-477e-9431-87d166480be0', 'SAVEWO DASH F Portable E-Scooter 便攜型電動滑板車 （香港國際版）', 'dashf-hk', '65321dae0465f1001173a8d8', 'SAVEWO DASH F Portable E-Scooter 便攜型電動滑板車 （香港國際版）*通過認證通過EN17128:2020 PLEV 電動個人載具認證*車身穩固 車身採用高強度鋁合金及鑄鐵複合車架，剛柔並重*車身穩固 車身採用高強度鋁合金及鑄鐵複合車架，剛柔並重*承重量高車輛淨重約15.5kg，安全承重高達100kg*防塵防水具有IP54的防塵及防水等級，減少維修需求*易攜易藏快速摺疊及展開，可放入汽車後備箱或輕鬆手持或拖拉，方便收納及攜帶*續航力高採用36V 7.8Ah 280Wh高容量電池，繼航力達28km，足夠日常代步*良好體驗強大的350W前驅無刷電機，峰值輸出達700W', '/products/savewo/dashf-hk.jpg', '[{"url": "/products/savewo/dashf-hk.jpg", "alt": "SAVEWO DASH F Portable E-Scooter 便攜型電動滑板車 （香港國際版）", "sortOrder": 0}, {"url": "/products/savewo/dashf-hk-2.jpg", "alt": "SAVEWO DASH F Portable E-Scooter 便攜型電動滑板車 （香港國際版）", "sortOrder": 1}, {"url": "/products/savewo/dashf-hk-3.jpg", "alt": "SAVEWO DASH F Portable E-Scooter 便攜型電動滑板車 （香港國際版）", "sortOrder": 2}, {"url": "/products/savewo/dashf-hk-4.jpg", "alt": "SAVEWO DASH F Portable E-Scooter 便攜型電動滑板車 （香港國際版）", "sortOrder": 3}, {"url": "/products/savewo/dashf-hk-5.jpg", "alt": "SAVEWO DASH F Portable E-Scooter 便攜型電動滑板車 （香港國際版）", "sortOrder": 4}, {"url": "/products/savewo/dashf-hk-6.jpg", "alt": "SAVEWO DASH F Portable E-Scooter 便攜型電動滑板車 （香港國際版）", "sortOrder": 5}, {"url": "/products/savewo/dashf-hk-7.jpg", "alt": "SAVEWO DASH F Portable E-Scooter 便攜型電動滑板車 （香港國際版）", "sortOrder": 6}, {"url": "/products/savewo/dashf-hk-8.jpg", "alt": "SAVEWO DASH F Portable E-Scooter 便攜型電動滑板車 （香港國際版）", "sortOrder": 7}]', 1980.0, NULL, 'active', 182) ON CONFLICT DO NOTHING;
