INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('63958689-d394-44f0-a8c2-1ebab1815db8', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'd66b8015-ab1e-4515-9b64-fa994d4452a8', '救世專業玻璃保護貼（超高清特薄版）(iPhone 15 適用)', 'savewo-proglass-ultra-thin-hd', '652faa1921c1460017f0ff2b', '*10秒無塵輕鬆安裝 10 seconds dust-free effortless installation精心設計無塵倉10秒精準定位安裝，抽走除塵貼後迅間無瑕無垢，附送氣泡清潔卡刮走氣泡，手殘黨亦可享零失敗體驗。*採用0.25mm 超薄超高韌性鋁矽玻璃比起傳統鈉鈣玻璃更具高透光性及韌性，更透明及更薄。*二次鋼化，防止破碎經過物理及化學硬化及鋼化處理，強度大增，抵受衝擊，不易破碎。*超強抗刮墊上雙層紙後以美工刀亂劃，紙穿貼無傷。*順滑手感，零摩擦力表面絲滑爽快，超原廠玻璃的觸感，電競一流！*95%超高透光度市場上最高的透光度，不損屏幕顯示效果。*特高色彩還原度重現屏幕色彩真象，減少失真。*', '/products/savewo/savewo-proglass-ultra-thin-hd.jpg', '[{"url": "/products/savewo/savewo-proglass-ultra-thin-hd.jpg", "alt": "救世專業玻璃保護貼（超高清特薄版）(iPhone 15 適用)", "sortOrder": 0}, {"url": "/products/savewo/savewo-proglass-ultra-thin-hd-2.jpg", "alt": "救世專業玻璃保護貼（超高清特薄版）(iPhone 15 適用)", "sortOrder": 1}, {"url": "/products/savewo/savewo-proglass-ultra-thin-hd-3.jpg", "alt": "救世專業玻璃保護貼（超高清特薄版）(iPhone 15 適用)", "sortOrder": 2}, {"url": "/products/savewo/savewo-proglass-ultra-thin-hd-4.jpg", "alt": "救世專業玻璃保護貼（超高清特薄版）(iPhone 15 適用)", "sortOrder": 3}, {"url": "/products/savewo/savewo-proglass-ultra-thin-hd-5.jpg", "alt": "救世專業玻璃保護貼（超高清特薄版）(iPhone 15 適用)", "sortOrder": 4}]', 138.0, NULL, 'active', 184) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('207d50a6-12b9-45f6-8737-2020d84ae750', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '0e7588df-a28c-4b75-80be-f1b9352e282e', 'SAVEWO AirFlow Neck Fan 便攜型掛頸式香薰風扇', 'airflow-neckfan', '652cd2c45bb71d002393607f', '無拘無束 溫柔送爽SAVEWO AirFlow 便攜型掛頸式香薰風扇重量只有180g，長期佩戴亦不感倦意；最長可4.5小時送出立體環形柔風，配合三段風速調節、小蒼蘭、佛手柑、山茶花三種不同香薰片，不論天氣，都可為您送爽添香。*風量不同 一樣溫柔三段風速調節，清爽微風可送走鬱悶，加強風力後則可帶來瞬間清涼，切合不同季節、環境需要。立體環形柔風，避免因為強風拂面而造成頭痛、頭暈等不適。*香薰擴香 感受自然可添加三款不同花果香味的香薰片，以散發香氣、提振精神，使您漫步城市、仍可呼吸自然。*自由自在 親膚舒適 解放雙手，工作、運動、烹飪時不再大汗淋漓。以親膚材質所製，減少黏膩感。鬆緊可調，不感束縛。*', '/products/savewo/airflow-neckfan.jpg', '[{"url": "/products/savewo/airflow-neckfan.jpg", "alt": "SAVEWO AirFlow Neck Fan 便攜型掛頸式香薰風扇", "sortOrder": 0}, {"url": "/products/savewo/airflow-neckfan-2.jpg", "alt": "SAVEWO AirFlow Neck Fan 便攜型掛頸式香薰風扇", "sortOrder": 1}, {"url": "/products/savewo/airflow-neckfan-3.jpg", "alt": "SAVEWO AirFlow Neck Fan 便攜型掛頸式香薰風扇", "sortOrder": 2}]', 168.0, NULL, 'active', 185) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('30f415b1-37e1-4607-a1f5-3a2a2c459deb', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'd66b8015-ab1e-4515-9b64-fa994d4452a8', '*1米* SAVEWO ProCable USB-C CoAxial USB4 Thunderbolt 4 極速全能線（三色可選）', 'procable-coaxial-1m', '652674171f1fb16a1824691a', 'SAVEWO ProCable USB-C CoAxial 再度升級登場！超高速超穩定超耐用！SAVEWO ProCable USB-C CoAxial 以最完美USB-C全能線為目標為開發目標，兼容USB4及Thunderblot 4 ，達至一線全能，支援PD3.1 240W極速充電，40Gbps超高速數據傳輸，更支援DP1.4 8K60hz/ 4k144hz的超高清視頻傳輸，只要有一條線就可以滿足USB-C最高的性能要求！適用於一切的USB-C裝置及應用場景！救世產品從來𣎴單止追求數字上的性能，更賈保証產品穩定及耐用，每一個客戶拿到實物後都會感受到其與眾不同的設計，並能以超值價格得到最佳的', '/products/savewo/procable-coaxial-1m.jpg', '[{"url": "/products/savewo/procable-coaxial-1m.jpg", "alt": "*1米* SAVEWO ProCable USB-C CoAxial USB4 Thunderbolt 4 極速全能線（三色可選）", "sortOrder": 0}, {"url": "/products/savewo/procable-coaxial-1m-2.jpg", "alt": "*1米* SAVEWO ProCable USB-C CoAxial USB4 Thunderbolt 4 極速全能線（三色可選）", "sortOrder": 1}, {"url": "/products/savewo/procable-coaxial-1m-3.jpg", "alt": "*1米* SAVEWO ProCable USB-C CoAxial USB4 Thunderbolt 4 極速全能線（三色可選）", "sortOrder": 2}, {"url": "/products/savewo/procable-coaxial-1m-4.jpg", "alt": "*1米* SAVEWO ProCable USB-C CoAxial USB4 Thunderbolt 4 極速全能線（三色可選）", "sortOrder": 3}, {"url": "/products/savewo/procable-coaxial-1m-5.jpg", "alt": "*1米* SAVEWO ProCable USB-C CoAxial USB4 Thunderbolt 4 極速全能線（三色可選）", "sortOrder": 4}, {"url": "/products/savewo/procable-coaxial-1m-6.jpg", "alt": "*1米* SAVEWO ProCable USB-C CoAxial USB4 Thunderbolt 4 極速全能線（三色可選）", "sortOrder": 5}, {"url": "/products/savewo/procable-coaxial-1m-7.jpg", "alt": "*1米* SAVEWO ProCable USB-C CoAxial USB4 Thunderbolt 4 極速全能線（三色可選）", "sortOrder": 6}, {"url": "/products/savewo/procable-coaxial-1m-8.jpg", "alt": "*1米* SAVEWO ProCable USB-C CoAxial USB4 Thunderbolt 4 極速全能線（三色可選）", "sortOrder": 7}, {"url": "/products/savewo/procable-coaxial-1m-9.jpg", "alt": "*1米* SAVEWO ProCable USB-C Co