INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('add213b5-73f0-4c03-9da1-b0cb873548fb', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'ee5d2925-5774-4a23-92ce-01a1b071f520', '*10米卷裝* SAVEWO 救世 TranSkin 防水透明薄膜 (闊10cm)', 'wondaleaf-flatdressing-10m', '64f6ef57041be1002036ab9f', 'SAVEWO 救世 TranSkin 防水透明薄膜，薄到只得0.02mm，防水耐用、透氣舒適！超薄親膚的材質，貼上後就不覺得存在。無論是洗手或是沐浴，長時間防水功能能有效預防傷口因沾水而發炎，加速傷口癒合，提供極佳防護！🔗 產品網站https://www.savewo.com/healthcare/zh-hk/products/transkin/dressing/ts-rd10香港製造0.02mm超薄設計使傷口完美隱形，面上傷痕不再顯眼日常洗手、洗澡不會影響傷口可根據傷口大小剪裁，不易捲邊鬆脫，即使用於腳踝、手指等關節位置也不容易鬆脫清潔後的割傷、擦傷、燙傷等，可配合藥膏加速傷口癒合應用場景廣', '/products/savewo/wondaleaf-flatdressing-10m.jpg', '[{"url": "/products/savewo/wondaleaf-flatdressing-10m.jpg", "alt": "*10米卷裝* SAVEWO 救世 TranSkin 防水透明薄膜 (闊10cm)", "sortOrder": 0}, {"url": "/products/savewo/wondaleaf-flatdressing-10m-2.jpg", "alt": "*10米卷裝* SAVEWO 救世 TranSkin 防水透明薄膜 (闊10cm)", "sortOrder": 1}, {"url": "/products/savewo/wondaleaf-flatdressing-10m-3.jpg", "alt": "*10米卷裝* SAVEWO 救世 TranSkin 防水透明薄膜 (闊10cm)", "sortOrder": 2}]', 380.0, NULL, 'active', 189) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('7e03d572-fbb9-4313-9d18-d33aadafbe50', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '3b4f89f7-ada4-4fe0-9f12-d3040323a344', 'Rainec ULTRA 極輕特大高性能碳纖維雨傘 (典雅黑)', 'rainec-ultra-black', '64e72e2ed6dfa10020113179', 'Rainec ULTRA為市場上最輕巧的特大高性能雨傘，採用全碳纖傘架及傘骨，傘長102cm，展開後覆蓋面積直徑高達134cm，重量卻只有410g。「大而不重，輕而易舉」的Rainec ULTRA即使三人同行，亦能「風雨同路」無懼沾濕。Rainec ULTRA晴雨均宜，最新研發的Rainec TEX超高性能傘布，具有超潑水塗層，令水形成水滴滑走，快速乾透，潑水性能測試高達滿分100分。遮蔽99.95% UV紫外光，有助保持美白；同時遮擋100%可見光， 阻隔熱力穿透，收即時降溫之效。其特製手柄上設有防滑斜面，只要靠牆即可穩妥站立，設計巧妙，便於收納。🔗 產品網站https://rainec.c', '/products/savewo/rainec-ultra-black.jpg', '[{"url": "/products/savewo/rainec-ultra-black.jpg", "alt": "Rainec ULTRA 極輕特大高性能碳纖維雨傘 (典雅黑)", "sortOrder": 0}, {"url": "/products/savewo/rainec-ultra-black-2.jpg", "alt": "Rainec ULTRA 極輕特大高性能碳纖維雨傘 (典雅黑)", "sortOrder": 1}, {"url": "/products/savewo/rainec-ultra-black-3.jpg", "alt": "Rainec ULTRA 極輕特大高性能碳纖維雨傘 (典雅黑)", "sortOrder": 2}, {"url": "/products/savewo/rainec-ultra-black-4.jpg", "alt": "Rainec ULTRA 極輕特大高性能碳纖維雨傘 (典雅黑)", "sortOrder": 3}, {"url": "/products/savewo/rainec-ultra-black-5.jpg", "alt": "Rainec ULTRA 極輕特大高性能碳纖維雨傘 (典雅黑)", "sortOrder": 4}]', 338.0, NULL, 'active', 190) ON CONFLICT DO NOTHING;
