INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('90bfabe9-cdff-47bc-9134-b37e327b92f9', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '00462c1c-b0f1-475d-b69c-5e40ad30ded5', '*KS 兒童細碼* SAVEWO 3DMEOW DARK GREEN 救世立體喵兒童防護口罩 深綠色 (30片獨立包裝/盒) (2-6歲適用)', '3dmeows2darkgreen', '64ad0d4a80eede5c04e69143', 'SAVEWO 3DMEOW for Kids救世立體喵兒童防護口罩！萌爆升級！童心抗疫！綻放笑容！立體喵！超透氣！強過濾！採用救世最新TypeCool＋過濾技術，前所未有的透氣感受，配合 ESPP 不織布親膚物料及舒適型耳帶，質感柔軟舒適。把最好的都給予小朋友，讓他們戴著口罩也能綻放笑容！SAVEWO 3DMEOW for Kids 救世立體喵是即棄式兒童防護口罩，採用專利萌爆立體剪裁，有效增加呼吸空間，長時間穿戴也十分舒適，設有2款尺碼，適配2-6歲小童及7-13歲中童的臉型。升級版本採用最新TypeCool+ 過濾技術，超低呼吸阻力 Breathing Resistance&lt; 2.8', '/products/savewo/3dmeows2darkgreen.jpg', '[{"url": "/products/savewo/3dmeows2darkgreen.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW DARK GREEN 救世立體喵兒童防護口罩 深綠色 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 0}, {"url": "/products/savewo/3dmeows2darkgreen-2.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW DARK GREEN 救世立體喵兒童防護口罩 深綠色 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 1}, {"url": "/products/savewo/3dmeows2darkgreen-3.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW DARK GREEN 救世立體喵兒童防護口罩 深綠色 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 2}, {"url": "/products/savewo/3dmeows2darkgreen-4.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW DARK GREEN 救世立體喵兒童防護口罩 深綠色 (30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 3}]', 149.0, NULL, 'active', 192) ON CONFLICT DO NOTHING;
