INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('5eeb52f8-7ec3-402e-b026-c094fcb38550', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '3b4f89f7-ada4-4fe0-9f12-d3040323a344', 'Rainec mini Pro 超輕防曬超潑水防回彈自動摺遮 (Silver Wormwood/銀葉艾)', 'rainec-minipro-silverwormwood', '6475d5d966055100239c06dc', '產品特點- 250g 超輕玻璃纖維傘骨玻璃纖維 + 鋁鎂合金複合傘骨，令開合極其順暢，整傘僅重250g，超堅硬耐用且輕盈，輕鬆駕馭。- 超潑水急乾潑水塗層令雨水形成水滴型。有效減少雨水沾在傘布，快速乾透，潑水性能測試達至滿分100分。(AATCC TM22-2017e)- 隔絕99.95%紫外光終極標準高性能不透光布。遮蔽99.95% UV，能同時作為防曬傘使用，晴雨兼用。(AATCC TM183-2020)- 不透光遮陽隔熱特製純黑不透光底層，實現零透光，有效遮擋100%可見光， 同時阻隔熱力穿透，即時降溫。(AATCC 203-2016)- 280T 超高密度傘布超輕薄傘布採用超密280T', '/products/savewo/rainec-minipro-silverwormwood.jpg', '[{"url": "/products/savewo/rainec-minipro-silverwormwood.jpg", "alt": "Rainec mini Pro 超輕防曬超潑水防回彈自動摺遮 (Silver Wormwood/銀葉艾)", "sortOrder": 0}, {"url": "/products/savewo/rainec-minipro-silverwormwood-2.jpg", "alt": "Rainec mini Pro 超輕防曬超潑水防回彈自動摺遮 (Silver Wormwood/銀葉艾)", "sortOrder": 1}, {"url": "/products/savewo/rainec-minipro-silverwormwood-3.jpg", "alt": "Rainec mini Pro 超輕防曬超潑水防回彈自動摺遮 (Silver Wormwood/銀葉艾)", "sortOrder": 2}, {"url": "/products/savewo/rainec-minipro-silverwormwood-4.jpg", "alt": "Rainec mini Pro 超輕防曬超潑水防回彈自動摺遮 (Silver Wormwood/銀葉艾)", "sortOrder": 3}, {"url": "/products/savewo/rainec-minipro-silverwormwood-5.jpg", "alt": "Rainec mini Pro 超輕防曬超潑水防回彈自動摺遮 (Silver Wormwood/銀葉艾)", "sortOrder": 4}]', 198.0, NULL, 'sold_out', 197) ON CONFLICT DO NOTHING;
