INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('2ad0eae9-a271-41cc-b356-1b7499cda3ce', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '7ed7ec4c-f825-40e7-99d9-486092d7834c', '半價超級優惠 5折！*優惠價$11800，原價$23800 *SAVEWO HEALTHCHAIR Z CARBON - ZC1 高性能碳纖維電動輪椅', 'healthchair-zcarbonzc1', '64658d301cf24300239a4517', '半價超級優惠 5折！$11,800 原價 $23,800 試車預約：95482544HealthChair Z CARBON ZC1碳纖車架 極致輕量 完美功能 「承重高達150kg」原價$23800 預訂優惠價$11800 🔗 產品網站https://healthchair.com/zc1/特點：*極致輕量 - 採用碳纖維車架，連電池總重僅為19kg，約為傳統電動輪椅一半重量。*極強承重 - 安全負重達150kg，足以應付不同顧客需求，為市場上最高承重性能的摺疊電動輪椅。*3秒摺疊 - 簡單步驟，摺疊後體積細小，並可站立及拖行，便於攜帶和存放。*持久續航力 - 採用高容量電池時，一次充電提供', '/products/savewo/healthchair-zcarbonzc1.jpg', '[{"url": "/products/savewo/healthchair-zcarbonzc1.jpg", "alt": "半價超級優惠 5折！*優惠價$11800，原價$23800 *SAVEWO HEALTHCHAIR Z CARBON - ZC1 高性能碳纖維電動輪椅", "sortOrder": 0}, {"url": "/products/savewo/healthchair-zcarbonzc1-2.jpg", "alt": "半價超級優惠 5折！*優惠價$11800，原價$23800 *SAVEWO HEALTHCHAIR Z CARBON - ZC1 高性能碳纖維電動輪椅", "sortOrder": 1}, {"url": "/products/savewo/healthchair-zcarbonzc1-3.jpg", "alt": "半價超級優惠 5折！*優惠價$11800，原價$23800 *SAVEWO HEALTHCHAIR Z CARBON - ZC1 高性能碳纖維電動輪椅", "sortOrder": 2}, {"url": "/products/savewo/healthchair-zcarbonzc1-4.jpg", "alt": "半價超級優惠 5折！*優惠價$11800，原價$23800 *SAVEWO HEALTHCHAIR Z CARBON - ZC1 高性能碳纖維電動輪椅", "sortOrder": 3}, {"url": "/products/savewo/healthchair-zcarbonzc1-5.jpg", "alt": "半價超級優惠 5折！*優惠價$11800，原價$23800 *SAVEWO HEALTHCHAIR Z CARBON - ZC1 高性能碳纖維電動輪椅", "sortOrder": 4}, {"url": "/products/savewo/healthchair-zcarbonzc1-6.jpg", "alt": "半價超級優惠 5折！*優惠價$11800，原價$23800 *SAVEWO HEALTHCHAIR Z CARBON - ZC1 高性能碳纖維電動輪椅", "sortOrder": 5}, {"url": "/products/savewo/healthchair-zcarbonzc1-7.jpg", "alt": "半價超級優惠 5折！*優惠價$11800，原價$23800 *SAVEWO HEALTHCHAIR Z CARBON - ZC1 高性能碳纖維電動輪椅", "sortOrder": 6}, {"url": "/products/savewo/healthchair-zcarbonzc1-8.jpg", "alt": "半價超級優惠 5折！*優惠價$11800，原價$23800 *SAVEWO HEALTHCHAIR Z CARBON - ZC1 高