INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('bf187510-3ab2-45e6-bc28-60537ad1e250', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '69787a97-49de-477e-9431-87d166480be0', 'SAVEWO DASH F E-Scooter 日本「特定原付」版本', 'dashf-jp', '6426a9ac74535e1c5ef202d2', 'SAVEWO DASH F E-Scooter 日本「特定原付」版本首款日本國外品牌取得免許認證的「特定原付」電動車 (認證編號為JATA-0023，即第23款取得認證車型)！任何年滿16歲人士，在日本都可以無需駕駛執照，騎行SAVEWO DASH F在行人同車道上暢行！【DASH F特點一覽】*通過認證通過EN17128:2020 PLEV 電動個人載具認證日本國土交通省註冊「特定原付」電動車*車身穩固 車身採用高強度鋁合金及鑄鐵複合車架，剛柔並重*承重量高車輛淨重約15.5kg，安全承重高達100kg*防塵防水具有IP54的防塵及防水等級，減少維修需求*易攜易藏快速摺疊及展開，可放入汽車後', '/products/savewo/dashf-jp.jpg', '[{"url": "/products/savewo/dashf-jp.jpg", "alt": "SAVEWO DASH F E-Scooter 日本「特定原付」版本", "sortOrder": 0}, {"url": "/products/savewo/dashf-jp-2.jpg", "alt": "SAVEWO DASH F E-Scooter 日本「特定原付」版本", "sortOrder": 1}, {"url": "/products/savewo/dashf-jp-3.jpg", "alt": "SAVEWO DASH F E-Scooter 日本「特定原付」版本", "sortOrder": 2}, {"url": "/products/savewo/dashf-jp-4.jpg", "alt": "SAVEWO DASH F E-Scooter 日本「特定原付」版本", "sortOrder": 3}, {"url": "/products/savewo/dashf-jp-5.jpg", "alt": "SAVEWO DASH F E-Scooter 日本「特定原付」版本", "sortOrder": 4}, {"url": "/products/savewo/dashf-jp-6.jpg", "alt": "SAVEWO DASH F E-Scooter 日本「特定原付」版本", "sortOrder": 5}, {"url": "/products/savewo/dashf-jp-7.jpg", "alt": "SAVEWO DASH F E-Scooter 日本「特定原付」版本", "sortOrder": 6}, {"url": "/products/savewo/dashf-jp-8.jpg", "alt": "SAVEWO DASH F E-Scooter 日本「特定原付」版本", "sortOrder": 7}, {"url": "/products/savewo/dashf-jp-9.jpg", "alt": "SAVEWO DASH F E-Scooter 日本「特定原付」版本", "sortOrder": 8}]', 2980.0, NULL, 'active', 202) ON CONFLICT DO NOTHING;
