INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('26edc4f1-0305-4cfa-afd7-5defa1578819', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '827788ac-3d7c-40dc-88c5-5f6e6de09891', '*480支裝, 平均 $5/盒* SAVEWO COVID-19 (SARS-COV-2) ANTIGEN TEST KIT 新型冠狀病毒抗原測試劑', 'rat-covid19-480', '63bd2a419af4bc0017cc975f', '新版SAVEWO測試劑登場！品質更好！使用更方便！防疫法例實施後，快測需求更大，不同場合均需要顯示快測結果以示健康狀況，唔少用家向我哋分享用後心得，經過不少意見數集變成數據分析後，我哋重新設計改良並推出全新版本快速抗原測試劑，兩大清晰三大保證，務求令大家買得安心用得稱心：🔺 全新包裝更美觀，說明更清晰，全年齡都能使用正確！🔺 每盒包裝均印有香港衛生署認證編號，官方醫療級認可，信心保證！🔺 檢測器上設有日期同ID位置，方便用戶填上資料於不同場合顯示記錄🔺 全新品質監控機制，令出廠品質更有保證！🔺 全新鮮製造，特長3年保質期，使用期限最大化，效能及質素保證！🔗 產品網站https://www.sa', '/products/savewo/rat-covid19-480.jpg', '[{"url": "/products/savewo/rat-covid19-480.jpg", "alt": "*480支裝, 平均 $5/盒* SAVEWO COVID-19 (SARS-COV-2) ANTIGEN TEST KIT 新型冠狀病毒抗原測試劑", "sortOrder": 0}, {"url": "/products/savewo/rat-covid19-480-2.jpg", "alt": "*480支裝, 平均 $5/盒* SAVEWO COVID-19 (SARS-COV-2) ANTIGEN TEST KIT 新型冠狀病毒抗原測試劑", "sortOrder": 1}]', 2400.0, NULL, 'active', 214) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('7b240965-d079-471d-945a-bb22ee3655f4', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '3a0021f1-4a3a-45d6-928f-711d9cebfb99', '*R 標準碼* SAVEWO ROYAL MASK 救世 2D 對摺型口罩 晨霧「KF94 + KN95 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)', 'royal-r-morningmist', '63b7da70f2c508002362424c', '集救世科研與時尚極致於一身，極修臉對摺型口罩 Royal Mask，能高度適合95%人士臉形，簡約而細緻V形設計讓你配戴極為方便亦易於收納。秉承救世專利過濾技術 TYPECOOL+，Royal Mask 保留「高透氣」「強過濾」「防敏感」特質，除有效防禦99.9%飛沫、花粉、懸浮物質、細菌及病毒，更配合獨有剪裁讓其緊貼面部完美防止漏氣，符合人體工學的立體設計，內部空間比一般口罩多出30％，呼吸更暢順，配戴更舒適無阻！Royal 級剪裁專利V形設計以極致的人體工學研發而成，質料防敏剪裁獨特，舒適地貼服在臉上猶如無物。配戴後更顯臉型利落自然，流暢線條讓你流露出最自然輕盈一面，無論便裝或晚裝，Roy', '/products/savewo/royal-r-morningmist.jpg', '[{"url": "/products/savewo/royal-r-morningmist.jpg", "alt": "*R 標準碼* SAVEWO ROYAL MASK 救世 2D 對摺型口罩 晨霧「KF94 + KN95 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)", "sortOrder": 0}, {"url": "/products/savewo/royal-r-morningmist-2.jpg", "alt": "*R 標準碼* SAVEWO ROYAL MASK 救世 2D 對摺型口罩 晨霧「KF94 + KN95 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)", "sortOrder": 1}, {"url": "/products/savewo/royal-r-morningmist-3.jpg", "alt": "*R 標準碼* SAVEWO ROYAL MASK 救世 2D 對摺型口罩 晨霧「KF94 + KN95 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)", "sortOrder": 2}, {"url": "/products/savewo/royal-r-morningmist-4.jpg", "alt": "*R 標準碼* SAVEWO ROYAL MASK 救世 2D 對摺型口罩 晨霧「KF94 + KN95 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)", "sortOrder": 3}, {"url": "/products/savewo/royal-r-morningmist-5.jpg", "alt": "*R 標準碼* SAVEWO ROYAL MASK 救世 2D 對摺型口罩 晨霧「KF94 + KN95 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)", "sortOrder": 4}]', 149.0, NULL, 'active', 215) ON CONFLICT DO NOTHING;
