INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('24de74b6-4557-47ed-a73d-eccdc3da1ec8', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'd66b9de1-9046-49e4-bba6-512eadf35382', '*R 標準碼* SAVEWO 3DMASK Candy 救世超立體口罩 幻彩糖果版 (3色耳帶各10件，30片/盒，獨立包裝）', 'candy-r', '6392a3d75f5870002e9468a1', '眾望所歸，CANDY返嚟喇！曾大受歡迎一度斷市再斷市嘅 3DMASK CANDY 系列終於回歸，今次重新推出仲大大升級，剪裁秉承最貼服V面嘅VPlus系列，突顯面部輪廓令面形更瘦更尖。配以全新3款糖果色耳帶，簡潔地流露你可愛一面！一盒三色，讓你隨不同心情配戴適合果味！糖果耳帶顏色：藍色 - 藍莓 Blueberry紫色 - 提子 Grape粉色 - 草莓 StrawberrySAVEWO 3DMASK Candy 救世超立體口罩 幻彩糖果版(3色耳帶各10件，30片/盒 ，獨立包裝）Regular Size 標準碼 摺疊尺寸：208 mm x 81 mm張開尺寸：170 mm x 112 mm', '/products/savewo/candy-r.jpg', '[{"url": "/products/savewo/candy-r.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK Candy 救世超立體口罩 幻彩糖果版 (3色耳帶各10件，30片/盒，獨立包裝）", "sortOrder": 0}, {"url": "/products/savewo/candy-r-2.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK Candy 救世超立體口罩 幻彩糖果版 (3色耳帶各10件，30片/盒，獨立包裝）", "sortOrder": 1}, {"url": "/products/savewo/candy-r-3.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK Candy 救世超立體口罩 幻彩糖果版 (3色耳帶各10件，30片/盒，獨立包裝）", "sortOrder": 2}, {"url": "/products/savewo/candy-r-4.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK Candy 救世超立體口罩 幻彩糖果版 (3色耳帶各10件，30片/盒，獨立包裝）", "sortOrder": 3}, {"url": "/products/savewo/candy-r-5.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK Candy 救世超立體口罩 幻彩糖果版 (3色耳帶各10件，30片/盒，獨立包裝）", "sortOrder": 4}, {"url": "/products/savewo/candy-r-6.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK Candy 救世超立體口罩 幻彩糖果版 (3色耳帶各10件，30片/盒，獨立包裝）", "sortOrder": 5}, {"url": "/products/savewo/candy-r-7.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK Candy 救世超立體口罩 幻彩糖果版 (3色耳帶各10件，30片/盒，獨立包裝）", "sortOrder": 6}, {"url": "/products/savewo/candy-r-8.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK Candy 救世超立體口罩 幻彩糖果版 (3色耳帶各10件，30片/盒，獨立包裝）", "sortOrder": 7}]', 129.0, NULL, 'active', 219) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('07b9dcc1-6e32-43a4-a0cb-875e0619ad77', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '00462c1c-b0f1-475d-b69c-5e40ad30ded5', '*KDT 小顏人士* SAVEWO 3DMEOW BLACK 救世立體喵頑童防護口罩 黑色 (30片獨立包裝/盒) (大童, 小顏人士適用)', 'kidultsblack', '637f54d9edb00700310a80ce', '概覽童真不是小朋友的專利，救世精心開發出 SAVEWO 3DMEOW For Kidults 立體喵頑童版防護口罩！現正推出黑色常規版本 !救世立體喵頑童版防護口罩採用中童及小顏成人設計，同時也適合各位童心未泯嘅大細路！除了白喵、粉紅喵、粉藍喵之外，仲有隻跑得慢半拍既黑貓趕黎登場！3DMEOW更通過韓國MFDS 認證為KF94等級，尺碼增至4款，無論大人同小朋友都能夠安心配戴，變成超可愛貓喵萌爆示人！爸爸媽媽賺錢買喵戴～3DMEOW For Kidults配合3DMEOW For Kids，同囝囝囡囡一齊萌爆全場！童心抗疫！綻放笑容！🔗 產品網站https://www.savewo.com/h', '/products/savewo/kidultsblack.jpg', '[{"url": "/products/savewo/kidultsblack.jpg", "alt": "*KDT 小顏人士* SAVEWO 3DMEOW BLACK 救世立體喵頑童防護口罩 黑色 (30片獨立包裝/盒) (大童, 小顏人士適用)", "sortOrder": 0}, {"url": "/products/savewo/kidultsblack-2.jpg", "alt": "*KDT 小顏人士* SAVEWO 3DMEOW BLACK 救世立體喵頑童防護口罩 黑色 (30片獨立包裝/盒) (大童, 小顏人士適用)", "sortOrder": 1}, {"url": "/products/savewo/kidultsblack-3.jpg", "alt": "*KDT 小顏人士* SAVEWO 3DMEOW BLACK 救世立體喵頑童防護口罩 黑色 (30片獨立包裝/盒) (大童, 小顏人士適用)", "sortOrder": 2}, {"url": "/products/savewo/kidultsblack-4.jpg", "alt": "*KDT 小顏人士* SAVEWO 3DMEOW BLACK 救世立體喵頑童防護口罩 黑色 (30片獨立包裝/盒) (大童, 小顏人士適用)", "sortOrder": 3}, {"url": "/products/savewo/kidultsblack-5.jpg", "alt": "*KDT 小顏人士* SAVEWO 3DMEOW BLACK 救世立體喵頑童防護口罩 黑色 (30片獨立包裝/盒) (大童, 小顏人士適用)", "sortOrder": 4}, {"url": "/products/savewo/kidultsblack-6.jpg", "alt": "*KDT 小顏人士* SAVEWO 3DMEOW BLACK 救世立體喵頑童防護口罩 黑色 (30片獨立包裝/盒) (大童, 小顏人士適用)", "sortOrder": 5}]', 149.0, NULL, 'active', 220) ON CONFLICT DO NOTHING;
