INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('77cfcb61-f7c3-4938-a050-9de53d33ae11', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '32234e3e-2b17-4439-9d07-45628db0d7c4', '*145mm KL 兒童大碼* SAVEWO ClassicMask 三摺平面口罩 白色 (30片獨立包裝/盒)', 'classic-145kl-white', '6302f4289ad4bc0025ec7977', '【簡約不簡單】SAVEWO ClassicMask  超快適，高透氣，強過濾SAVEWO首款經典三摺平面口罩  ClassicMask正式登場，推出白色、灰色及黑色三款簡約色調，簡單質樸的色調及設計，滿足不少朋友仔返璞歸真生活態度。唯優秀的性能及品質，我們絕不妥協。V臉剪裁設計，美觀貼臉，採用訂製物料生產，舒適柔軟耳帶，給你無痛感的佩戴感受，加上TYPECOOL+過濾技術，有效維持24小時以上的超強過濾效能及超高透氣度。用上特製ESPP親膚順滑底層，絕不起毛，呵護肌膚。符合美國  ASTM LEVEL3及歐盟  EN14683:2019 Type IIR醫用口罩標準。 SAVEWO Class', '/products/savewo/classic-145kl-white.jpg', '[{"url": "/products/savewo/classic-145kl-white.jpg", "alt": "*145mm KL 兒童大碼* SAVEWO ClassicMask 三摺平面口罩 白色 (30片獨立包裝/盒)", "sortOrder": 0}, {"url": "/products/savewo/classic-145kl-white-2.jpg", "alt": "*145mm KL 兒童大碼* SAVEWO ClassicMask 三摺平面口罩 白色 (30片獨立包裝/盒)", "sortOrder": 1}, {"url": "/products/savewo/classic-145kl-white-3.jpg", "alt": "*145mm KL 兒童大碼* SAVEWO ClassicMask 三摺平面口罩 白色 (30片獨立包裝/盒)", "sortOrder": 2}, {"url": "/products/savewo/classic-145kl-white-4.jpg", "alt": "*145mm KL 兒童大碼* SAVEWO ClassicMask 三摺平面口罩 白色 (30片獨立包裝/盒)", "sortOrder": 3}, {"url": "/products/savewo/classic-145kl-white-5.jpg", "alt": "*145mm KL 兒童大碼* SAVEWO ClassicMask 三摺平面口罩 白色 (30片獨立包裝/盒)", "sortOrder": 4}, {"url": "/products/savewo/classic-145kl-white-6.jpg", "alt": "*145mm KL 兒童大碼* SAVEWO ClassicMask 三摺平面口罩 白色 (30片獨立包裝/盒)", "sortOrder": 5}]', 45.0, NULL, 'active', 226) ON CONFLICT DO NOTHING;
