INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('98dfe0cd-2b0f-433f-9d41-578d67e8fa5f', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '3b4f89f7-ada4-4fe0-9f12-d3040323a344', 'Rainec Air 超輕防曬超潑水摺遮  (Celestine 天青)', 'rainec-air-celestine', '62ee394fc121c800317316ef', '產品特點•	140g 超輕便攜碳纖維 + 鋁鎂合金複合傘骨，開合極其順暢，整傘僅重140g，輕盈超堅硬，輕鬆駕馭。•	超潑水急乾 經專業驗證潑水測試 AATCC TM22-2017e，潑水性能滿分100分，減少雨水沾在傘布，極速乾透。•	不透光遮陽隔熱特製純黑不透光底層，實現零透光，有效遮擋陽光，經不透光測試AATCC 203-2016，有效遮擋100%可見光，阻隔熱力穿透，即時降溫。•	隔絕99.95% 紫外光     經專業驗證抗紫外線測試 AATCC TM183-2020，抗紫外線指數 UPF2000，阻擋 &gt;99.9% 紫外線，隔絕紫外光穿透，能同時作為防曬傘使用，保護您的肌膚，', '/products/savewo/rainec-air-celestine.jpg', '[{"url": "/products/savewo/rainec-air-celestine.jpg", "alt": "Rainec Air 超輕防曬超潑水摺遮  (Celestine 天青)", "sortOrder": 0}, {"url": "/products/savewo/rainec-air-celestine-2.jpg", "alt": "Rainec Air 超輕防曬超潑水摺遮  (Celestine 天青)", "sortOrder": 1}, {"url": "/products/savewo/rainec-air-celestine-3.jpg", "alt": "Rainec Air 超輕防曬超潑水摺遮  (Celestine 天青)", "sortOrder": 2}, {"url": "/products/savewo/rainec-air-celestine-4.jpg", "alt": "Rainec Air 超輕防曬超潑水摺遮  (Celestine 天青)", "sortOrder": 3}, {"url": "/products/savewo/rainec-air-celestine-5.jpg", "alt": "Rainec Air 超輕防曬超潑水摺遮  (Celestine 天青)", "sortOrder": 4}, {"url": "/products/savewo/rainec-air-celestine-6.jpg", "alt": "Rainec Air 超輕防曬超潑水摺遮  (Celestine 天青)", "sortOrder": 5}, {"url": "/products/savewo/rainec-air-celestine-7.jpg", "alt": "Rainec Air 超輕防曬超潑水摺遮  (Celestine 天青)", "sortOrder": 6}, {"url": "/products/savewo/rainec-air-celestine-8.jpg", "alt": "Rainec Air 超輕防曬超潑水摺遮  (Celestine 天青)", "sortOrder": 7}]', 168.0, NULL, 'active', 229) ON CONFLICT DO NOTHING;
