INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('2b82499d-38f5-4a4b-a114-7da718764338', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'd66b9de1-9046-49e4-bba6-512eadf35382', '*R 標準碼* SAVEWO 3DMASK Vplus 救世超立體口罩 (30片獨立包裝/盒)', 'vplus-r', '62e1f804be92f20026619655', '適合度最高的剪裁設計 傳承3DMASK 超立體口罩剪裁加以改良，更為貼合臉型，3DMASK V plus 採用第三代R Size 標準碼，在原有修面設計及適配尺寸之間取得平衡，令95%以上成人合適配戴，為適合度最高的超立體口罩。用戶配戴後的臉型線條更利落，顯V型修臉型效果，視覺流暢自然。3DMASK V plus 採用特製舒適型耳帶，柔軟順滑質感，配載舒適無痛感。採用SAVEWO TYPECOOL+ 過濾技術，能持久保持過濾效能，過濾效率 ≥ 99.9%並有效24小時以上，為你提供極緻防護。摺疊尺寸：208 mm x 81 mm張開尺寸：170 mm x 112 mm適合人群：95% 以上成人', '/products/savewo/vplus-r.jpg', '[{"url": "/products/savewo/vplus-r.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK Vplus 救世超立體口罩 (30片獨立包裝/盒)", "sortOrder": 0}, {"url": "/products/savewo/vplus-r-2.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK Vplus 救世超立體口罩 (30片獨立包裝/盒)", "sortOrder": 1}, {"url": "/products/savewo/vplus-r-3.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK Vplus 救世超立體口罩 (30片獨立包裝/盒)", "sortOrder": 2}, {"url": "/products/savewo/vplus-r-4.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK Vplus 救世超立體口罩 (30片獨立包裝/盒)", "sortOrder": 3}, {"url": "/products/savewo/vplus-r-5.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK Vplus 救世超立體口罩 (30片獨立包裝/盒)", "sortOrder": 4}, {"url": "/products/savewo/vplus-r-6.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK Vplus 救世超立體口罩 (30片獨立包裝/盒)", "sortOrder": 5}]', 129.0, NULL, 'active', 231) ON CONFLICT DO NOTHING;
