INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('5c94c27b-d67b-4d0f-b88f-a24515092bf6', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '00462c1c-b0f1-475d-b69c-5e40ad30ded5', '*KDT 小顏人士* SAVEWO 3DMEOW 救世立體喵頑童防護口罩「吸血鬼小狼」(30片獨立包裝/盒) (大童, 小顏人士適用)', 'vampire3dmeowkidult', '620f67f0b5128a001aa68ca4', '【萬眾期待！吸血鬼小狼決定再回來人間作惡！🖤】自從上年吸血鬼小狼同大家渡過咗一個好鬼好玩嘅Halloween🎃👻之後，就銷聲匿跡……傳聞佢去咗德古拉伯爵古堡遊歷🏰，學習做一隻更好的吸血鬼🧛‍♂️，古堡巍然矗立喺200尺嘅高崖之上，小狼天生有輕功底子，完全難佢唔到9秒9就上去，但係㩒門鐘後先知吸血鬼德古拉伯爵原來不在家🙈雖然小狼深深被古堡嘅神秘氣氛所吸引，但係都知道人間有好多朋友仔掛住佢🥺，小狼大人好開心，決定再回來人間！💌為大家帶來型爆嘅黑色立體喵口罩，準備好再進入黑色世界吧！🖤😈救世立體喵口罩 「吸血小狼版」KDT-頑童版萬眾期待，率先登場，立即預訂！SAVEWO 3DMEOW VAMPIR', '/products/savewo/vampire3dmeowkidult.jpg', '[{"url": "/products/savewo/vampire3dmeowkidult.jpg", "alt": "*KDT 小顏人士* SAVEWO 3DMEOW 救世立體喵頑童防護口罩「吸血鬼小狼」(30片獨立包裝/盒) (大童, 小顏人士適用)", "sortOrder": 0}, {"url": "/products/savewo/vampire3dmeowkidult-2.jpg", "alt": "*KDT 小顏人士* SAVEWO 3DMEOW 救世立體喵頑童防護口罩「吸血鬼小狼」(30片獨立包裝/盒) (大童, 小顏人士適用)", "sortOrder": 1}, {"url": "/products/savewo/vampire3dmeowkidult-3.jpg", "alt": "*KDT 小顏人士* SAVEWO 3DMEOW 救世立體喵頑童防護口罩「吸血鬼小狼」(30片獨立包裝/盒) (大童, 小顏人士適用)", "sortOrder": 2}, {"url": "/products/savewo/vampire3dmeowkidult-4.jpg", "alt": "*KDT 小顏人士* SAVEWO 3DMEOW 救世立體喵頑童防護口罩「吸血鬼小狼」(30片獨立包裝/盒) (大童, 小顏人士適用)", "sortOrder": 3}, {"url": "/products/savewo/vampire3dmeowkidult-5.jpg", "alt": "*KDT 小顏人士* SAVEWO 3DMEOW 救世立體喵頑童防護口罩「吸血鬼小狼」(30片獨立包裝/盒) (大童, 小顏人士適用)", "sortOrder": 4}, {"url": "/products/savewo/vampire3dmeowkidult-6.jpg", "alt": "*KDT 小顏人士* SAVEWO 3DMEOW 救世立體喵頑童防護口罩「吸血鬼小狼」(30片獨立包裝/盒) (大童, 小顏人士適用)", "sortOrder": 5}]', 149.0, NULL, 'active', 250) ON CONFLICT DO NOTHING;
