INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('290aaf32-5563-4ca6-b14e-4408f2ddd929', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '00462c1c-b0f1-475d-b69c-5e40ad30ded5', '*KL 兒童大碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 聖誕別注版「聖誕小狼」(30片獨立包裝/盒) (7-13歲適用)', '3dmeowxml2', '61b0540a3b378c002350dbae', '小狼聖誕鉅製！3DMEOW 節日換裝，Jungle Meow 聖誕喵降臨，同小朋友一齊過聖誕啦！3DMEOW 聖誕別注版全年最開心嘅聖誕節即將來臨，戴上3DMEOW聖誕別注版嚟歡度佳節啦！佢以聖誕紅主題配色，配上青綠色耳帶，戴上後立即化身聖誕喵，等小朋友以萌爆造型，同小狼一齊過聖誕啦！提提大家，3DMEOW 聖誕別注版係節日限定推出貨品，真係手快有、手慢冇架🎄🎄！3DMEOW 聖誕別注版(30片獨立包裝/盒)3DMEOW KL 兒童大碼 (7-13歲少年)摺疊：90 x 120mm張開：140 x 120mm特點:細菌過濾效率 BFE≥99.9%顆粒過濾效率 PFE≥99.9%病毒過濾效率 V', '/products/savewo/3dmeowxml2.jpg', '[{"url": "/products/savewo/3dmeowxml2.jpg", "alt": "*KL 兒童大碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 聖誕別注版「聖誕小狼」(30片獨立包裝/盒) (7-13歲適用)", "sortOrder": 0}, {"url": "/products/savewo/3dmeowxml2-2.jpg", "alt": "*KL 兒童大碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 聖誕別注版「聖誕小狼」(30片獨立包裝/盒) (7-13歲適用)", "sortOrder": 1}, {"url": "/products/savewo/3dmeowxml2-3.jpg", "alt": "*KL 兒童大碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 聖誕別注版「聖誕小狼」(30片獨立包裝/盒) (7-13歲適用)", "sortOrder": 2}]', 149.0, NULL, 'active', 259) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('ced37218-90da-4f1a-8557-d73f4cab2203', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '00462c1c-b0f1-475d-b69c-5e40ad30ded5', '*KS 兒童細碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 聖誕別注版「聖誕小狼」(30片獨立包裝/盒) (2-6歲適用)', '3dmeowxms2', '61b05338333591002f259dea', '小狼聖誕鉅製！3DMEOW 節日換裝，Jungle Meow 聖誕喵降臨，同小朋友一齊過聖誕啦！3DMEOW 聖誕別注版全年最開心嘅聖誕節即將來臨，戴上3DMEOW聖誕別注版嚟歡度佳節啦！佢以聖誕紅主題配色，配上青綠色耳帶，戴上後立即化身聖誕喵，等小朋友以萌爆造型，同小狼一齊過聖誕啦！提提大家，3DMEOW 聖誕別注版係節日限定推出貨品，真係手快有、手慢冇架🎄🎄！特點:細菌過濾效率 BFE≥99.9%顆粒過濾效率 PFE≥99.9%病毒過濾效率 VFE≥99.9%創新  過濾技術，超強過濾極致透氣，能持久保持過濾效能，過濾效率有效24小時以上超低呼吸阻力 Breathing Resistanc', '/products/savewo/3dmeowxms2.jpg', '[{"url": "/products/savewo/3dmeowxms2.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 聖誕別注版「聖誕小狼」(30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 0}, {"url": "/products/savewo/3dmeowxms2-2.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 聖誕別注版「聖誕小狼」(30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 1}, {"url": "/products/savewo/3dmeowxms2-3.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 聖誕別注版「聖誕小狼」(30片獨立包裝/盒) (2-6歲適用)", "sortOrder": 2}]', 149.0, NULL, 'active', 260) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('c2e3a2a4-c1c9-4c65-965f-7439e1d06d3d', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '00462c1c-b0f1-475d-b69c-5e40ad30ded5', '*KS 兒童細碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 黑色特別版「吸血鬼小狼」(30片獨立包裝/盒) (2-6歲幼年)', 'halloween3dmeows2', '615ffc19d7b9e245a6082639', '【🎃Halloween之小狼來了】Halo～Halloween👻萬聖節咁好玩，又點少得小狼嚟搞搞震啊！Trick or Treat😈？無糖🍬嘅話就罰你帶住萬聖節限量嘅小狼口罩周圍搗蛋🦹🏻‍♀️喇！小狼為大家帶來「吸血鬼小狼」系列，俾你同小狼一齊做隊友！戴住口罩一齊出發喇😼～萬聖節限定「小狼口罩系列」介紹：😈 3DMEOW 黑色特別版「吸血鬼小狼」萬聖節來臨，吸血鬼小狼要登場啦👹！平時可愛純潔嘅喵喵們都要嚟個大變身🦹‍♀️，黑化咗嘅立體喵口罩已經為各位預備好，提供3款尺寸，大細吸血鬼小狼都有晒造型，隨時可以開始Trick or Treat喇！😈😈SAVEWO 3DMEOW 立體喵口罩 黑色特別版', '/products/savewo/halloween3dmeows2.jpg', '[{"url": "/products/savewo/halloween3dmeows2.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 黑色特別版「吸血鬼小狼」(30片獨立包裝/盒) (2-6歲幼年)", "sortOrder": 0}, {"url": "/products/savewo/halloween3dmeows2-2.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 黑色特別版「吸血鬼小狼」(30片獨立包裝/盒) (2-6歲幼年)", "sortOrder": 1}, {"url": "/products/savewo/halloween3dmeows2-3.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 黑色特別版「吸血鬼小狼」(30片獨立包裝/盒) (2-6歲幼年)", "sortOrder": 2}, {"url": "/products/savewo/halloween3dmeows2-4.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 黑色特別版「吸血鬼小狼」(30片獨立包裝/盒) (2-6歲幼年)", "sortOrder": 3}, {"url": "/products/savewo/halloween3dmeows2-5.jpg", "alt": "*KS 兒童細碼* SAVEWO 3DMEOW 救世立體喵兒童防護口罩 黑色特別版「吸血鬼小狼」(30片獨立包裝/盒) (2-6歲幼年)", "sortOrder": 4}]', 149.0, NULL, 'active', 261) ON CONFLICT DO NOTHING;
