INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('fbce8384-4aac-4efb-8dbe-9529f3d3ce75', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'ac191fba-1f46-48e1-ad53-69980cff771d', '*M 中碼* SAVEWO PremiumMask 救世超卓口罩 175mm*95mm 粉紅色 (30片獨立包裝/盒)', 'premium-175m-pink', '615d72cb4ef0ab0024a8fb7b', '概覽召喚粉紅教徒！救世SAVEWO 特別推出適合大部分女士臉型的175mm 口罩，更增添夢幻色彩，幻化成SAVEWO PremiumMask常規款粉紅色，滿滿少女感，更容易襯衫，絕對是妳的必然選擇！SAVEWO PremiumMask 常規版粉紅色是一款精心設計的平面型口罩，沿用PremiumMask 系列四摺風琴式設計，加上弧形封邊，簡單一拉就能從平面變成立體型，符合人體力學設計，有效防止漏氣。口罩的鼻樑及嘴部均設有定型條，令口罩立體堅挺，比一般平面口罩有更多的嘴部空間。整個口罩均採用定製物料生產，加上SAVEWO TypeCool+ 過濾技術，有效維持24小時以上的超強過濾效能及超高透氣度', '/products/savewo/premium-175m-pink.jpg', '[{"url": "/products/savewo/premium-175m-pink.jpg", "alt": "*M 中碼* SAVEWO PremiumMask 救世超卓口罩 175mm*95mm 粉紅色 (30片獨立包裝/盒)", "sortOrder": 0}, {"url": "/products/savewo/premium-175m-pink-2.jpg", "alt": "*M 中碼* SAVEWO PremiumMask 救世超卓口罩 175mm*95mm 粉紅色 (30片獨立包裝/盒)", "sortOrder": 1}, {"url": "/products/savewo/premium-175m-pink-3.jpg", "alt": "*M 中碼* SAVEWO PremiumMask 救世超卓口罩 175mm*95mm 粉紅色 (30片獨立包裝/盒)", "sortOrder": 2}, {"url": "/products/savewo/premium-175m-pink-4.jpg", "alt": "*M 中碼* SAVEWO PremiumMask 救世超卓口罩 175mm*95mm 粉紅色 (30片獨立包裝/盒)", "sortOrder": 3}, {"url": "/products/savewo/premium-175m-pink-5.jpg", "alt": "*M 中碼* SAVEWO PremiumMask 救世超卓口罩 175mm*95mm 粉紅色 (30片獨立包裝/盒)", "sortOrder": 4}]', 55.0, NULL, 'active', 263) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('06f6ccc9-c3d7-41b6-8812-bcb6e2452bb6', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'ac191fba-1f46-48e1-ad53-69980cff771d', '*R 標準碼* SAVEWO PremiumMask 救世超卓口罩 160mm*95mm 純白色 (30片獨立包裝/盒)', 'premium-160r-white', '614dba3386c3180023ce23ca', '概覽SAVEWO PremiumMask 救世超卓口罩是精心設計的平面型口罩，採了四摺風琴式設計，加上弧形封邊，一拉就能由平面口罩變成立體形，符合人體力學設計，有效防止漏氣。口罩的鼻樑及嘴部均設有定型條，令口罩立體堅挺，比一般平面口罩有更多的嘴部空間。整個口罩均由專用定製物料生產，加上SAVEWO TypeCool+ 過濾技術，超強過濾效能及超高透氣度，99.9%的超高過濾效能可維持24小時以上。配合特製ESPP親水性順滑底層，絕不起毛，呵護肌膚。符合美國ASTM LEVEL3 及歐盟EN14683:2019 Type IIR 醫用口罩標準。R 標準碼張開：160(W) x 95(H)mm適合', '/products/savewo/premium-160r-white.jpg', '[{"url": "/products/savewo/premium-160r-white.jpg", "alt": "*R 標準碼* SAVEWO PremiumMask 救世超卓口罩 160mm*95mm 純白色 (30片獨立包裝/盒)", "sortOrder": 0}, {"url": "/products/savewo/premium-160r-white-2.jpg", "alt": "*R 標準碼* SAVEWO PremiumMask 救世超卓口罩 160mm*95mm 純白色 (30片獨立包裝/盒)", "sortOrder": 1}, {"url": "/products/savewo/premium-160r-white-3.jpg", "alt": "*R 標準碼* SAVEWO PremiumMask 救世超卓口罩 160mm*95mm 純白色 (30片獨立包裝/盒)", "sortOrder": 2}, {"url": "/products/savewo/premium-160r-white-4.jpg", "alt": "*R 標準碼* SAVEWO PremiumMask 救世超卓口罩 160mm*95mm 純白色 (30片獨立包裝/盒)", "sortOrder": 3}, {"url": "/products/savewo/premium-160r-white-5.jpg", "alt": "*R 標準碼* SAVEWO PremiumMask 救世超卓口罩 160mm*95mm 純白色 (30片獨立包裝/盒)", "sortOrder": 4}, {"url": "/products/savewo/premium-160r-white-6.jpg", "alt": "*R 標準碼* SAVEWO PremiumMask 救世超卓口罩 160mm*95mm 純白色 (30片獨立包裝/盒)", "sortOrder": 5}, {"url": "/products/savewo/premium-160r-white-7.jpg", "alt": "*R 標準碼* SAVEWO PremiumMask 救世超卓口罩 160mm*95mm 純白色 (30片獨立包裝/盒)", "sortOrder": 6}, {"url": "/products/savewo/premium-160r-white-8.jpg", "alt": "*R 標準碼* SAVEWO PremiumMask 救世超卓口罩 160mm*95mm 純白色 (30片獨立包裝/盒)", "sortOrder": 7}, {"url": "/products/savewo/premium-160r-white-9.jpg", "alt": "*R 標準碼* SAVEWO PremiumMask 救世超卓口罩 160mm*95mm 純白色 (30片獨立包裝/盒)", "sortOrder": 8}, {"url