INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('7000ea25-083d-400f-a3aa-79b6cd2d2794', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'ac191fba-1f46-48e1-ad53-69980cff771d', '*R 標準碼* SAVEWO PremiumMask 救世超卓口罩 160mm*95mm 粉紅色 (30片獨立包裝/盒)', 'premium-160r-pink', '6113aef1054c6b003581585b', '概覽召喚粉紅教徒！救世SAVEWO 特別推出適合大部分女士臉型的160mm 口罩，更增添夢幻色彩，幻化成SAVEWO PremiumMask常規款粉紅色，滿滿少女感，更容易襯衫，絕對是妳的必然選擇！SAVEWO PremiumMask 常規版粉紅色是一款精心設計的平面型口罩，沿用PremiumMask 系列四摺風琴式設計，加上弧形封邊，簡單一拉就能從平面變成立體型，符合人體力學設計，有效防止漏氣。口罩的鼻樑及嘴部均設有定型條，令口罩立體堅挺，比一般平面口罩有更多的嘴部空間。整個口罩均採用定製物料生產，加上SAVEWO TypeCool+ 過濾技術，有效維持24小時以上的超強過濾效能及超高透氣度', '/products/savewo/premium-160r-pink.jpg', '[{"url": "/products/savewo/premium-160r-pink.jpg", "alt": "*R 標準碼* SAVEWO PremiumMask 救世超卓口罩 160mm*95mm 粉紅色 (30片獨立包裝/盒)", "sortOrder": 0}, {"url": "/products/savewo/premium-160r-pink-2.jpg", "alt": "*R 標準碼* SAVEWO PremiumMask 救世超卓口罩 160mm*95mm 粉紅色 (30片獨立包裝/盒)", "sortOrder": 1}, {"url": "/products/savewo/premium-160r-pink-3.jpg", "alt": "*R 標準碼* SAVEWO PremiumMask 救世超卓口罩 160mm*95mm 粉紅色 (30片獨立包裝/盒)", "sortOrder": 2}, {"url": "/products/savewo/premium-160r-pink-4.jpg", "alt": "*R 標準碼* SAVEWO PremiumMask 救世超卓口罩 160mm*95mm 粉紅色 (30片獨立包裝/盒)", "sortOrder": 3}, {"url": "/products/savewo/premium-160r-pink-5.jpg", "alt": "*R 標準碼* SAVEWO PremiumMask 救世超卓口罩 160mm*95mm 粉紅色 (30片獨立包裝/盒)", "sortOrder": 4}, {"url": "/products/savewo/premium-160r-pink-6.jpg", "alt": "*R 標準碼* SAVEWO PremiumMask 救世超卓口罩 160mm*95mm 粉紅色 (30片獨立包裝/盒)", "sortOrder": 5}, {"url": "/products/savewo/premium-160r-pink-7.jpg", "alt": "*R 標準碼* SAVEWO PremiumMask 救世超卓口罩 160mm*95mm 粉紅色 (30片獨立包裝/盒)", "sortOrder": 6}]', 55.0, NULL, 'active', 267) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('f1950b27-174e-4c03-833a-bdb37741eee6', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '16d69777-80aa-411e-83bc-e9cd319ec2ea', '救世超立體口罩 SAVEWO 3DMASK EXTREME PRO「FFP3 + KF99 + ASTM LEVEL3 certified 」(15片獨立包裝/盒)', 'extremepro', '60deba3caa163b002fe3e567', 'SAVEWO 3DMASK EXTREME PRO同時達到四大國際標準歐盟FFP3 、KF99、ASTM level 3 及 Type IIR 的即棄式防護呼吸器，保護效能遠超N95！首度採用五層式設計，集合「超強的過濾效能」，「無可匹敵的透氣度」，「極緻密合性能」，「長期作業的舒適度」四大重點於一身的最強防護呼吸器，擁有極緻過濾率，在高風險或惡劣環境下提供極致的保護力，防止塵埃、細菌、病毒等侵襲及感染。而呼吸阻力卻在傳統FFP3 無呼氣閥呼吸器阻力一半以下，透氣度超凡，在其高過濾效能及高氣密性能保護下，用家也能舒適地呼吸。特點 : 極致的密合性能EX PRO擁有獨特專利的V型設計及立體剪裁的', '/products/savewo/extremepro.jpg', '[{"url": "/products/savewo/extremepro.jpg", "alt": "救世超立體口罩 SAVEWO 3DMASK EXTREME PRO「FFP3 + KF99 + ASTM LEVEL3 certified 」(15片獨立包裝/盒)", "sortOrder": 0}, {"url": "/products/savewo/extremepro-2.jpg", "alt": "救世超立體口罩 SAVEWO 3DMASK EXTREME PRO「FFP3 + KF99 + ASTM LEVEL3 certified 」(15片獨立包裝/盒)", "sortOrder": 1}, {"url": "/products/savewo/extremepro-3.jpg", "alt": "救世超立體口罩 SAVEWO 3DMASK EXTREME PRO「FFP3 + KF99 + ASTM LEVEL3 certified 」(15片獨立包裝/盒)", "sortOrder": 2}, {"url": "/products/savewo/extremepro-4.jpg", "alt": "救世超立體口罩 SAVEWO 3DMASK EXTREME PRO「FFP3 + KF99 + ASTM LEVEL3 certified 」(15片獨立包裝/盒)", "sortOrder": 3}, {"url": "/products/savewo/extremepro-5.jpg", "alt": "救世超立體口罩 SAVEWO 3DMASK EXTREME PRO「FFP3 + KF99 + ASTM LEVEL3 certified 」(15片獨立包裝/盒)", "sortOrder": 4}, {"url": "/products/savewo/extremepro-6.jpg", "alt": "救世超立體口罩 SAVEWO 3DMASK EXTREME PRO「FFP3 + KF99 + ASTM LEVEL3 certified 」(15片獨立包裝/盒)", "sortOrder": 5}, {"url": "/products/savewo/extremepro-7.jpg", "alt": "救世超立體口罩 SAVEWO 3DMASK EXTREME PRO「FFP3 + KF99 + ASTM LEVEL3 certified 」(15片獨立包裝/盒)", "sortOrder": 6}, {"url": "/products/savewo/extremepro-8.jpg", "alt": "救世超立體口罩 SAVEWO 3DMASK EXTREME PRO「FFP3 + KF99 + ASTM LEVEL3 certified 」(15片獨立包裝/盒)", "sortOrder": 7}, {"url": "/products/savewo/extremepro-9.jpg", "alt": "救世超立體口罩 SAVEWO 3DMASK EXTREME PRO「FFP3 + KF99 + ASTM LEVEL3 certified 」(15片獨立包裝/盒)", "sortOrder": 8}, {"url": "/products/savewo/extremepro-10.jpg", "alt": "救世超立體口罩 SAVEWO 3DMASK EXTREME PRO「FFP3 + KF99 + ASTM LEVEL3 certified 」(15片獨立包裝/盒)", "sortOrder": 9}]', 149.0, NULL, 'active', 268) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('897e56fa-d81d-4d70-8e7f-c328dd9947e5', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '7187e8af-25ad-4cbf-aa41-a6b51e1adcd7', 'SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE (20片獨立包裝/盒)', 'smile', '60992cbae8f04d002f3da7cf', '全球首個無障礙FFP2認證呼吸器全新研發的SAVEWO VisionFilm 超高清防霧視窗專利技術，在口罩中間嘴部位置形成廣角透明視窗，能多角度展示用家的嘴部。VisionFilm 膠片以超音波技術焊接於口罩的中央，防水防漏氣，確保氣密安全。VisionFilm具有高清防霧氣功能，無論用家說話甚至做運動，也𣎴會出現任何霧化。SAVEWO 3DMASK Smile 的口罩設計採用3DMASK Extreme Pro的V-Shape 專利設計改良而成，加上FleXnet 專利支撐物料，提供超立體堅挺的剪裁，更貼合人的面型。上方設有方便摺疊的專利設計，能夠讓用戶輕鬆調校口罩視窗的傾仰角度，即使不同', '/products/savewo/smile.jpg', '[{"url": "/products/savewo/smile.jpg", "alt": "SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE (20片獨立包裝/盒)", "sortOrder": 0}, {"url": "/products/savewo/smile-2.jpg", "alt": "SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE (20片獨立包裝/盒)", "sortOrder": 1}, {"url": "/products/savewo/smile-3.jpg", "alt": "SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE (20片獨立包裝/盒)", "sortOrder": 2}, {"url": "/products/savewo/smile-4.jpg", "alt": "SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE (20片獨立包裝/盒)", "sortOrder": 3}, {"url": "/products/savewo/smile-5.jpg", "alt": "SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE (20片獨立包裝/盒)", "sortOrder": 4}, {"url": "/products/savewo/smile-6.jpg", "alt": "SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE (20片獨立包裝/盒)", "sortOrder": 5}, {"url": "/products/savewo/smile-7.jpg", "alt": "SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE (20片獨立包裝/盒)", "sortOrder": 6}, {"url": "/products/savewo/smile-8.jpg", "alt": "SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE (20片獨立包裝/盒)", "sortOrder": 7}, {"url": "/products/savewo/smile-9.jpg", "alt": "SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE (20片獨立包裝/盒)", "sortOrder": 8}, {"url": "/products/savewo/smile-10.jpg", "alt": "SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE (20片獨立包裝/盒)", "sortOrder": 9}, {"url": "/products/savewo/smile-11.jpg", "alt": "SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE (20片獨立包裝/盒)", "sortOrder": 10}, {"url": "/products/savewo/smile-12.jpg", "alt": "SAVEWO 3DMASK SMILE 救世超立體口罩 SMILE (20片獨立包裝/盒)", "sortOrder": 11}]', 99.0, NULL, 'active', 269) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('3f5473c4-6fcc-419a-953d-1e4b317c9204', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '3f73ad1e-bfa4-4f24-bccc-95a66f75e37a', '*R 標準碼 - 對應90%以上成人面型，剪裁較合女士* SAVEWO 3DMASK ULTRA 救世超立體口罩 ULTRA TYPECOOL+「FFP2 + KF94 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)', 'ultra-r', '608d03408094a4001a83d2b0', 'SAVEWO 3DMASK Ultra 救世超立體口罩是嶄新的即棄式防護呼吸器及醫用口罩，結合多種救世創新科技，通過各種嚴格的測試，擁有極高的過濾性能，特製的立體剪裁，彈性無痛寬耳帶，超低的呼吸阻力，即使長時間穿戴也十分舒適。無論功能及使用體驗均力臻完美。UltraSpunBond 超潑水面料，配合UltraSeal 超音波接焊點技術，令超薄透氣的3DMASK Ultra 達到前所未有的立體堅挺，更高耐用度，無懼惡劣環境，以及更強大的潑水及抗水性能，防止飛沫及液濺阻擋達160mmHg。TypeCool+過濾技術，超低呼吸阻力只有&lt; 2.4mmH2O，僅為傳統呼吸器的三分之一。得益於不受濕', '/products/savewo/ultra-r.jpg', '[{"url": "/products/savewo/ultra-r.jpg", "alt": "*R 標準碼 - 對應90%以上成人面型，剪裁較合女士* SAVEWO 3DMASK ULTRA 救世超立體口罩 ULTRA TYPECOOL+「FFP2 + KF94 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)", "sortOrder": 0}, {"url": "/products/savewo/ultra-r-2.jpg", "alt": "*R 標準碼 - 對應90%以上成人面型，剪裁較合女士* SAVEWO 3DMASK ULTRA 救世超立體口罩 ULTRA TYPECOOL+「FFP2 + KF94 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)", "sortOrder": 1}, {"url": "/products/savewo/ultra-r-3.jpg", "alt": "*R 標準碼 - 對應90%以上成人面型，剪裁較合女士* SAVEWO 3DMASK ULTRA 救世超立體口罩 ULTRA TYPECOOL+「FFP2 + KF94 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)", "sortOrder": 2}, {"url": "/products/savewo/ultra-r-4.jpg", "alt": "*R 標準碼 - 對應90%以上成人面型，剪裁較合女士* SAVEWO 3DMASK ULTRA 救世超立體口罩 ULTRA TYPECOOL+「FFP2 + KF94 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)", "sortOrder": 3}, {"url": "/products/savewo/ultra-r-5.jpg", "alt": "*R 標準碼 - 對應90%以上成人面型，剪裁較合女士* SAVEWO 3DMASK ULTRA 救世超立體口罩 ULTRA TYPECOOL+「FFP2 + KF94 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)", "sortOrder": 4}, {"url": "/products/savewo/ultra-r-6.jpg", "alt": "*R 標準碼 - 對應90%以上成人面型，剪裁較合女士* SAVEWO 3DMASK ULTRA 救世超立體口罩 ULTRA TYPECOOL+「FFP2 + KF94 + ASTM LEVEL3 認證 」(30片獨立包裝/盒)", "sortOrder": 5}, {"url": "/products/savewo/ultra-r-7.jpg", "alt": "*R 標準碼 - 對應90%以上成人面型，剪裁較合女士* SAVEWO 3DMASK ULTRA 救世超立體口罩 ULTRA TYPECOOL+「FFP2 + KF94 + A