INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('0d2969e6-3fef-4aed-b5a8-622226ad42f2', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'ac191fba-1f46-48e1-ad53-69980cff771d', '*R 標準碼* SAVEWO PremiumMask Medical 救世超卓口罩醫護版 160mm*95mm 藍色 (30片獨立包裝/盒)', 'premium-160r-medical', '608a79e4e78db80014c90426', '全新SAVEWO PremiumMask 超卓口罩醫護版登場，首款正式採用救世遂層消毒系統的口罩，更新增萬眾期待的小顏160mm尺寸！SAVEWO PremiumMask 救世超卓口罩醫護版就是在廣徵用家意見後誕生的全新產品。口罩保留簡單一拉就能從平面變成立體型的優點，比一般平面口罩有更多的嘴部空間；改為採用改良的四摺風琴式設計，加上弧形封邊，令配戴感受更好。採用救世原創的零距離UVC消毒裝置，令口罩每一層布料均獨立經過UVC紫光線消毒，為醫護人員提供最潔淨的保護。設計就是要懂得取捨，以用戶的實際需求為首要。PremiumMask醫護版決定取消常規版嘴部中骨支撐設計，最大化減少醫護調整口罩的動', '/products/savewo/premium-160r-medical.jpg', '[{"url": "/products/savewo/premium-160r-medical.jpg", "alt": "*R 標準碼* SAVEWO PremiumMask Medical 救世超卓口罩醫護版 160mm*95mm 藍色 (30片獨立包裝/盒)", "sortOrder": 0}, {"url": "/products/savewo/premium-160r-medical-2.jpg", "alt": "*R 標準碼* SAVEWO PremiumMask Medical 救世超卓口罩醫護版 160mm*95mm 藍色 (30片獨立包裝/盒)", "sortOrder": 1}, {"url": "/products/savewo/premium-160r-medical-3.jpg", "alt": "*R 標準碼* SAVEWO PremiumMask Medical 救世超卓口罩醫護版 160mm*95mm 藍色 (30片獨立包裝/盒)", "sortOrder": 2}]', 55.0, NULL, 'active', 271) ON CONFLICT DO NOTHING;
