INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('b373ef6b-130c-4c88-92c7-28516e524eaf', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '4477ab1c-023c-415a-bad3-33c6c2a01e92', 'SAVEWO 3DBEAR 救世立體啤口罩 白色 (30片獨立包裝/盒) (6-24月嬰幼兒適用)', '3dbear-white-30-pieces-individually-packagedbox-', '6086afed60dbb90011bb0343', 'SAVEWO 3DBEAR 救世立體啤口罩！讓寶寶亦能綻放笑容！保護極緻、可愛滿分！立體啤！高透氣！強過濾！針對6-24月大BB精心設計的立體剪裁，採用救世TypeCool+ 過濾技術，超高過濾率及超透氣舒適的立體啤啤熊仔口罩矚目登場！SAVEWO 3DBEAR 救世立體啤口罩是即棄式幼兒防護口罩，採用TypeCool+ 過濾技術，超高過濾率及超透氣舒適為核心，配合 ESPP 不織布親膚物料及舒適型耳帶，特別適合幼兒使用。有效過濾99.9%細菌、微塵及病毒。每片均採用獨立個體包裝，方便攜帶。*本產品建議使用年齡只作參考用途。幼兒應在成人監督下使用本產品，如發現一切異常問題，應該立即停用本產品。', '/products/savewo/3dbear-white-30-pieces-individually-packagedbox-.jpg', '[{"url": "/products/savewo/3dbear-white-30-pieces-individually-packagedbox-.jpg", "alt": "SAVEWO 3DBEAR 救世立體啤口罩 白色 (30片獨立包裝/盒) (6-24月嬰幼兒適用)", "sortOrder": 0}, {"url": "/products/savewo/3dbear-white-30-pieces-individually-packagedbox--2.jpg", "alt": "SAVEWO 3DBEAR 救世立體啤口罩 白色 (30片獨立包裝/盒) (6-24月嬰幼兒適用)", "sortOrder": 1}, {"url": "/products/savewo/3dbear-white-30-pieces-individually-packagedbox--3.jpg", "alt": "SAVEWO 3DBEAR 救世立體啤口罩 白色 (30片獨立包裝/盒) (6-24月嬰幼兒適用)", "sortOrder": 2}, {"url": "/products/savewo/3dbear-white-30-pieces-individually-packagedbox--4.jpg", "alt": "SAVEWO 3DBEAR 救世立體啤口罩 白色 (30片獨立包裝/盒) (6-24月嬰幼兒適用)", "sortOrder": 3}, {"url": "/products/savewo/3dbear-white-30-pieces-individually-packagedbox--5.jpg", "alt": "SAVEWO 3DBEAR 救世立體啤口罩 白色 (30片獨立包裝/盒) (6-24月嬰幼兒適用)", "sortOrder": 4}, {"url": "/products/savewo/3dbear-white-30-pieces-individually-packagedbox--6.jpg", "alt": "SAVEWO 3DBEAR 救世立體啤口罩 白色 (30片獨立包裝/盒) (6-24月嬰幼兒適用)", "sortOrder": 5}, {"url": "/products/savewo/3dbear-white-30-pieces-individually-packagedbox--7.jpg", "alt": "SAVEWO 3DBEAR 救世立體啤口罩 白色 (30片獨立包裝/盒) (6-24月嬰幼兒適用)", "sortOrder": 6}]', 149.0, NULL, 'active', 273) ON CONFLICT DO NOTHING;
