INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('0d053865-3d08-4015-90a4-e17c41122d37', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '919ce055-51a2-4708-a286-f3386bc938e3', '*R 標準碼* SAVEWO 3DMASK HANA 救世超立體口罩 花色系列 河津櫻「KF94 + ASTM LEVEL3」(30片獨立包裝/盒)', 'hana-r-pink', '60817ecb7bbc62001a84fe85', '萬象更新，SAVEWO 3DMASK Hana Collection 救世超立體口罩花色系列亦升級登場！全新二代目採用改良的Regular 標準碼立體剪裁，令口罩更立體更舒適，而且配戴後更顯瘦～另外還增加了Small 細碼，適合中童及小顏人仕～全新的舒適型耳帶柔軟順滑，加上透氣物料，配戴感受一試難忘。沿用5種精心調配的花樣色彩，讓您可以隨心配搭喜好，時尚抗疫。採用SAVEWO TypeCool+ 過濾技術，有效過濾99.9%細菌、微塵及病毒，持續效能長達24小時。呼吸阻力Breathing 低於 2.4mmH2O，並符合韓國KF94及美國ASTM Level3規格。花色系列顏色：藍色 - 藍雪', '/products/savewo/hana-r-pink.jpg', '[{"url": "/products/savewo/hana-r-pink.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK HANA 救世超立體口罩 花色系列 河津櫻「KF94 + ASTM LEVEL3」(30片獨立包裝/盒)", "sortOrder": 0}, {"url": "/products/savewo/hana-r-pink-2.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK HANA 救世超立體口罩 花色系列 河津櫻「KF94 + ASTM LEVEL3」(30片獨立包裝/盒)", "sortOrder": 1}, {"url": "/products/savewo/hana-r-pink-3.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK HANA 救世超立體口罩 花色系列 河津櫻「KF94 + ASTM LEVEL3」(30片獨立包裝/盒)", "sortOrder": 2}, {"url": "/products/savewo/hana-r-pink-4.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK HANA 救世超立體口罩 花色系列 河津櫻「KF94 + ASTM LEVEL3」(30片獨立包裝/盒)", "sortOrder": 3}, {"url": "/products/savewo/hana-r-pink-5.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK HANA 救世超立體口罩 花色系列 河津櫻「KF94 + ASTM LEVEL3」(30片獨立包裝/盒)", "sortOrder": 4}]', 129.0, NULL, 'active', 276) ON CONFLICT DO NOTHING;
