INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('74b88ed2-3568-4783-b3a5-9c12c2e830d1', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'd66b8015-ab1e-4515-9b64-fa994d4452a8', 'SAVEWO 救世HEPA H13 及活性碳淨化濾網組合（For TGP-X系列）', 'tgp-hepah13-kit', '607aa7b27301be003ead8f6a', ' 🔗 產品網站https://www.savewo.com/healthcare/zh-hk/products/tgp-x1c包裝內容 特制濾網組合套裝（跟機已有一套） 3件可洗滌初濾網 1件活性碳空氣淨化濾網 1件HEPA H13級 高效濾網第一層 可洗滌初濾網 把守第一關為阻隔大體積塵埃而設，如人類及動物脫下的毛髮、衣物上的灰塵、以至床鋪被單飄出的羽紗及綿毛，都先由第一度防線阻檔，守衛第二、三層高效濾網*初濾網均可自行清洗，用家應每月清洗一次，確保濾網清潔衛生，讓其發揮最大功效，保護高效濾網。 第二層 活性碳空氣淨化濾網 異味終結者以純天然椰子穀物質製成碳晶，再以蜂巢網格設計，能高效過濾揮', '/products/savewo/tgp-hepah13-kit.jpg', '[{"url": "/products/savewo/tgp-hepah13-kit.jpg", "alt": "SAVEWO 救世HEPA H13 及活性碳淨化濾網組合（For TGP-X系列）", "sortOrder": 0}, {"url": "/products/savewo/tgp-hepah13-kit-2.jpg", "alt": "SAVEWO 救世HEPA H13 及活性碳淨化濾網組合（For TGP-X系列）", "sortOrder": 1}, {"url": "/products/savewo/tgp-hepah13-kit-3.jpg", "alt": "SAVEWO 救世HEPA H13 及活性碳淨化濾網組合（For TGP-X系列）", "sortOrder": 2}, {"url": "/products/savewo/tgp-hepah13-kit-4.jpg", "alt": "SAVEWO 救世HEPA H13 及活性碳淨化濾網組合（For TGP-X系列）", "sortOrder": 3}]', 480.0, NULL, 'active', 279) ON CONFLICT DO NOTHING;
