INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('6be6ebea-7fc8-4800-ba97-f2c8df99d1aa', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'd66b9de1-9046-49e4-bba6-512eadf35382', '*R 標準碼* SAVEWO 3DMASK V1 救世超立體口罩 (30片獨立包裝/盒)', 'v1-r', '6006bc4e4284f9003ba07835', '概覽SAVEWO 3DMASK V1 救世超立體口罩是即棄式防護口罩，採用獨特的立體剪裁，有效增加呼吸空間，加上超彈性常規耳帶，比一般平面口罩更貼面，長時間穿戴也十分舒適。採用TypeCool 清涼型通氣技術，超低呼吸阻力 Breathing Resistance&lt; 2.8mmH2O，防止飛沫及液濺阻擋達120mm Hg，有效過濾99.9%細菌、微塵及病毒。每片均採用獨立個體包裝，自用送禮都一流！🔗 產品網站https://www.savewo.com/healthcare/zh-hk/products/3dmask-v1產品規格：常規耳帶 - 救世精選的量產化耳帶，穩定可靠立體剪裁提供', '/products/savewo/v1-r.jpg', '[{"url": "/products/savewo/v1-r.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK V1 救世超立體口罩 (30片獨立包裝/盒)", "sortOrder": 0}, {"url": "/products/savewo/v1-r-2.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK V1 救世超立體口罩 (30片獨立包裝/盒)", "sortOrder": 1}, {"url": "/products/savewo/v1-r-3.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK V1 救世超立體口罩 (30片獨立包裝/盒)", "sortOrder": 2}, {"url": "/products/savewo/v1-r-4.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK V1 救世超立體口罩 (30片獨立包裝/盒)", "sortOrder": 3}, {"url": "/products/savewo/v1-r-5.jpg", "alt": "*R 標準碼* SAVEWO 3DMASK V1 救世超立體口罩 (30片獨立包裝/盒)", "sortOrder": 4}]', 69.0, NULL, 'active', 283) ON CONFLICT DO NOTHING;
INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('fe396c9f-28e2-4985-9857-677156db5ca0', 'fcf07b48-fe21-4ec2-ad72-56481f918883', 'ac191fba-1f46-48e1-ad53-69980cff771d', '*M 中碼* SAVEWO PremiumMask 救世超卓口罩 175mm*95mm 純白色 (30片獨立包裝/盒)', 'premium-175m-white', '5fe71ec9d0c25f001168f064', '概覽SAVEWO PremiumMask 救世超卓口罩是精心設計的平面型口罩，採了四摺風琴式設計，加上弧形封邊，一拉就能由平面口罩變成立體形，符合人體力學設計，有效防止漏氣。口罩的鼻樑及嘴部均設有定型條，令口罩立體堅挺，比一般平面口罩有更多的嘴部空間。整個口罩均由專用定製物料生產，加上SAVEWO TypeCool+ 過濾技術，超強過濾效能及超高透氣度，99.9%的超高過濾效能可維持24小時以上。配合特製ESPP親水性順滑底層，絕不起毛，呵護肌膚。符合美國ASTM LEVEL3 及歐盟EN14683:2019 Type IIR 醫用口罩標準。M 中碼張開：175(W) x 95(H)mm適合人', '/products/savewo/premium-175m-white.jpg', '[{"url": "/products/savewo/premium-175m-white.jpg", "alt": "*M 中碼* SAVEWO PremiumMask 救世超卓口罩 175mm*95mm 純白色 (30片獨立包裝/盒)", "sortOrder": 0}, {"url": "/products/savewo/premium-175m-white-2.jpg", "alt": "*M 中碼* SAVEWO PremiumMask 救世超卓口罩 175mm*95mm 純白色 (30片獨立包裝/盒)", "sortOrder": 1}, {"url": "/products/savewo/premium-175m-white-3.jpg", "alt": "*M 中碼* SAVEWO PremiumMask 救世超卓口罩 175mm*95mm 純白色 (30片獨立包裝/盒)", "sortOrder": 2}, {"url": "/products/savewo/premium-175m-white-4.jpg", "alt": "*M 中碼* SAVEWO PremiumMask 救世超卓口罩 175mm*95mm 純白色 (30片獨立包裝/盒)", "sortOrder": 3}, {"url": "/products/savewo/premium-175m-white-5.jpg", "alt": "*M 中碼* SAVEWO PremiumMask 救世超卓口罩 175mm*95mm 純白色 (30片獨立包裝/盒)", "sortOrder": 4}, {"url": "/products/savewo/premium-175m-white-6.jpg", "alt": "*M 中碼* SAVEWO PremiumMask 救世超卓口罩 175mm*95mm 純白色 (30片獨立包裝/盒)", "sortOrder": 5}, {"url": "/products/savewo/premium-175m-white-7.jpg", "alt": "*M 中碼* SAVEWO PremiumMask 救世超卓口罩 175mm*95mm 純白色 (30片獨立包裝/盒)", "sortOrder": 6}, {"url": "/products/savewo/premium-175m-white-8.jpg", "alt": "*M 中碼* SAVEWO PremiumMask 救世超卓口罩 175mm*95mm 純白色 (30片獨立包裝/盒)", "sortOrder": 7}, {"url": "/products/savewo/premium-175m-white-9.jpg", "alt": "*M 中碼* SAVEWO PremiumMask 救世超卓口罩 175mm*95mm 純白色 (30片獨立包裝/盒)", "sortOrder": 8}, {"url": "/products/savewo/premium-175m-white-10.jpg", "alt": "*M 中碼* SAVEWO PremiumMask 救世超卓口罩 175mm*95mm 純白色 (30片獨立包裝/盒)", "sortOrder": 9}, {"url": "/products/savewo/premium-175m-white-11.jpg", "alt": "*M 中碼* SAVEWO PremiumMask 救世超卓口罩 175mm*95mm 純白色 (30片獨立包裝/盒)", "sortOrder": 10}]', 55.0, NULL, 'active', 284) ON CONFLICT DO NOTHING;
