INSERT INTO products (id, tenant_id, category_id, name, slug, sku, description, image, images, selling_price, stock, status, sort_order) VALUES ('fabcb1ed-1cf0-4881-9bc0-2331669a9cee', 'fcf07b48-fe21-4ec2-ad72-56481f918883', '230876d0-de4c-4946-aef5-f28fd2bfdce5', 'SAVEWO 救世 FACESHIELD FS-001防護全面罩', 'savewo-救世-faceshield-fs-001防護全面罩', '5f4d3854bb140f1d9ae97010', '救世 FACESHIELD FS-001防護全面罩，高清透明膠片，無阻視線！根本透明一樣！抗病毒防飛沬，為你提供全面防護！要到高危地方，例如診所或者醫院，除咗帶救世口罩，仲可以用埋防護全面罩，有效阻擋飛沫及病毒，同時遮蓋眼睛及臉部，全臉保護，減低感染風險。高清透明膠片的防霧塗層，不受呼吸濕氣影響，戴上後無阻視線，根本透明一樣！眼框輕巧無重感，長時間佩戴都係零負擔！不少朋友仔都有不自覺碰觸臉部的習慣，如果手沒有清潔好，也會帶來感染風險！戴上防護全面罩後，有膠片阻擋觸摸自己的臉部，減低被接觸感染的機會。產品特點：- 高清透明膠片，防霧塗層，無阻視線- 有效阻擋飛沫，同時遮蓋眼睛及臉部- 高效阻隔病', '/products/savewo/savewo-救世-faceshield-fs-001防護全面罩.jpg', '[{"url": "/products/savewo/savewo-救世-faceshield-fs-001防護全面罩.jpg", "alt": "SAVEWO 救世 FACESHIELD FS-001防護全面罩", "sortOrder": 0}, {"url": "/products/savewo/savewo-救世-faceshield-fs-001防護全面罩-2.jpg", "alt": "SAVEWO 救世 FACESHIELD FS-001防護全面罩", "sortOrder": 1}, {"url": "/products/savewo/savewo-救世-faceshield-fs-001防護全面罩-3.jpg", "alt": "SAVEWO 救世 FACESHIELD FS-001防護全面罩", "sortOrder": 2}, {"url": "/products/savewo/savewo-救世-faceshield-fs-001防護全面罩-4.jpg", "alt": "SAVEWO 救世 FACESHIELD FS-001防護全面罩", "sortOrder": 3}, {"url": "/products/savewo/savewo-救世-faceshield-fs-001防護全面罩-5.jpg", "alt": "SAVEWO 救世 FACESHIELD FS-001防護全面罩", "sortOrder": 4}, {"url": "/products/savewo/savewo-救世-faceshield-fs-001防護全面罩-6.jpg", "alt": "SAVEWO 救世 FACESHIELD FS-001防護全面罩", "sortOrder": 5}, {"url": "/products/savewo/savewo-救世-faceshield-fs-001防護全面罩-7.jpg", "alt": "SAVEWO 救世 FACESHIELD FS-001防護全面罩", "sortOrder": 6}, {"url": "/products/savewo/savewo-救世-faceshield-fs-001防護全面罩-8.jpg", "alt": "SAVEWO 救世 FACESHIELD FS-001防護全面罩", "sortOrder": 7}]', 39.0, NULL, 'active', 294) ON CONFLICT DO NOTHING;